-- Poems batch 229
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ab0d01da-cd80-4920-b66e-0fa6160db98d','義利吟','邵雍','宋','宋诗','song-poetry','','[]','意不若義，義不若利。',40,'全唐诗/poet.song.21000.json','["意不若義，義不若利。", "利之使人，能忘生死。", "利不若義，義不若意。", "意之使人，能動天地。"]'),
('a6f9995a-6fa6-41a8-811d-3859fc3008f4','代簡謝朱殿直贈長韻詩','邵雍','宋','宋诗','song-poetry','','[]','慇懃見贈用長篇，里閈過從積有年。',32,'全唐诗/poet.song.21000.json','["慇懃見贈用長篇，里閈過從積有年。", "歲事報成還報始，春華相次又暄妍。"]'),
('14b530d9-2059-4b58-9252-7902fd34da8c','試筆','邵雍','宋','宋诗','song-poetry','','[]','心在人軀號太陽，能於事上發輝光。',64,'全唐诗/poet.song.21000.json','["心在人軀號太陽，能於事上發輝光。", "如何皎日照八表，得似靈臺高一方。", "家用平康貧不害，身無疾病瘦何妨。", "高吟大笑洛城裏，看盡人間手脚忙。"]'),
('e745a192-59f0-43d6-9bd1-4d7317d3ebf2','試硯','邵雍','宋','宋诗','song-poetry','','[]','富貴傲人人未信，還知富貴去如何。',64,'全唐诗/poet.song.21000.json','["富貴傲人人未信，還知富貴去如何。", "常觀靜處光陰好，亦恐閑時思慮多。", "日出自然天不暗，風來安得水無波。", "世間大有平田地，因甚須由捷徑過。"]'),
('a54d78cf-eda3-4563-91fc-f297807bf016','問調鼎','邵雍','宋','宋诗','song-poetry','','[]','請將調鼎問于君，調鼎功夫敢預聞。',64,'全唐诗/poet.song.21000.json','["請將調鼎問于君，調鼎功夫敢預聞。", "只有鹽梅難盡善，豈無薑桂助爲辛。", "和羹必欲須求美，衆口如何便得均。", "慎勿輕言天下事，伊周殊不是庸人。"]'),
('d4bd5609-a9ab-4658-b89a-895d9293c240','讀古詩','邵雍','宋','宋诗','song-poetry','','[]','閑讀古人詩，因看古人意。',48,'全唐诗/poet.song.21000.json','["閑讀古人詩，因看古人意。", "古今時雖殊，其意固無異。", "喜怒與哀樂，貧賤與富貴。", "惜哉情何物，使人能如是。"]'),
('df2fd934-834a-48d3-8e8b-e8fc97151458','蠹書魚','邵雍','宋','宋诗','song-poetry','','[]','形狀類于魚，其心好蠹書。',48,'全唐诗/poet.song.21000.json','["形狀類于魚，其心好蠹書。", "居常遊篋笥，未始在江湖。", "爲害千般有，言烹一物無。", "年年當盛夏，曬了却如初。"]'),
('19595285-35a1-46d9-af71-b92ad1c1f147','歲儉吟','邵雍','宋','宋诗','song-poetry','','[]','歲儉心非儉，家貧道不貧。',24,'全唐诗/poet.song.21000.json','["歲儉心非儉，家貧道不貧。", "誰知天地內，別有好乾坤。"]'),
('2917dcda-5333-40a1-bfc6-ea28e7a1b284','極論','邵雍','宋','宋诗','song-poetry','','[]','下有黄泉上有天，人人許住百來年。',64,'全唐诗/poet.song.21000.json','["下有黄泉上有天，人人許住百來年。", "還知虛過死萬遍，都似不曾生一般。", "要識明珠須巨海，如求良玉必名山。", "先能了盡世間事，然後方言出世間。"]'),
('d0211c5b-c41a-4d14-92cf-d5d30b530721','求鑑吟','邵雍','宋','宋诗','song-poetry','','[]','人無鑑流水，當求鑑止水。',48,'全唐诗/poet.song.21000.json','["人無鑑流水，當求鑑止水。", "流水無定形，止水有定體。", "人無鑑于水，當求鑑于人。", "水鑑見人貌，人鑑見人神。"]'),
('712c61b4-30ac-424c-b5aa-4ca89c04c009','學佛吟','邵雍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','飽食豐衣不易過，日長時節奈愁何。',64,'全唐诗/poet.song.21000.json','["飽食豐衣不易過，日長時節奈愁何。", "求名少日投宣聖，怕死老年親釋迦。", "妄欲斷緣緣愈重，徼求去病病還多。", "長江一片常如練，幸自無風又起波。"]'),
('a1e5b43f-ae6e-43a8-b0aa-9c048f92a1dd','霜露吟','邵雍','宋','宋诗','song-poetry','','[]','天地有潤澤，其降也瀼瀼。',48,'全唐诗/poet.song.21000.json','["天地有潤澤，其降也瀼瀼。", "暖則爲湛露，寒則爲繁霜。", "爲露萬物悅，爲霜萬物傷。", "二物本一氣，恩威何昭彰。"]'),
('ea5db40c-27bb-4f49-aa46-103793dd6d08','天命吟','邵雍','宋','宋诗','song-poetry','','[]','可委者命，可憑者天。',20,'全唐诗/poet.song.21000.json','["可委者命，可憑者天。", "人無率爾，事不偶然。"]'),
('319bc15e-52e4-44df-a11d-d097b6f7a75e','性情吟','邵雍','宋','宋诗','song-poetry','','[]','踐形治性，踐跡治情。',20,'全唐诗/poet.song.21000.json','["踐形治性，踐跡治情。", "賢人踐跡，聖人踐形。"]'),
('38cabafc-4f02-49e7-83db-442328f9250a','心跡吟','邵雍','宋','宋诗','song-poetry','','[]','聖人了心，賢人了跡。',20,'全唐诗/poet.song.21000.json','["聖人了心，賢人了跡。", "了心無窮，了跡無極。"]'),
('a9224201-6485-4ead-bbff-c608606d5660','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','物不兩盛，事難獨行。',20,'全唐诗/poet.song.21000.json','["物不兩盛，事難獨行。", "榮瘁迭起，賢愚並行。"]'),
('5799d5e0-1f7e-42ce-bb9b-976be447f8c3','思慮吟','邵雍','宋','宋诗','song-poetry','','[]','思慮未起，鬼神莫知。',20,'全唐诗/poet.song.21000.json','["思慮未起，鬼神莫知。", "不由乎我，更由乎誰。"]'),
('31d44357-f0e5-451a-a67a-c205c92791f2','代書答朝中舊友','邵雍','宋','宋诗','song-poetry','','[]','少日治文章，亦曾觀國光。',48,'全唐诗/poet.song.21000.json','["少日治文章，亦曾觀國光。", "山林雖不返，畎畝未嘗忘。", "麋鹿寧無志，鵷鴻自有行。", "還知今日事，大故索思量。"]'),
('f010eca3-f7de-4d95-b6aa-2baf1fa64214','冬不出吟','邵雍','宋','宋诗','song-poetry','','[]','冬非不欲出，欲出苦日短。',48,'全唐诗/poet.song.21000.json','["冬非不欲出，欲出苦日短。", "年老恐話長，天寒怕歸晚。", "山翁頭有風，鄉友情非淺。", "必欲相招延，春光況不遠。"]'),
('2154fddd-d719-4b2a-aa65-617ce320d720','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','地以靜而方，天以動而圓。',72,'全唐诗/poet.song.21000.json','["地以靜而方，天以動而圓。", "既正方圓體，還明動靜權。", "靜久必成潤，動極遂成然。", "潤則水體具，然則火用全。", "水體以器受，火用以薪傳。", "體在天地後，用起天地先。"]'),
('b9c3bc3b-a9e8-4332-8b89-defb4a395983','家國吟','邵雍','宋','宋诗','song-poetry','','[]','邪正異心，家國同體。',20,'全唐诗/poet.song.21000.json','["邪正異心，家國同體。", "邪能敗亡，正能興起。"]'),
('519e29da-8430-48f2-9a15-9bf02c82a4ec','邪正吟','邵雍','宋','宋诗','song-poetry','','[]','賢人好正，姦人好邪。',20,'全唐诗/poet.song.21000.json','["賢人好正，姦人好邪。", "好邪則競，好正則和。"]'),
('b991dbe9-4aa9-49c6-bed8-97b7fa24f724','義利吟  其一','邵雍','宋','宋诗','song-poetry','','[]','君子尚義，小人尚利。',20,'全唐诗/poet.song.21000.json','["君子尚義，小人尚利。", "尚利則亂，尚義則治。"]'),
('73252ee4-fceb-47d7-9b4d-a14683ed049a','義利吟  其二','邵雍','宋','宋诗','song-poetry','','[]','人作者事，天命者時。',20,'全唐诗/poet.song.21000.json','["人作者事，天命者時。", "時來易失，事去難追。"]'),
('0902ba74-03af-4503-b7e4-8e5761d8ed67','恩義吟','邵雍','宋','宋诗','song-poetry','','[]','恩深者親，義重者君。',20,'全唐诗/poet.song.21000.json','["恩深者親，義重者君。", "恩義兩得，始謂之人。"]'),
('b92a5489-507c-4c09-ab5c-cbb87615868a','閑步吟','邵雍','宋','宋诗','song-poetry','','[]','何者謂知音，知音難漫尋。',48,'全唐诗/poet.song.21000.json','["何者謂知音，知音難漫尋。", "既無師曠耳，安有伯牙琴。", "雖逼桑榆景，寧忘松桂心。", "獨行月堤上，一步一高吟。"]'),
('de5628af-9c67-4576-99d5-0d82af777b64','坐右吟','邵雍','宋','宋诗','song-poetry','','[]','萬物備于身，直須資養深。',48,'全唐诗/poet.song.21000.json','["萬物備于身，直須資養深。", "因何爲寶鑑，只被用精金。", "酒少如茶飲，詩多似史吟。", "顔淵方內樂，天下事難任。"]'),
('5ba77a49-6fd6-4c68-8566-3dc37d284ce0','感雪吟','邵雍','宋','宋诗','song-poetry','','[]','旨酒嘉肴與管絃，通宵鼎沸樂豐年。',32,'全唐诗/poet.song.21000.json','["旨酒嘉肴與管絃，通宵鼎沸樂豐年。", "侯門深處還知否，百萬流民在露天。"]'),
('90438076-418c-46dc-b24f-546ccd412caa','六十五歲新正自貽','邵雍','宋','宋诗','song-poetry','','[]','予家洛城裏，況在天津畔。',168,'全唐诗/poet.song.21000.json','["予家洛城裏，況在天津畔。", "行年六十五，當宋之盛旦。", "南園臨通衢，北圃仰雙觀。", "雖然在京國，却如處山澗。", "清泉篆溝渠，茂木綉霄漢。", "涼風竹下來，皓月松間見。", "面前有芝蘭，目下無冰炭。", "坐上有餘歡，胸中無交戰。", "冬夏既不出，炎涼徒自變。", "榮辱既不入，富貴徒自衒。", "惡聞人之惡，樂道人之善。", "不行何趑趄，勿藥何瞑眩。", "誰謂金石堅，其心亦能斷。", "誰謂鬼神靈，其誠亦能貫。"]'),
('49fa631d-9bd8-41ed-ba99-3e694f6a3fd0','小車六言吟','邵雍','宋','宋诗','song-poetry','','["\u534e\u5c71"]','昔人乘車是常，今見乘車倉皇。',280,'全唐诗/poet.song.21000.json','["昔人乘車是常，今見乘車倉皇。", "既有前車戒慎，豈無覆轍兢莊。", "將出必用茶飲，欲登先須道裝。", "軫邊更掛詩帙，轅畔仍懸酒缸。", "輪緩爲移芳草，蓋低因礙垂楊。", "水際尤宜穩審，花間更要安詳。", "朝出頻經履道，晚歸屢過平康。", "春重縱觀明媚，秋深飫看豐穰。", "五鳳樓前月色，天津橋上風涼。", "金谷園中流水，魏王堤外脩篁。", "靜處光陰最好，閑中氣味偏長。", "所經莫不意得，所見無非情忘。", "或見農人擁耒，或見蠶女求桑。", "或見蘼蕪遍野，或見蒺蔾滿牆。", "或見荆棘茂密，或見芝蘭芬芳。", "或見雞豚狗彘，或見鵰鶚鸞凰。", "惡者既不見害，善者固無相傷。", "華嶽三峯岌嶪，黄陂萬頃汪洋。", "不爲虛作男子，無負閑居洛陽。", "天地精英多得，堯夫老去何妨。"]'),
('b3c4eb00-f909-4c33-928a-d22b999fdedb','安樂吟','邵雍','宋','宋诗','song-poetry','','[]','安樂先生，不顯姓氏。',200,'全唐诗/poet.song.21000.json','["安樂先生，不顯姓氏。", "垂三十年，居洛之涘。", "風月情懷，江湖性氣。", "色期其舉，翔而後至。", "無賤無貧，無富無貴。", "無將無迎，無拘無忌。", "窘未嘗憂，飲不至醉。", "收天下春，歸之肝肺。", "盆池資吟，甕牖薦睡。", "小車賞心，大筆快志。", "或戴接䍦，或著半臂。", "或坐林間，或行水際。", "樂見善人，樂聞善事。", "樂道善言，樂行善意。", "聞人之惡，若負芒刺。", "聞人之善，如佩蘭蕙。", "不佞禪伯，不諛方士。", "不出戶庭，直際天地。", "三軍莫凌，萬鍾莫致。", "爲快活人，六十五歲。"]'),
('473d1756-2941-4070-92ca-9ebb2cc93641','甕牖吟','邵雍','宋','宋诗','song-poetry','','[]','有客無知，唯知自守。',200,'全唐诗/poet.song.21000.json','["有客無知，唯知自守。", "自守無他，唯求寡咎。", "有屋數間，有田數畝。", "用盆爲池，以甕爲牖。", "牆高于肩，室大于斗。", "布被暖餘，蔾羹飽後。", "氣吐胸中，充塞宇宙。", "筆落人間，暉映瓊玖。", "人能知止，以退爲茂。", "我自不出，何退之有。", "心無妄思，足無妄走。", "人無妄交，物無妄受。", "炎炎論之，甘處其陋。", "綽綽言之，無出其右。", "羲軒之書，未嘗去手。", "堯舜之談，未嘗虛口。", "當中和天，同樂易友。", "吟自在詩，飲歡喜酒。", "百年升平，不爲不偶。", "七十康强，不爲不壽。"]'),
('1917697d-85c2-4c2e-9876-290c141f9e3d','盆池吟','邵雍','宋','宋诗','song-poetry','','[]','有客無知，唯知不爲。',200,'全唐诗/poet.song.21000.json','["有客無知，唯知不爲。", "不爲無他，唯求不欺。", "我有人是，人無我非。", "因開甕牖，遂鑿盆池。", "都邑地貴，江湖景奇。", "能游澤國，不下堂基。", "簾外青草，軒前黄陂。", "壺中月落，鑑裏雲飛。", "既有荷芰，豈無𦳓茨。", "既有蝌蚪，豈無蛟螭。", "亦或清淺，亦或渺瀰。", "亦或淥凈，亦或漣漪。", "風起蘋藻，涼生袖衣。", "林宗何在，范蠡何歸。", "密雪霏霏，輕冰披披。", "垂柳依依，細雨微微。", "可以觀止，可以忘機。", "可以照物，可以看時。", "不樂乎我，更樂乎誰。", "吾于是日，再見伏羲。"]'),
('6d6866d2-3bb5-42c9-9e99-cb3be4fd79bb','小車吟','邵雍','宋','宋诗','song-poetry','','[]','有客無知，唯知有家。',200,'全唐诗/poet.song.21000.json','["有客無知，唯知有家。", "有家能歸，其歸非遐。", "靈臺瑩靜，天壞披葩。", "書用大筆，出乘小車。", "身爲男子，生于中華。", "又居洛陽，爲幸何多。", "天地中央，帝王貞宅。", "漢唐遺烈，氣象自佳。", "聖賢區宇，士人淵藪。", "仁義場圃，聞見無涯。", "里巷相切，親朋相過。", "人疑日馭，我謂星查。", "或遊金谷，或泛月波。", "或經履道，或過銅駝。", "進退雲水，舒卷煙霞。", "揄揚風月，擡帖鶑花。", "性喜飲酒，飲喜微酡。", "飲未微酡，口先吟哦。", "吟哦不足，遂及浩歌。", "浩歌不足，無可柰何。"]'),
('661c4703-0059-40fe-827e-c9cc191ffe87','大筆吟','邵雍','宋','宋诗','song-poetry','','[]','有客無知，爲性太質。',200,'全唐诗/poet.song.21000.json','["有客無知，爲性太質。", "不忮不求，無固無必。", "足躡天根，手探月窟。", "所得之懷，盡賦于筆。", "意遠情融，氣和神逸。", "酒放微醺，綃鋪半匹。", "如風之卒，如雲之勃。", "如電之歘，如雨之密。", "或往或還，或沒或出。", "滌盪氛埃，廓開天日。", "鸞鳳翺翔，龍蛇盤屈。", "春葩暄妍，秋山崒屼。", "三千簪裾，俯循儒術。", "百萬貔貅，仰聽軍律。", "松桂成林，芝蘭滿室。", "蜀錦初番，朝霞乍拂。", "白璧一雙，黄金百鎰。", "羲之來求，牧之來乞。", "物外神交，人間事畢。", "觀者析酲，收之愈疾。"]'),
('4468270d-9be2-40a6-986d-4344afeaa8e5','觀易吟','邵雍','宋','宋诗','song-poetry','','[]','一物其來有一身，一身還有一乾坤。',64,'全唐诗/poet.song.21000.json','["一物其來有一身，一身還有一乾坤。", "能知萬物備於我，肯把三才別立根。", "天向一中分體用，人於心上起經綸。", "天人焉有兩般義，道不虛行只在人。"]'),
('57d72a8b-977c-4b1b-9bb9-98f0a69f7cbe','觀書吟','邵雍','宋','宋诗','song-poetry','','[]','吁嗟四代帝王權，盡入區區一舊編。',64,'全唐诗/poet.song.21000.json','["吁嗟四代帝王權，盡入區區一舊編。", "或讓或爭三萬里，相因相革二千年。", "唐虞事業誰能繼，湯武功夫世莫傅。", "時既不同人又異，仲尼惡得不潸然。"]'),
('c1d8e7b9-2554-47b2-bea3-8354e1999ce4','觀詩吟','邵雍','宋','宋诗','song-poetry','','[]','愛君難得似當時，曲盡人情莫若詩。',64,'全唐诗/poet.song.21000.json','["愛君難得似當時，曲盡人情莫若詩。", "無雅豈明王教化，有風方識國興衰。", "知音未若吳公子，潤色曾經魯仲尼。", "三百五篇天下事，後人誰敢更譏非。"]'),
('bd1959b4-0200-4c24-b4ef-2f5acb67ee2b','觀春秋吟','邵雍','宋','宋诗','song-poetry','','[]','堂堂王室寄空名，天下無時不戰爭。',64,'全唐诗/poet.song.21000.json','["堂堂王室寄空名，天下無時不戰爭。", "滅國伐人雖恐後，尋盟報役未嘗寧。", "晉齊命令炎如火，文武資基冷似冰。", "唯有感麟心一片，萬年千載若丹青。"]'),
('9b72fffc-0c0b-4d5b-8304-e864acc57b61','觀三皇吟','邵雍','宋','宋诗','song-poetry','','[]','許大乾坤自我宣，乾坤之外復何言。',64,'全唐诗/poet.song.21000.json','["許大乾坤自我宣，乾坤之外復何言。", "初分大道非常道，纔有先天未後天。", "作法極微難看蹟，收功最久不知年。", "若教世上論勳業，料得更無人在前。"]'),
('ea03ed74-f03e-47f1-978d-5bdf6723612a','觀五帝吟','邵雍','宋','宋诗','song-poetry','','[]','進退肯將天下讓，著何言語狀雍容。',64,'全唐诗/poet.song.21000.json','["進退肯將天下讓，著何言語狀雍容。", "衣裳垂處威儀盛，玉帛修時意思恭。", "物物盡能循至理，人人自願立殊功。", "當時何故得如此，只被聲明類日中。"]'),
('ceea76ee-a699-4184-83c6-d0bc742853ea','觀三王吟','邵雍','宋','宋诗','song-poetry','','[]','一片中原萬里餘，殆非孱德所宜居。',64,'全唐诗/poet.song.21000.json','["一片中原萬里餘，殆非孱德所宜居。", "夏商正朔猶能布，湯武干戈未便驅。", "澤火有名方受革，水天無應不成需。", "詳知仁義爲心者，肯作人間淺丈夫。"]'),
('a09e2875-6610-48f5-a932-84af77095200','觀五伯吟','邵雍','宋','宋诗','song-poetry','','[]','刻意尊名名愈虧，人人奔命不勝疲。',64,'全唐诗/poet.song.21000.json','["刻意尊名名愈虧，人人奔命不勝疲。", "生靈劍戟林中活，公道貸財心裏歸。", "雖則餼羊能愛體，柰何鳴鳳未來儀。", "東周五百餘年內，歎息唯聞一仲尼。"]'),
('c60652ff-0817-4c2f-948d-b7a953dc244a','觀七國吟','邵雍','宋','宋诗','song-poetry','','[]','當其末路尚縱橫，仁義之言固不聽。',64,'全唐诗/poet.song.21000.json','["當其末路尚縱橫，仁義之言固不聽。", "肯謂破齊存即墨，能勝坑趙盡長平。", "清晨見鬼未爲怪，白日殺人奚足驚。", "加以蘇張掉三寸，扼喉其勢不俱生。"]'),
('3e17ca46-7c5e-4282-b2a2-bb37cb8727a6','觀嬴秦吟','邵雍','宋','宋诗','song-poetry','','[]','轟轟七國正爭籌，利害相磨未便休。',64,'全唐诗/poet.song.21000.json','["轟轟七國正爭籌，利害相磨未便休。", "比至一雄心底定，其如四海血橫流。", "三千賓客方成夢，百二山河又變秋。", "謾說罷侯能置守，趙高元不是封候。"]'),
('881a91af-1d1a-4d03-b680-9c6897033df2','觀兩漢吟','邵雍','宋','宋诗','song-poetry','','[]','秦破河山舊戰場，豈期民復見耕桑。',64,'全唐诗/poet.song.21000.json','["秦破河山舊戰場，豈期民復見耕桑。", "九千來里開封域，四百餘年號帝王。", "剝喪既而遭莽卓，經營殊不念高光。", "當時文物如期盛，城復何由更有隍。"]'),
('6e96d294-8c08-47b6-b777-c40164a7faf8','觀三國吟','邵雍','宋','宋诗','song-poetry','','[]','桓桓鼎峙震雷音，絕唱高蹤沒處尋。',64,'全唐诗/poet.song.21000.json','["桓桓鼎峙震雷音，絕唱高蹤沒處尋。", "簫鼓一方情未暢，弓刀萬里力難任。", "論兵狠石寧無意，飲馬黄河徒有心。", "雖日天時亦人事，誰知慮外失良金。"]'),
('9336c64b-b9c7-4ff3-937c-3adbf8e893e1','觀西晉吟','邵雍','宋','宋诗','song-poetry','','[]','承平未必便無憂，安若忘危非善謀。',64,'全唐诗/poet.song.21000.json','["承平未必便無憂，安若忘危非善謀。", "題品人材憑雅誚，雌黄時事用風流。", "有刀難剖公閭腹，無木可梟元海頭。", "禍在夕陽亭一句，上東門嘯浪悠悠。"]'),
('109c16f5-06f2-4067-88f0-703a7b65f7bf','觀十六國吟','邵雍','宋','宋诗','song-poetry','','[]','溥天之下號寰區，大禹曾經治水餘。',64,'全唐诗/poet.song.21000.json','["溥天之下號寰區，大禹曾經治水餘。", "衣到敝時多蟣虱，瓜當爛後足蟲蛆。", "龍章本不資狂寇，象魏何嘗薦亂胡。", "尼父有言堪味處，當時欠一管夷吾。"]'),
('87f80930-fc8a-4174-9dd8-c1e891aa1d27','觀南北朝吟','邵雍','宋','宋诗','song-poetry','','[]','方其天下分南北，聘使何嘗絕往還。',64,'全唐诗/poet.song.21000.json','["方其天下分南北，聘使何嘗絕往還。", "偏霸尚存前典憲，小康猶带舊腥羶。", "洛陽雅望稱崔浩，江表奇才服謝安。", "二百四年能並轡，謾將夷虜互爲言。"]'),
('66ddeace-894c-4ebc-8862-c611893be2cd','觀隋朝吟','邵雍','宋','宋诗','song-poetry','','[]','始謀當日已非臧，又更相承或自戕。',64,'全唐诗/poet.song.21000.json','["始謀當日已非臧，又更相承或自戕。", "蟻螻人民貪土地，泥沙金帛悅姬姜。", "征遼意思縻荒服，泛汴情懷厭未央。", "三十六年都掃地，不然天下未歸唐。"]'),
('e1cce2c0-d092-4451-b461-4e1687e42f54','觀有唐吟','邵雍','宋','宋诗','song-poetry','','[]','天生神武奠中央，不爾羣凶未易攘。',64,'全唐诗/poet.song.21000.json','["天生神武奠中央，不爾羣凶未易攘。", "貞觀若無風凜凜，開元安有氣揚揚。", "憑高始見山河壯，入夏方知日月長。", "三百年間能渾一，事雖成往道彌光。"]'),
('6a083feb-e7c1-4cab-8bf7-916fcf635850','觀五代吟','邵雍','宋','宋诗','song-poetry','','[]','自從唐季墜皇綱，天下生靈被擾攘。',64,'全唐诗/poet.song.21000.json','["自從唐季墜皇綱，天下生靈被擾攘。", "社稷安危懸卒伍，朝廷輕重擊藩方。", "深冬寒木固不脫，未旦小星猶有光。", "五十三年更五姓，始知除掃待真王。"]'),
('5fa11278-741e-44ed-95c9-a52d2c9d731d','觀盛化吟  其一','邵雍','宋','宋诗','song-poetry','','[]','紛紛五代亂離間，一旦雲開復見天。',64,'全唐诗/poet.song.21000.json','["紛紛五代亂離間，一旦雲開復見天。", "草木百年新雨露，車書萬里舊山川。", "尋常巷陌猶簪紱，取次園亭亦管絃。", "人老太平春未老，鶑花無害日高眠。"]'),
('f461b46c-5287-473b-bfaf-4e3bccb38ba0','觀盛化吟  其二','邵雍','宋','宋诗','song-poetry','','[]','吾曹養拙頼明時，爲幸居多寧不知。',64,'全唐诗/poet.song.21000.json','["吾曹養拙頼明時，爲幸居多寧不知。", "天下英才中遁跡，人間好景處開眉。", "生來只慣見豐稔，老去未嘗經亂離。", "五事歷將前代舉，帝堯而下固無之。"]'),
('ed169782-c342-4a3c-9521-3b816bd24096','喜老吟','邵雍','宋','宋诗','song-poetry','','[]','幾何能得鬢如絲，安用區區鑷白髭。',64,'全唐诗/poet.song.21000.json','["幾何能得鬢如絲，安用區區鑷白髭。", "在世上官雖不做，出人間事却能知。", "待天春暖秋涼日，是我東遊西泛時。", "多少寬平好田地，山翁方始會開眉。"]'),
('c3773ea9-678f-44f7-846b-e3a0b7834fee','瞻禮孔子吟','邵雍','宋','宋诗','song-poetry','','[]','執卷何人不讀書，能知性者又何如。',64,'全唐诗/poet.song.21000.json','["執卷何人不讀書，能知性者又何如。", "工居天下語言內，妙出世間繩墨餘。", "陶冶有無天事業，權衡治亂帝功夫。", "大哉贊易脩經意，料得生民以後無。"]'),
('3a89767e-9290-41a2-9ffb-00d498259162','還圓益上人詩卷','邵雍','宋','宋诗','song-poetry','','[]','瓶錫相從更一巾，一巾曾拂十州塵。',64,'全唐诗/poet.song.21000.json','["瓶錫相從更一巾，一巾曾拂十州塵。", "心通佛性久無礙，口道儒言殊不陳。", "吳越江山前日事，伊嵩風月此時身。", "閑行坐閑松陰下，應恃眼明長笑人。"]'),
('33cfb636-83d8-4564-bcb7-ba623bed79bc','天人吟','邵雍','宋','宋诗','song-poetry','','[]','知盡人情天豈異，未知何啻隔天地。',64,'全唐诗/poet.song.21000.json','["知盡人情天豈異，未知何啻隔天地。", "少時氣銳未更諳，不信人間有難事。", "知盡人情與天意，合而言之安有二。", "能推己心達人心，天下何憂不能治。"]'),
('0653e84a-a33a-4dce-9af5-7efd458869b2','錦幈春吟','邵雍','宋','宋诗','song-poetry','','[]','錦幈山下有家園，每歲家園過禁煙。',64,'全唐诗/poet.song.21000.json','["錦幈山下有家園，每歲家園過禁煙。", "早是三春天氣好，那堪百里主人賢。", "同於一派水邊飲，醉向萬株花底眠。", "明日歸鞍遂東指，上陽風景更暄妍。"]'),
('20c53a27-e06e-4582-a2af-3a264b30f006','樂春吟','邵雍','宋','宋诗','song-poetry','','[]','四時唯愛春，春更愛春分。',48,'全唐诗/poet.song.21000.json','["四時唯愛春，春更愛春分。", "有暖溫存物，無寒著莫人。", "好花方蓓蕾，美酒正輕醇。", "安樂窩中客，如何不半醺。"]'),
('4333b2ea-0425-40a5-a689-93fd6e5e3537','觀物吟四首  其一','邵雍','宋','宋诗','song-poetry','','[]','日月無異明，晝夜有異體。',48,'全唐诗/poet.song.21000.json','["日月無異明，晝夜有異體。", "人鬼無異情，生死有異理。", "既未能知生，又焉能知死。", "既未能事人，又焉能事鬼。"]'),
('1b8a35c6-c7e9-4b85-9b01-fc3062093231','觀物吟四首  其二','邵雍','宋','宋诗','song-poetry','','[]','鶑蟬體既分，安用苦云云。',48,'全唐诗/poet.song.21000.json','["鶑蟬體既分，安用苦云云。", "氣盛有餘力，聲銷無異聞。", "時來由自己，勢去屬他人。", "莫作傷心事，傷心不益身。"]'),
('c58795c2-10d0-49d8-b74d-6a093f10e671','觀物吟四首  其三','邵雍','宋','宋诗','song-poetry','','[]','古今情一也，能處又何難。',48,'全唐诗/poet.song.21000.json','["古今情一也，能處又何難。", "識事事非易，知人人所艱。", "多疑虧任用，輕信失防閑。", "堯舜其猶病，何嘗無大姦。"]'),
('9aabc017-c899-405c-abf0-89c94a72d119','觀物吟四首  其四','邵雍','宋','宋诗','song-poetry','','[]','人之耳所聞，不若目親照。',48,'全唐诗/poet.song.21000.json','["人之耳所聞，不若目親照。", "耳聞有異同，目照無多少。", "併棄耳目官，專用舌口較。", "不成天下功，止成天下笑。"]'),
('39496cdf-b1b4-460e-abf8-bcdc8bd5ade6','人貴有精神吟','邵雍','宋','宋诗','song-poetry','','[]','有貴有精神，精神多不醇。',96,'全唐诗/poet.song.21000.json','["有貴有精神，精神多不醇。", "有精神而醇，爲第一等人。", "不醇無義理，是非隨怒喜。", "怒以是爲非，喜以非爲是。", "怒是善人疎，喜非小人比。", "敗國與亡家，鮮有不由此。", "娶妻娶柔和，嫁夫嫁才美。", "安得正婦人，作配真男子。"]'),
('302968e1-1881-4761-ae04-9e902c35e913','義利吟','邵雍','宋','宋诗','song-poetry','','[]','賁於丘園，束帛戔戔。',60,'全唐诗/poet.song.21000.json','["賁於丘園，束帛戔戔。", "義既在前，利在其間。", "捨爾靈龜，歸我朵頤。", "義既失之，利何能爲。", "尚義必讓，君子道長。", "尚利必爭，小人道行。"]'),
('4893b857-9c57-4999-9f84-614d44b21f83','小車初出吟','邵雍','宋','宋诗','song-poetry','','[]','物外洞天三十六，都疑布在洛陽中。',32,'全唐诗/poet.song.21000.json','["物外洞天三十六，都疑布在洛陽中。", "小車春暖秋涼日，一日止能移一宮。"]'),
('996cd62a-e5f3-4c69-a269-a6a1a4899dd3','府尹王宣徽席上作  其一','邵雍','宋','宋诗','song-poetry','','[]','留都三判主人翁，大第名園冠洛中。',32,'全唐诗/poet.song.21000.json','["留都三判主人翁，大第名園冠洛中。", "又喜一年春入手，萬花香照酒巵紅。"]'),
('71cc9188-a197-4257-a99a-2c6323b3bdd8','府尹王宣徽席上作  其二','邵雍','宋','宋诗','song-poetry','','[]','紛紛又過一年春，守落情懷酒漫醇。',32,'全唐诗/poet.song.21000.json','["紛紛又過一年春，守落情懷酒漫醇。", "滿眼暄妍都去盡，樽前唯憶舊交親。"]'),
('798267d7-e6d6-49e0-983a-b96aa5312d55','春暮答人吟','邵雍','宋','宋诗','song-poetry','','[]','相違經歲意何如，漫說爲隣德不孤。',32,'全唐诗/poet.song.21000.json','["相違經歲意何如，漫說爲隣德不孤。", "咫尺洛陽春己盡，過從能憶舊時無。"]'),
('9b273809-54c0-4fb5-af69-06a69e8f3fad','天津聞樂吟','邵雍','宋','宋诗','song-poetry','','[]','名園相倚洛陽春，巷陌無塵羅綺新。',32,'全唐诗/poet.song.21000.json','["名園相倚洛陽春，巷陌無塵羅綺新。", "何處青樓隔桃李，樂聲時復到天津。"]'),
('d904d46f-2061-436d-9219-93cae992171b','春暮吟','邵雍','宋','宋诗','song-poetry','','[]','有意楊花空學雪，無情榆莢漫堆錢。',32,'全唐诗/poet.song.21000.json','["有意楊花空學雪，無情榆莢漫堆錢。", "窮愁不服春辜負，酒病依還似去年。"]'),
('3953fa54-7bb6-4081-8d77-0ed5874fe903','自問二首  其一','邵雍','宋','宋诗','song-poetry','','[]','因甚年來可作詩，柰何人老又春歸。',32,'全唐诗/poet.song.21000.json','["因甚年來可作詩，柰何人老又春歸。", "流鶑不忍花離披，啼到黄昏猶自啼。"]'),
('c1035b75-bd38-422c-9111-b95ec54224b1','自問二首  其二','邵雍','宋','宋诗','song-poetry','','[]','年來因甚可吟詩，桃李無言鶑有辭。',32,'全唐诗/poet.song.21000.json','["年來因甚可吟詩，桃李無言鶑有辭。", "啼到黄昏猶自啼，柰何人老又春歸。"]'),
('4ede05a1-db50-4a5c-bbbf-045ad945db85','和成都俞公達運使見寄','邵雍','宋','宋诗','song-poetry','','[]','前年車從過天津，花底當時把酒頻。',32,'全唐诗/poet.song.21000.json','["前年車從過天津，花底當時把酒頻。", "此日錦城花爛漫，何嘗更憶洛城春。"]'),
('8a189451-6c86-4274-b55b-4df6f99e01e1','吳越吟二首','邵雍','宋','宋诗','song-poetry','','[]','乙未闔廬凌楚歲，戊辰勾踐破吳時。',64,'全唐诗/poet.song.21000.json','["乙未闔廬凌楚歲，戊辰勾踐破吳時。", "正如當日乘虛事，三十四年人不知。", "夫差丁未曾囚越，勾踐戊辰還滅吳。", "二十二年時返復，一如當日却乘虛。"]'),
('33087761-98c9-47ec-bfa2-d405aa18a17c','屬事吟','邵雍','宋','宋诗','song-poetry','','[]','鷦鷯分寄一枝巢，不信甘言便易驕。',64,'全唐诗/poet.song.21000.json','["鷦鷯分寄一枝巢，不信甘言便易驕。", "當力尚難超北海，去威何足動鴻毛。", "願將情意分明謝，肯把恩光取次燒。", "天寵居多爲幸久，春花無柰正夭饒。"]'),
('21c51bf1-337e-4505-ab93-9a6643c2c463','興亡吟  其一','邵雍','宋','宋诗','song-poetry','','[]','孫陳李三人，亡國體相似。',24,'全唐诗/poet.song.21000.json','["孫陳李三人，亡國體相似。", "雖然少有文，何復語英氣。"]'),
('d1863ac6-86ff-4c83-a424-cad877789d79','興亡吟  其二','邵雍','宋','宋诗','song-poetry','','[]','曹劉孫三人，興國體相似。',24,'全唐诗/poet.song.21000.json','["曹劉孫三人，興國體相似。", "雖然小有才，何復語命世。"]'),
('a231bf21-d49e-4835-a3f1-92c411ce3c4f','文武吟','邵雍','宋','宋诗','song-poetry','','[]','既爲文士，必有武備。',20,'全唐诗/poet.song.21000.json','["既爲文士，必有武備。", "文武之道，皆吾家事。"]'),
('d2833624-d291-4fbe-b8cc-d1969ad0767c','善惡吟  其一','邵雍','宋','宋诗','song-poetry','','[]','瞽鯀有子，堯舜無嗣。',20,'全唐诗/poet.song.21000.json','["瞽鯀有子，堯舜無嗣。", "餘慶餘殃，何故如此。"]'),
('3cc50b88-2a15-4577-b5e8-c791d520fd3f','善惡吟  其二','邵雍','宋','宋诗','song-poetry','','[]','堯舜無子，瞽鯀有嗣。',20,'全唐诗/poet.song.21000.json','["堯舜無子，瞽鯀有嗣。", "福善禍淫，何故如此。"]'),
('a8a904b5-4101-4e07-bb08-b0c3f74f3412','責己吟','邵雍','宋','宋诗','song-poetry','','[]','不爲十分人，不責十分事。',24,'全唐诗/poet.song.21000.json','["不爲十分人，不責十分事。", "既爲十分人，須責十分是。"]'),
