('4be77965-f42a-498b-8c3b-9ce27f8fa128','四者吟','邵雍','宋','宋诗','song-poetry','','[]','財色名勢，爲世所親。',20,'全唐诗/poet.song.21000.json','["財色名勢，爲世所親。", "四者不動，然後見人。"]'),
('63392aea-8972-43be-9238-a69e8c9f1024','恩怨吟','邵雍','宋','宋诗','song-poetry','','[]','人之常情，無重于死。',40,'全唐诗/poet.song.21000.json','["人之常情，無重于死。", "恩感人心，死猶有喜。", "怨結人心，死猶未已。", "恩怨之深，使人如此。"]'),
('807dc3a3-db9d-4a81-8ffa-df09a214542a','秦川吟二首  其一','邵雍','宋','宋诗','song-poetry','','[]','當時馬上過秦川，倏忽于今二十年。',32,'全唐诗/poet.song.21000.json','["當時馬上過秦川，倏忽于今二十年。", "因見夫君話家住，依稀記得舊風煙。"]'),
('6764ee3a-976b-4378-ba58-3dc3811503a2','秦川吟二首  其二','邵雍','宋','宋诗','song-poetry','','[]','秦川兩漢帝王區，今日關東作帝都。',32,'全唐诗/poet.song.21000.json','["秦川兩漢帝王區，今日關東作帝都。", "多少聖賢存舊史，夕陽唯只見荒蕪。"]'),
('c1140d74-4fa1-436a-badc-7066ff520ac6','和絳守王仲賢郎中','邵雍','宋','宋诗','song-poetry','','[]','爲郎得絳分銅虎，見寄詩中非浪誇。',64,'全唐诗/poet.song.21000.json','["爲郎得絳分銅虎，見寄詩中非浪誇。", "地土尚傳唐草木，山川猶起晉雲霞。", "園池富有吟供筆，風俗淳無訟到衙。", "太守下車民受賜，一心殊不負官家。"]'),
('7b32006d-d4df-424c-93bb-05905bd81438','日月吟','邵雍','宋','宋诗','song-poetry','','[]','月明星自稀，日出月亦微。',24,'全唐诗/poet.song.21000.json','["月明星自稀，日出月亦微。", "既有少正卯，豈無孔仲尼。"]'),
('7d88f72d-417c-49cc-ae29-d98c4e43ea1a','水旱吟  其一','邵雍','宋','宋诗','song-poetry','','[]','堯水九年，湯旱七載。',20,'全唐诗/poet.song.21000.json','["堯水九年，湯旱七載。", "調變之功，此時安在。"]'),
('74e98d92-441b-434d-a904-0d611bab05e7','水旱吟  其二','邵雍','宋','宋诗','song-poetry','','[]','九年洪水，七年大旱。',20,'全唐诗/poet.song.21000.json','["九年洪水，七年大旱。", "非堯與湯，民死過半。"]'),
('cd218e71-c588-49fd-81ea-36670469d5ab','老去吟  其一','邵雍','宋','宋诗','song-poetry','','[]','使吾却十歲，亦可少集事。',24,'全唐诗/poet.song.21000.json','["使吾却十歲，亦可少集事。", "柰何天地間，日無再中理。"]'),
('340dbcb4-379b-4686-973a-b4c8997e2625','老去吟  其二','邵雍','宋','宋诗','song-poetry','','[]','吾今六十六，衰老何可擬。',24,'全唐诗/poet.song.21000.json','["吾今六十六，衰老何可擬。", "志逮力不逮，人共知之矣。"]'),
('91707507-3a42-4f6b-91b7-0a2953035049','人事吟','邵雍','宋','宋诗','song-poetry','','[]','索鍊無如事，難知莫若人。',24,'全唐诗/poet.song.21000.json','["索鍊無如事，難知莫若人。", "人情隨手別，事體到頭均。"]'),
('505440c5-d596-489a-ac28-a4a994376ffb','不同吟','邵雍','宋','宋诗','song-poetry','','[]','求者不得，辭者不能。',20,'全唐诗/poet.song.21000.json','["求者不得，辭者不能。", "二者相去，其遠幾程。"]'),
('d28f8296-55ed-47d2-8ced-02980b49e6f1','貪義吟','邵雍','宋','宋诗','song-poetry','','[]','貪人之惡，其過莫大。',20,'全唐诗/poet.song.21000.json','["貪人之惡，其過莫大。", "貪人之善，是亦爲罪。"]'),
('714481cb-51ec-4d67-afd8-4a22afceef7a','月新吟','邵雍','宋','宋诗','song-poetry','','[]','月新與月殘，形狀兩相似。',24,'全唐诗/poet.song.21000.json','["月新與月殘，形狀兩相似。", "柰何人之情，初見自歡喜。"]'),
('2c6d1ca6-92ea-4431-b799-e1a88feda1b1','和內鄉李師甫長官見寄  其一','邵雍','宋','宋诗','song-poetry','','[]','雖未似神仙，能逃暑與寒。',48,'全唐诗/poet.song.21000.json','["雖未似神仙，能逃暑與寒。", "何嘗無水竹，未始離林巒。", "道不同新學，才難動要官。", "時和歲豐後，亦自有餘歡。"]'),
('e31ee14d-7583-4c84-a71f-4a17f90e26f1','和內鄉李師甫長官見寄  其二','邵雍','宋','宋诗','song-poetry','','[]','歲豐時又康，爲邑在南陽。',48,'全唐诗/poet.song.21000.json','["歲豐時又康，爲邑在南陽。", "不廢吏民事，得遊雲水鄉。", "春輸桃李艷，風薦蕙蘭香。", "太守兼賢傑，且無奔走忙。"]'),
('9c34413f-6bf4-4a63-b88d-9a4e26070153','內鄉天春亭','邵雍','宋','宋诗','song-poetry','','[]','內鄉有園名天春，春時桃李如綵雲。',64,'全唐诗/poet.song.21000.json','["內鄉有園名天春，春時桃李如綵雲。", "邑民携觴連帘幕，或歌或舞何歡欣。", "縣尹中間意自若，直謂前世無古人。", "牡丹百品紅與紫，華而不實徒紛紜。"]'),
('a6b14170-6b2f-4c4e-b843-0171d800b022','內鄉兼隠亭','邵雍','宋','宋诗','song-poetry','','[]','兼隠詫來書，於時特起予。',48,'全唐诗/poet.song.21000.json','["兼隠詫來書，於時特起予。", "民淳無訟聽，縣僻類山居。", "簿領盃盤外，宮聯談笑餘。", "不知當此際，傍邑更誰知。"]'),
('bd65350d-8bbe-4edd-924f-29f14a719296','李少卿見招代往吟','邵雍','宋','宋诗','song-poetry','','[]','洛城春去會仙才，春去還驚夏却來。',48,'全唐诗/poet.song.21000.json','["洛城春去會仙才，春去還驚夏却來。", "微雨過牡丹初謝，輕風動芍藥纔開。", "綠楊陰裏擁樽罍，身健時康好放懷。"]'),
('d70beb96-f918-4846-b628-c247c7d05e07','病酒吟','邵雍','宋','宋诗','song-poetry','','[]','年年當此際，酒病掩柴扉。',48,'全唐诗/poet.song.21000.json','["年年當此際，酒病掩柴扉。", "早是人多感，那堪春又歸。", "花殘蝴蝶亂，晝永子規啼。", "安得如前日，和風初扇微。"]'),
('67d790d5-c724-43df-bbf2-0b58e4ebb693','爭讓吟','邵雍','宋','宋诗','song-poetry','','[]','有讓豈無爭，無沿安有革。',48,'全唐诗/poet.song.21000.json','["有讓豈無爭，無沿安有革。", "爭讓起于心，沿革生于跡。", "羲軒讓以道，堯舜讓以德。", "湯武爭以功，桓文爭以力。"]'),
('4a7e60b5-2181-4afe-b2ea-8c93d78e37e7','謝王諫議見思吟','邵雍','宋','宋诗','song-poetry','','[]','西齋前後半松筠，萬慮澄餘始見真。',32,'全唐诗/poet.song.21000.json','["西齋前後半松筠，萬慮澄餘始見真。", "不謂天光明淨處，又能時憶舊交親。"]'),
