('03c80f5d-ebb4-4a73-8949-7e93933861c8','齊鄭吟','邵雍','宋','宋诗','song-poetry','','[]','子産何嘗辭鄭小，晏嬰殊不願齊衰。',32,'全唐诗/poet.song.21000.json','["子産何嘗辭鄭小，晏嬰殊不願齊衰。", "二賢生若得其地，才業當爲王者師。"]'),
('96bfa3fd-9093-4b6b-8615-a8ea49391ed1','代書寄呂庫部','邵雍','宋','宋诗','song-poetry','','[]','周王八駿走天涯，爭似君家四寶奇。',32,'全唐诗/poet.song.21000.json','["周王八駿走天涯，爭似君家四寶奇。", "鄭洛風煙雖咫尺，恨無由往一觀之。"]'),
('19976ebe-9d64-4a65-bbb0-21f20b820046','和王安之少卿雨後','邵雍','宋','宋诗','song-poetry','','[]','焦勞九夏餘，一雨物皆蘇。',48,'全唐诗/poet.song.21000.json','["焦勞九夏餘，一雨物皆蘇。", "蛙鼓不足聽，蚊雷未易驅。", "非唯仰歲給，抑亦了官輸。", "林下閑遊客，何妨儘自愉。"]'),
('d9a496ac-647c-4c6c-9ce3-55f0801bc0dc','和和承制見贈','邵雍','宋','宋诗','song-poetry','','[]','自度無能處世間，經冬經夏掩柴關。',64,'全唐诗/poet.song.21000.json','["自度無能處世間，經冬經夏掩柴關。", "青雲路穩無功上，翠竹叢疎有分閑。", "猶許艷花酬素志，更將佳酒發酡顔。", "年來老態非常甚，長懼英才未易攀。"]'),
('ecde21cd-a170-47f6-8aac-885c3d66bcbf','清和吟','邵雍','宋','宋诗','song-poetry','','[]','清而不和，隘而多鄙。',40,'全唐诗/poet.song.21000.json','["清而不和，隘而多鄙。", "和而不清，慢而鮮禮。", "既和且清，義無定體。", "時行則行，時止則止。"]'),
('32f02c1b-7c3d-4395-8dc4-c47f03c241d5','異同吟','邵雍','宋','宋诗','song-poetry','','[]','俊快傷滅裂，厚重傷滯泥。',48,'全唐诗/poet.song.21000.json','["俊快傷滅裂，厚重傷滯泥。", "趨造隨所尚，不免有同異。", "異己必爲非，同己必爲是。", "是非戰異同，終身不知義。"]'),
('148f6e82-e561-44ab-9826-310b379fc770','即事吟','邵雍','宋','宋诗','song-poetry','','[]','生求媚于人，死求媚于鬼。',48,'全唐诗/poet.song.21000.json','["生求媚于人，死求媚于鬼。", "媚人幸富貴，媚鬼免罪戾。", "生死雖殊途，人鬼豈異理。", "哀哉過用心，妄意何時已。"]'),
('5814b559-221d-42e4-b9ed-424814486dd1','觀物吟  其一','邵雍','宋','宋诗','song-poetry','','[]','耳目聰明男子身，洪鈞賦與不爲貧。',64,'全唐诗/poet.song.21000.json','["耳目聰明男子身，洪鈞賦與不爲貧。", "因探月窟方知物，未躡天根豈識人。", "乾遇巽時觀月窟，地逢雷處看天根。", "天根月窟閑來往，三十六宮都是春。"]'),
('42dbe700-b7e6-4204-b12a-0b1826764f54','觀物吟  其二','邵雍','宋','宋诗','song-poetry','','[]','淳厚之人少秀慧，秀慧之人少審諦。',32,'全唐诗/poet.song.21000.json','["淳厚之人少秀慧，秀慧之人少審諦。", "安得淳厚又秀慧，與之共話人間事。"]'),
('617b26a5-8634-4df1-9517-7addc411337b','對酒吟','邵雍','宋','宋诗','song-poetry','','[]','有酒時時泛一甌，年將七十待何求。',64,'全唐诗/poet.song.21000.json','["有酒時時泛一甌，年將七十待何求。", "齒衰婚嫁尚未了，歲旱田園纔薄收。", "客去有時閑拱手，日高無事靜梳頭。", "霜毛不止裝詩景，更可因而入畫休。"]'),
('c75f5c62-fbf8-440d-acd7-fc6735d69c54','秋懷吟','邵雍','宋','宋诗','song-poetry','','[]','一番春了未多時，雲外征鴻又報歸。',64,'全唐诗/poet.song.21000.json','["一番春了未多時，雲外征鴻又報歸。", "節物眼前來若此，歲華頭上去如斯。", "當年志意雖然在，今日筋骸寧不衰。", "頼有寸心常自喜，聖人難處却能知。"]'),
('22de8a5e-cc58-475a-ba54-aa92948bfe39','和王安之少卿秋遊','邵雍','宋','宋诗','song-poetry','','[]','春夏而來可作詩，雖然可作待何爲。',64,'全唐诗/poet.song.21000.json','["春夏而來可作詩，雖然可作待何爲。", "屢空濫得同顔子，歷物固難如惠施。", "風月情懷無柰處，雲山意思不勝時。", "一歌一詠聊酬唱，敢拒安之與靜之。"]'),
('5935d467-9790-41e7-82c0-f07e2331a7f3','和王安之同赴府尹王宣徽洛社秋會','邵雍','宋','宋诗','song-poetry','','[]','後房深出會親賓，樂按新聲妙入神。',64,'全唐诗/poet.song.21000.json','["後房深出會親賓，樂按新聲妙入神。", "紅燭盛時翻翠袖，畫橈停處占青蘋。", "早年金殿舊遊客，此日鳳池將去人。", "宅冠名都號蝸隠，邵堯夫敢作西鄰。"]'),
('88e1df19-bafc-4908-a8f6-223d184aec0d','負河陽河清濟源三處之約以詩愧謝之','邵雍','宋','宋诗','song-poetry','','[]','秋霖積久泥正滑，念念何日天開晴。',64,'全唐诗/poet.song.21000.json','["秋霖積久泥正滑，念念何日天開晴。", "親朋延望固已甚，衰軀怯寒難遠行。", "一程相去雖不遠，兩次講行終未成。", "二事交戰乎胸中，隠几愁坐無由平。"]'),
('4cdfff87-bf91-4254-bc87-542bd6976a49','依韻和王安之少卿秋約吟','邵雍','宋','宋诗','song-poetry','','[]','升沉惡足論，事體到頭均。',48,'全唐诗/poet.song.21000.json','["升沉惡足論，事體到頭均。", "一片蓬蒿地，千年雲水身。", "收成時正好，寒暖氣初勻。", "自此過從樂，諸公莫厭頻。"]'),
('82aa1c76-153a-4af7-8abb-f2cecd1e3ce1','長子伯溫失解以詩示之','邵雍','宋','宋诗','song-poetry','','[]','儒家所尚者，行善與文章。',48,'全唐诗/poet.song.21000.json','["儒家所尚者，行善與文章。", "用捨何嘗定，枯榮未易量。", "干求便黽勉，得失是尋常。", "外物不可必，其言味其長。"]'),
('0a5bc98a-5f0c-467c-a4d5-9ca317cf85d6','歲暮自貽吟','邵雍','宋','宋诗','song-poetry','','[]','天道無長春，地道無常珍。',120,'全唐诗/poet.song.21000.json','["天道無長春，地道無常珍。", "須稟中和氣，方生粹美人。", "良田多黍稌，薄地足荆榛。", "樗櫟蓬蒿類，止能充惡薪。", "既爲萬物靈，須有萬物粹。", "既無萬物靈，徒分萬物類。", "欲出至珍言，須有至珍意。", "欲彰至美名，須作至美事。", "濟事爲美事，悟主爲珍意。", "柰何此二者，我獨無一與。"]'),
('c4f415d2-a644-478a-bc53-6a128a1972ae','君子飲酒吟','邵雍','宋','宋诗','song-poetry','','[]','父慈子孝，兄友弟恭。',40,'全唐诗/poet.song.21000.json','["父慈子孝，兄友弟恭。", "家給人足，時和歲豐。", "筋骸康健，里閈樂從。", "君子飲酒，其樂無窮。"]'),
('b963af03-7224-40fe-988f-1b7dee744204','讀張子房傳吟','邵雍','宋','宋诗','song-poetry','','[]','漢室開基第一功，善哉能始又能終。',64,'全唐诗/poet.song.21000.json','["漢室開基第一功，善哉能始又能終。", "直疑後日赤松子，便是當年黄石公。", "用捨隨時無分限，行藏在我有窮通。", "古人已死不復見，痛惜今人少此風。"]'),
('01bdf5d5-06f6-47ea-9b29-e225cc3f65e4','觀物吟二道  其一','邵雍','宋','宋诗','song-poetry','','[]','柳性至柔軟，一年長丈餘。',24,'全唐诗/poet.song.21000.json','["柳性至柔軟，一年長丈餘。", "雖然易得榮，柰何易得枯。"]'),
('e08dccdf-b08a-4638-87ce-217ed9270f7c','觀物吟二道  其二','邵雍','宋','宋诗','song-poetry','','[]','百穀仰膏雨，極枯變極榮。',24,'全唐诗/poet.song.21000.json','["百穀仰膏雨，極枯變極榮。", "安得此甘澤，聊且振羣生。"]'),
('1b8ff280-d992-4a8d-8769-cb5c3c7adce4','治亂吟五首  其一','邵雍','宋','宋诗','song-poetry','','[]','亂多于治，害多于利。',30,'全唐诗/poet.song.21000.json','["亂多于治，害多于利。", "悲多于喜，惡多于美。", "一陰一陽，柰何如此。"]'),
('f37181c4-93ef-46f9-9c76-18913e35b5e7','治亂吟五首  其二','邵雍','宋','宋诗','song-poetry','','[]','中原一片閑田地，曾示三皇與五帝。',32,'全唐诗/poet.song.21000.json','["中原一片閑田地，曾示三皇與五帝。", "三皇五帝子孫多，或賤或貧或富貴。"]'),
('b5339c99-a9c9-423b-b9b2-631b074d37f3','治亂吟五首  其三','邵雍','宋','宋诗','song-poetry','','[]','精義入神以致用，利用出入之謂神。',32,'全唐诗/poet.song.21000.json','["精義入神以致用，利用出入之謂神。", "神無方而易無體，藏諸用而顯諸仁。"]'),
('42b0ff74-9ce3-4037-89b0-7b4f924411dc','治亂吟五首  其四','邵雍','宋','宋诗','song-poetry','','[]','火能勝水，火不勝水，其火遂滅。',60,'全唐诗/poet.song.21000.json','["火能勝水，火不勝水，其火遂滅。", "水能從火，水不從火，其水不熱。", "夫能制妻，夫不制妻，其妻遂絕。", "妻能從夫，妻不從夫，其妻必孽。"]'),
('57dd4ae8-2dfe-439c-844e-ab87a98b0a40','治亂吟五首  其五','邵雍','宋','宋诗','song-poetry','','[]','天能生而不能養，地能養而不能生。',64,'全唐诗/poet.song.21000.json','["天能生而不能養，地能養而不能生。", "火能烹而不能沃，水能沃而不能烹。", "天地尚猶無全功，水火何由有全能。", "得用二者交相養，反爲二者交相凌。"]'),
('5e36a670-c3e5-4441-83f0-f07863ad9e60','三十年吟','邵雍','宋','宋诗','song-poetry','','[]','比三十年前，今日爲艱難。',48,'全唐诗/poet.song.21000.json','["比三十年前，今日爲艱難。", "比三十年後，今日爲安閑。", "治久人思亂，亂久人思安。", "安得千年鶴，乘去遊仙山。"]'),
('22e6bff6-22cf-4df1-aee3-de4426f69bfd','有病吟','邵雍','宋','宋诗','song-poetry','','[]','身之有病，當求藥醫。',60,'全唐诗/poet.song.21000.json','["身之有病，當求藥醫。", "藥之非良，其身必虧。", "國之有病，當求人醫。", "人之非良，其國必危。", "事之未急，當速改爲。", "事之既急，雖悔難追。"]'),
('af1e583d-b1b8-4910-8eed-be997ad57de8','對花吟','邵雍','宋','宋诗','song-poetry','','[]','今年花似昔年開，今日人開昔日懷。',64,'全唐诗/poet.song.21000.json','["今年花似昔年開，今日人開昔日懷。", "煩惱全無半掐子，喜歡長有百車來。", "光陰已過意未過，齒髮雖頹志未頹。", "人問堯夫曾出否，答云方自洞天回。"]'),
('124a65b0-3977-4327-b99d-893bdabf0323','自述','邵雍','宋','宋诗','song-poetry','','[]','春暖秋涼人半醉，安車麈尾閑從事。',32,'全唐诗/poet.song.21000.json','["春暖秋涼人半醉，安車麈尾閑從事。", "雖無大德及生靈，且與太平裝景致。"]'),
('31d45d86-bce6-467d-ba80-1958067dab4e','去事吟','邵雍','宋','宋诗','song-poetry','','[]','君子去事，民有餘祥。',20,'全唐诗/poet.song.21000.json','["君子去事，民有餘祥。", "小人去事，民有餘殃。"]'),
('73ef8fb9-94b3-42b9-a2b3-bd5a781af53b','策杖吟','邵雍','宋','宋诗','song-poetry','','[]','策杖南園或北園，春來尤足慰衰年。',64,'全唐诗/poet.song.21000.json','["策杖南園或北園，春來尤足慰衰年。", "初晴天氣上元後，乍暖風光寒食前。", "池岸微微裝嫩草，林稍薄薄罩輕煙。", "東君此際情何厚，非象之中正造妍。"]'),
('a35a0c0f-92d8-4706-985d-217d35a26ebe','不願吟','邵雍','宋','宋诗','song-poetry','','[]','不願朝廷命官職，不願朝廷賜粟帛。',32,'全唐诗/poet.song.21000.json','["不願朝廷命官職，不願朝廷賜粟帛。", "惟願朝廷省徭役，庶幾天下少安息。"]'),
('672a1d85-99b6-4fd6-b0f3-4ac19a5ac294','量力吟','邵雍','宋','宋诗','song-poetry','','[]','量力動時無悔吝，隨宜樂處省營爲。',32,'全唐诗/poet.song.21000.json','["量力動時無悔吝，隨宜樂處省營爲。", "須求騏驥方乘馬，亦恐終身無馬騎。"]'),
('9130d25e-92a9-419a-8242-9e58dba02fcc','戲答友人吟','邵雍','宋','宋诗','song-poetry','','[]','邵堯夫者是何人，歲歲春秋來謁君。',32,'全唐诗/poet.song.21000.json','["邵堯夫者是何人，歲歲春秋來謁君。", "車小半年行一轉，非如駿馬走香塵。"]'),
('4377da1b-ba36-4377-89e4-7c128974cf00','偶得吟','邵雍','宋','宋诗','song-poetry','','[]','臯陶遇舜，伊尹逢湯。',40,'全唐诗/poet.song.21000.json','["臯陶遇舜，伊尹逢湯。", "武丁得傅，文王獲姜。", "齊知管仲，漢識張良。", "諸葛開蜀，玄齡啟唐。"]'),
('44daf5cc-0a7b-413f-8f77-670612c86910','觀事吟','邵雍','宋','宋诗','song-poetry','','[]','一歲之事慎在春，一日之事慎在晨。',32,'全唐诗/poet.song.21000.json','["一歲之事慎在春，一日之事慎在晨。", "一生之事慎在少，一端之事慎在新。"]'),
('fa17ea02-b0f6-43fd-88a3-f0ed3d8a32a5','知音吟','邵雍','宋','宋诗','song-poetry','','[]','仲尼始可言無意，孟子方能不動心。',64,'全唐诗/poet.song.21000.json','["仲尼始可言無意，孟子方能不動心。", "莫向山中尋白玉，但於身上覓黄金。", "山中白玉有時得，身上黄金無處尋。", "我輩何人敢稱會，安知世上無知音。"]'),
('28b7baa3-ac83-4c5b-82be-91e938dacb97','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','利輕則義重，利重則義輕。',36,'全唐诗/poet.song.21000.json','["利輕則義重，利重則義輕。", "利不能勝義，自然多至誠。", "義不能勝利，自然多忿爭。"]'),
('22cfcb42-b8fd-497b-9414-fe394bbb0d99','金玉吟','邵雍','宋','宋诗','song-poetry','','[]','聖在人中出，心從行上修。',24,'全唐诗/poet.song.21000.json','["聖在人中出，心從行上修。", "金於砂裏得，玉向石中求。"]'),
('db169ab3-fd61-47bb-ad19-556a4e48c09c','風霜吟','邵雍','宋','宋诗','song-poetry','','[]','見風而靡者草也，見霜而殞者亦草也。',54,'全唐诗/poet.song.21000.json','["見風而靡者草也，見霜而殞者亦草也。", "見風而鳴者松也，見霜而凌者亦松也。", "見風而靡，見霜而傷。", "焉能爲有，焉能爲亡。"]'),
('28bae9a4-8116-423f-bb17-a746d6030312','上下吟','邵雍','宋','宋诗','song-poetry','','[]','自下觀上，無限富貴。',40,'全唐诗/poet.song.21000.json','["自下觀上，無限富貴。", "自上觀下，無限賤貧。", "自心觀物，何物能一。", "自物觀心，何心不均。"]'),
('ffe2bd2b-c1d9-4c90-a318-62c9daaf38ff','吾廬吟','邵雍','宋','宋诗','song-poetry','','[]','吾廬雖小粗容身，且免輕爲僦舍人。',32,'全唐诗/poet.song.21000.json','["吾廬雖小粗容身，且免輕爲僦舍人。", "大有世人無屋住，向人簷下索溫存。"]'),
('a6f9ba2e-8a14-49ea-8734-c38c7d0dba8d','瀍河上觀杏花迴','邵雍','宋','宋诗','song-poetry','','[]','瀍河東看杏花開，花外天津暮却迴。',32,'全唐诗/poet.song.21000.json','["瀍河東看杏花開，花外天津暮却迴。", "更把杏花頭上插，圖人知道看花來。"]'),
('ab3d44f4-c035-475c-8b5c-a41c5d947f50','娶妻吟','邵雍','宋','宋诗','song-poetry','','[]','人之娶妻，容德威儀。',20,'全唐诗/poet.song.21000.json','["人之娶妻，容德威儀。", "儻或生子，不臯則夔。"]'),
('c805c956-7519-49e5-a13c-fd57bdac153e','好事吟','邵雍','宋','宋诗','song-poetry','','[]','好事固難將力取，賢人須是著心求。',32,'全唐诗/poet.song.21000.json','["好事固難將力取，賢人須是著心求。", "浮生日月無多子，時過千休復萬休。"]'),
('c1542138-f6fa-4f65-9b93-8260b196ccd3','不再吟','邵雍','宋','宋诗','song-poetry','','[]','春無再至，花無再開。',20,'全唐诗/poet.song.21000.json','["春無再至，花無再開。", "人無再少，時無再來。"]'),
('166e522d-f4c4-49fe-995f-de3c17fdb575','毛頭吟  其一','邵雍','宋','宋诗','song-poetry','','[]','誰剪毛頭謝陸沉，生靈肌骨不勝侵。',64,'全唐诗/poet.song.21000.json','["誰剪毛頭謝陸沉，生靈肌骨不勝侵。", "人間自有迴天力，林下空多憂國心。", "日過中時憂未艾，月幾望處患仍深。", "軍中儒服吾家事，諸葛武侯何處尋。"]'),
('51dd9cd8-d448-413c-a62f-8757bd7e927c','毛頭吟  其二','邵雍','宋','宋诗','song-poetry','','[]','憂國心深爲愛君，愛君須更重於身。',64,'全唐诗/poet.song.21000.json','["憂國心深爲愛君，愛君須更重於身。", "口中講得未必是，手裏做成方始真。", "妄意動時難照物，俗情私處莫知人。", "厚誣天下凶之甚，多少英才在下塵。"]'),
('a9c615bd-cada-4b1d-9e81-7eab55bc7688','六得吟','邵雍','宋','宋诗','song-poetry','','[]','眼能識得，耳能聽得。',60,'全唐诗/poet.song.21000.json','["眼能識得，耳能聽得。", "口能道得，手能做得，身能行得，心能放得。", "六者盡能，與天同德。", "飲食起居，出處語默。", "不止省心，又更省力。"]'),
('9e30ad7e-5f08-4b40-a019-b74a085cb698','盛衰吟','邵雍','宋','宋诗','song-poetry','','[]','勢盛舉頭方偃蹇，氣衰旋踵却嗟吁。',32,'全唐诗/poet.song.21000.json','["勢盛舉頭方偃蹇，氣衰旋踵却嗟吁。", "厚誣天下稱賢者，天下何嘗可厚誣。"]'),
('ed5891ee-e020-4808-9a77-dfd54d69553d','富貴吟','邵雍','宋','宋诗','song-poetry','','[]','大舜與人同好惡，以人從欲得安乎。',32,'全唐诗/poet.song.21000.json','["大舜與人同好惡，以人從欲得安乎。", "能知富貴尋常事，富貴能驕非丈夫。"]'),
('55bde405-17e8-4222-84d8-002f8bf2e414','無妄吟','邵雍','宋','宋诗','song-poetry','','[]','耳無妄聽，目無妄顧。',40,'全唐诗/poet.song.21000.json','["耳無妄聽，目無妄顧。", "口無妄言，心無妄慮。", "四者不妄，聖賢之具。", "予何人哉，敢不希慕。"]'),
('d2f7a62e-ad1b-4051-890e-3752bed515ec','善惡吟','邵雍','宋','宋诗','song-poetry','','[]','人善不趨，己惡不除。',20,'全唐诗/poet.song.21000.json','["人善不趨，己惡不除。", "謂之知道，不亦難乎。"]'),
('1999ef06-7a4b-4756-b2ae-26fce1c7df05','春日園中吟','邵雍','宋','宋诗','song-poetry','','[]','春暖遊園乃是常，城中殊不異仙鄉。',64,'全唐诗/poet.song.21000.json','["春暖遊園乃是常，城中殊不異仙鄉。", "竹間日日同真侶，水畔時時泛羽觴。", "雨後鳥聲移樹囀，風前花氣觸人香。", "林間富貴一般樂，更縱其來更不妨。"]'),
('ad7b0576-a31c-41ef-881d-b2603d0e2698','解字吟','邵雍','宋','宋诗','song-poetry','','[]','人言爲信，日月爲明。',20,'全唐诗/poet.song.21000.json','["人言爲信，日月爲明。", "止戈爲武，羔美爲羹。"]'),
('ab04b3f3-615a-4e1a-99bc-5e5ef9c0a045','感事吟','邵雍','宋','宋诗','song-poetry','','[]','芝蘭種不榮，荆棘剪不去。',24,'全唐诗/poet.song.21000.json','["芝蘭種不榮，荆棘剪不去。", "二者無柰何，徘徊歲將暮。"]'),
('ab18522c-ee4d-4582-b9b2-afa9bde9590f','窮達吟','邵雍','宋','宋诗','song-poetry','','[]','窮不能卷，達不能舒。',20,'全唐诗/poet.song.21000.json','["窮不能卷，達不能舒。", "謂之知道，不亦難乎。"]'),
('95b722c4-5605-4e55-91ae-3f2788c96a04','宇宙吟','邵雍','宋','宋诗','song-poetry','','[]','宇宙在乎手，萬物在乎身。',24,'全唐诗/poet.song.21000.json','["宇宙在乎手，萬物在乎身。", "緜緜而若存，用之豈有勤。"]'),
('f860554c-62fe-46bf-9552-5c336d09693e','久旱吟','邵雍','宋','宋诗','song-poetry','','[]','久旱望雨，久雨思晴。',20,'全唐诗/poet.song.21000.json','["久旱望雨，久雨思晴。", "天之常道，人之常情。"]'),
('82f0f9c9-b4ef-4e90-8278-22fc153ec7e0','成性吟','邵雍','宋','宋诗','song-poetry','','[]','成性存存，用志不分。',20,'全唐诗/poet.song.21000.json','["成性存存，用志不分。", "又何患乎，不到古人。"]'),
('0bc71180-7f8d-471c-ab0b-1cee6833add1','路徑吟','邵雍','宋','宋诗','song-poetry','','[]','面前路徑無令窄，路徑窄時無過客。',32,'全唐诗/poet.song.21000.json','["面前路徑無令窄，路徑窄時無過客。", "過客無時路徑荒，人間大率多荆棘。"]'),
('039885c9-84ff-4067-a51c-ef98a73cf88b','大人吟','邵雍','宋','宋诗','song-poetry','','[]','天道遠，人道邇。',16,'全唐诗/poet.song.21000.json','["天道遠，人道邇。", "盡人情，合天理。"]'),
('bff1a87d-ccfe-43c2-9831-f2e55788db9a','先天吟示邢和叔','邵雍','宋','宋诗','song-poetry','','[]','一片先天號太虛，當其無事見真腴。',64,'全唐诗/poet.song.21000.json','["一片先天號太虛，當其無事見真腴。", "胸中美物肯自衒，天下英才敢厚誣。", "理順是言皆可放，義安何地不能居。", "直從宇泰收功後，始信人間有丈夫。"]'),
('4b967c15-5c02-4d11-82ee-e17a11d9eab1','感事吟','邵雍','宋','宋诗','song-poetry','','[]','爲善大宜量力分，知幾都在近人情。',64,'全唐诗/poet.song.21000.json','["爲善大宜量力分，知幾都在近人情。", "人情盡後疑難入，力分量時事自平。", "理順面前皆道路，義乖門外是榛荆。", "何人肯認此言語，此語分明人不聽。"]'),
('ec21ddbc-8be1-4cc8-a7d4-3a0e439092bc','浩歌吟','邵雍','宋','宋诗','song-poetry','','[]','何者謂知幾，惟神能造微。',48,'全唐诗/poet.song.21000.json','["何者謂知幾，惟神能造微。", "行藏全在我，用捨擊於時。", "每恨知人晚，常憂見事遲。", "與天爲一體，然後識宣尼。"]'),
('4cd21a95-0a73-4b11-8dd9-567eff315931','利名吟','邵雍','宋','宋诗','song-poetry','','[]','利名都不到胸中，由此胸中氣自沖。',32,'全唐诗/poet.song.21000.json','["利名都不到胸中，由此胸中氣自沖。", "既愛且憎皆是病，靈臺何日得從容。"]'),
('e70d8705-3089-4e47-b5c5-fa6f291373e8','憑高吟','邵雍','宋','宋诗','song-poetry','','[]','誰將酷烈千般毒，變作恩光一派深。',32,'全唐诗/poet.song.21000.json','["誰將酷烈千般毒，變作恩光一派深。", "惆悵先民不復見，更凭高處儘沉吟。"]'),
('803aa412-4b26-4786-8637-aaf888670887','意盡吟','邵雍','宋','宋诗','song-poetry','','[]','意盡于物，言盡于誠。',20,'全唐诗/poet.song.21000.json','["意盡于物，言盡于誠。", "矯情鎮物，非我所能。"]'),
('3a51bcfc-a7a4-4de9-af8b-6260c905882b','浩歌吟  其一','邵雍','宋','宋诗','song-poetry','','[]','憂愁與喜歡，相去一毫間。',48,'全唐诗/poet.song.21000.json','["憂愁與喜歡，相去一毫間。", "治亂不同體，山川無兩般。", "笛聲方遠聽，草色正遥看。", "何處危樓上，斜陽人凭欄。"]'),
('da86f7f7-6d93-4f7e-999d-6a3096806cf7','浩歌吟  其二','邵雍','宋','宋诗','song-poetry','','[]','嘉善既難投，先生宜罷休。',48,'全唐诗/poet.song.21000.json','["嘉善既難投，先生宜罷休。", "履霜猶可救，滅木更何求。", "獸困重來日，鴻飛遠去秋。", "民饑須是食，食外盡悠悠。"]'),
('51c6b7ac-9fb0-468f-acfb-9b4b811122d7','溫良吟','邵雍','宋','宋诗','song-poetry','','[]','君子溫良當責備，小人情僞又須知。',32,'全唐诗/poet.song.21000.json','["君子溫良當責備，小人情僞又須知。", "因驚世上機關惡，遂覺壺中日月遲。"]'),
('9d77ff18-ebd7-4fcd-b1e2-9eeaa4d4c4b7','贈曾敬仲歸三衢','王柏','宋','宋诗','song-poetry','','[]','切切蛩吟雨後繁，急催客子整歸轅。',64,'全唐诗/poet.song.210000.json','["切切蛩吟雨後繁，急催客子整歸轅。", "臨行慷慨有忠告，前此賡酬總戲言。", "先世聲名期遠紹，故家風範要長存。", "花朋月友終無益，膏火青編緊閉門。"]'),
('dc799227-cd5c-4c73-931f-349ff31e0785','題果齋集後','王柏','宋','宋诗','song-poetry','','[]','童髽及侍果齋賢，白璧沈埋二十年。',64,'全唐诗/poet.song.210000.json','["童髽及侍果齋賢，白璧沈埋二十年。", "師道倦爲蓮幕客，詩魂蜚伴雪堂僊。", "同游諸老無人在，所幸斯文有子傳。", "讀到徐卿珠玉句，撫膺三歎愧遺編。"]'),
('1f78475f-7da7-4878-ad94-51e73f21b13c','題西樓有感','王柏','宋','宋诗','song-poetry','','[]','往事傷心不可論，高情還許小通門。',64,'全唐诗/poet.song.210000.json','["往事傷心不可論，高情還許小通門。", "旋鋤荒草追風景，因種殘花剗雪痕。", "敗壁古苔權作主，破窗夜雨暗消魂。", "青山不管興亡事，依舊樓頭挹暮樽。"]'),
('c86a3fd7-c6d2-4288-9d6a-b9c7bbccfd51','送金華趙宰二首  其一','王柏','宋','宋诗','song-poetry','','[]','絃歌聲裏一瓢安，士友催詩送長官。',64,'全唐诗/poet.song.210000.json','["絃歌聲裏一瓢安，士友催詩送長官。", "律己十分無可議，愛民一念未嘗寒。", "更知耐事如公少，留取清名作樣看。", "百姓越疆歸令問，恩流職外此尤難。"]'),
('11a60e5a-34a8-496a-b692-d94b3d7ebc3f','送金華趙宰二首  其二','王柏','宋','宋诗','song-poetry','','[]','六龍潜處起宗英，來作金華有脚春。',64,'全唐诗/poet.song.210000.json','["六龍潜處起宗英，來作金華有脚春。", "人被撫摩稱是佛，事歸聽斷果如神。", "忍看鳬舄雙飛去，趁得葭灰一點新。", "近世柏臺冠豸者，多求作邑有聲人。"]'),
('a3453b46-ed50-41d9-8131-7cd73a318189','和德夫弟韻','王柏','宋','宋诗','song-poetry','','[]','偶尋沮溺問年豐，負笈肩琴恨不同。',64,'全唐诗/poet.song.210000.json','["偶尋沮溺問年豐，負笈肩琴恨不同。", "春草池塘君有夢，秋風燈火我何工。", "年時猶願文加進，老大方憂道未洪。", "妙手自堪修五鳳，繩樞草舍愧吾窮。"]'),
('84285ebe-594d-47fe-8458-64a2eb1b5d79','題承庵二首  其一','王柏','宋','宋诗','song-poetry','','[]','十年足不到承庵，撫事興思重愴然。',64,'全唐诗/poet.song.210000.json','["十年足不到承庵，撫事興思重愴然。", "風急雁行斜漠漠，夜深蟾影弄娟娟。", "爐亭暖徹通宵火，魚板驚殘向曉眠。", "欲識本來真面目，杖藜未免再留連。"]'),
('035ba1f5-e5ad-4fb0-ba4a-b3ff2377d90e','題承庵二首  其二','王柏','宋','宋诗','song-poetry','','[]','神封王爵號優游，衆水奔歸祠下流。',64,'全唐诗/poet.song.210000.json','["神封王爵號優游，衆水奔歸祠下流。", "沃若郊原真可隠，悠然心景自相投。", "綿綿野徑蟠山腹，瑟瑟枯溪瀉石頭。", "直到法華高處望，天珍未許有心求。"]'),
('6220cf34-503b-4942-bc59-83daa201dc61','有感','王柏','宋','宋诗','song-poetry','','[]','歲月飄零事轉乖，未能憑酒放眉開。',64,'全唐诗/poet.song.210000.json','["歲月飄零事轉乖，未能憑酒放眉開。", "蕭蕭棠棣悲離黍，寂寞芝蘭閟野萊。", "生計半隨豪氣壞，放心猶傍聖經迴。", "秋來旱勢滔滔遠，誰念蒼生正可哀。"]'),
('c5a1663d-0759-4511-83ca-e90667e6fc98','適莊兄遊山','王柏','宋','宋诗','song-poetry','','[]','誰閣重陰一日晴，清游應是愜高情。',64,'全唐诗/poet.song.210000.json','["誰閣重陰一日晴，清游應是愜高情。", "遥知雨後山光好，但想雲邊屐齒清。", "素壁雖曾題舊字，沈痾不許插新盟。", "因知關吏留魚鑰，謾遣奚奴候晚程。"]'),
('ea155e8e-6514-416b-8ad8-486ff0bd794a','元夕後即事','王柏','宋','宋诗','song-poetry','','[]','夜來風色作清寒，燈火殘時人意闌。',64,'全唐诗/poet.song.210000.json','["夜來風色作清寒，燈火殘時人意闌。", "歸路月華猶皎皎，今朝雪影亂漫漫。", "比他柳絮真無頼，損盡梅花不忍看。", "獨坐不知時節變，一襟和氣有餘歡。"]'),
('e822ff2a-84f8-4a54-ac14-2414c03161a7','題潘氏高遠臺','王柏','宋','宋诗','song-poetry','','[]','數曲梯階稍欠寬，略移武步到仙寰。',64,'全唐诗/poet.song.210000.json','["數曲梯階稍欠寬，略移武步到仙寰。", "詩懷納盡雙溪景，眼力推開千里山。", "方檻小欹煙雨外，飛蓬斜插斗牛間。", "馮虛似駕臨臯鶴，棲鶻危巢不足攀。"]'),
('517279d9-5b28-420b-9507-32144dc59312','送蒙齋姪宰餘姚','王柏','宋','宋诗','song-poetry','','[]','鳬舄攙先伯仲間，迎陽带雨渡天關。',64,'全唐诗/poet.song.210000.json','["鳬舄攙先伯仲間，迎陽带雨渡天關。", "向來邑爲貪風壞，此去民思善政安。", "三百里同開魯國，二千石即繼壺山。", "蒲封正次東溟側，要拓胸襟箇樣寬。"]'),
('5d5bc623-735b-49a0-af44-3297ab3ee60d','和胡子升大欠韻','王柏','宋','宋诗','song-poetry','','[]','能踐其形亦甚難，天高地下我中間。',64,'全唐诗/poet.song.210000.json','["能踐其形亦甚難，天高地下我中間。", "讀書未造精微閫，處世應迷利欲關。", "勉勉工夫何假字，區區繪事豈真顔。", "須知天賦元無欠，還爾當時勿恃還。"]'),
('e93e9eb0-9ef5-456f-bc7c-e6afa48cd277','新秋自警','王柏','宋','宋诗','song-poetry','','[]','直諒之言久不聞，秋來因作讀書吟。',64,'全唐诗/poet.song.210000.json','["直諒之言久不聞，秋來因作讀書吟。", "時時涵泳味無味，句句研窮深又深。", "老去已辜朋友望，閑中粗得聖賢心。", "無情歲月垂垂盡，夕秀朝華豈暇尋。"]'),
('7c30e0b3-83c2-43c8-b844-49471a5b3e81','黄華歌','王柏','宋','宋诗','song-poetry','','[]','太極動兮兩儀分，四序綱領秋與春。',318,'全唐诗/poet.song.210000.json','["太極動兮兩儀分，四序綱領秋與春。", "機緘密運乎三百六十五度之外，浩浩萬物資生成。", "清明純淑不易遇，間稟英氣俱異人。", "堂堂忠定公，獨得東方仁。", "維持帝出震，嵩岱鍾精神。", "定策慶元初，皇宋二百四十年社稷歸經綸。", "肆我東陽侯，獨得金天晶。", "兌正秋兮萬寶說，宗星夜挾長庚精。", "扶珪綴組真相種，來與十有四葉天子蘇寰瀛。", "春生秋殺造化功始備，前輝後映行見旂常新。", "炯炯御屏上，高揭刺史名。", "仁風靄四郡，溪山草木俱被循良聲。", "須女曉浮南極瑞，山光水氣騰祥雲。", "百姓欣欣有喜色，一步拜手祈松椿。", "日君煥赫停寶馭，月妃婐{女卮}留文茵。", "金風玉露澄象緯，洞洞下鑒民之情。", "一祝吾侯早歸絳闕佐明主，坐使天下風俗還真淳。", "再祝吾侯多男子，森森蘭玉盈階庭。", "三祝吾侯春秋八千歲，瓊漿玉斝長對黄華斟。"]'),
('6e1e82e5-101b-4429-878f-03a83b2fe3ee','竹石屏歌謝遁澤','王柏','宋','宋诗','song-poetry','','[]','好古博雅時遁澤，往歲贈我墨圖柏。',386,'全唐诗/poet.song.210000.json','["好古博雅時遁澤，往歲贈我墨圖柏。", "今年揆予初度臨，又復持贈竹石屏。", "柏以祝我老，竹以堅我心。", "長歌短歌先後發，書室夜夜生光熒。", "君才固磊落，愛我何獨深。", "此石不知出何地，來自紫陽夫子門。", "紫陽緣督兩授受，謂宜永作傳家珍。", "所寶又有大於此，餘光委照非其人。", "以我所願紫陽學，以我生作石笋孫。", "石笋固宜有石竹，笋竹生成同一根。", "當時竹上歲寒句，先達難賞流傳今。", "去年忽得紫陽歲寒字，如約屏石來同盟。", "朝夕歛身對二妙，儼然拱侍滄洲之竹林，寓物敬慕度義全幽貞。", "不有畏友相勉勵，安得準繩磨琢箴。", "句中雅意已佩服，石中有竹誰能評。", "歐梅蘇范六君子，絕識雄辨萬口稱。", "珠犀砂玉亦似矣，髣髴未得此理真。", "顧我生既晚，欲說口已瘖。", "造化發育固難測，嘗聞古有剛柔分。", "柔土既發萬物之生氣，剛土故涵萬物之陰精。", "人之所見自有限，熟識萬象俱妙凝。", "此非物之影，真是竹之形。", "遺梢墜葉積於土，土化爲石竹自存。", "生物不隨凝結變，請觀琥珀與水晶。"]'),
('8704c3cd-f719-4ecf-babc-3c0e063392f7','和希夷木犀韻','王柏','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋來望月如水犀，忽有香風鼻觀吹。',229,'全唐诗/poet.song.210000.json','["秋來望月如水犀，忽有香風鼻觀吹。", "徧尋不得見花面，若得見花敢輕賤。", "徐徐步轉牆角來，草色芊芊一徑開。", "儼然嘉樹奠南服，環佩鏘鏘萬圭綠。", "陽豔多情不敢媒，平生偶與西風熟。", "皇天清則土方真，耿耿誰如受命獨。", "三閭愁兮洞庭波，辛蓀蘭芷方並蓄。", "只有淮南招隠句，攀緣千古資膏馥。", "希夷雅好異於是，萬斛清香金一粟。", "曜靈西征易侵尋，綠鬢朱顔不待人。", "秋花不比春花早，開到秋花也是春。", "吟花弄葉何時足，年少須臾成老宿。", "一根生意貴栽培，力到自然文郁郁。", "君不見岩花獨步秋葉中，穿天出月莫敢相過從。"]'),
('59b06f2c-960a-4a34-a480-7a328fa7c38b','和易巖春雪韻','王柏','宋','宋诗','song-poetry','','[]','臘前雷，春半雪。',144,'全唐诗/poet.song.210000.json','["臘前雷，春半雪。", "顛倒失其時，相去踰一月。", "一月不爭多，燠寒異厥罰。", "垤戶當堅凝，陽氣乃舒發。", "草木既萌動，龍蛇起窟穴。", "萬物欣向榮，獰風夜狂悖。", "曉雞噤不鳴，但見窗間白。", "戰慄起推戶，瓊瑶已幾尺。", "陋巷書生釜不煙，關河甲士冰到骨。", "俯仰天地間，芽甲盡摧折。", "萬境寂無聲，羣動亦僵裂。", "當其懷煦煦，蠢蠢競懽悅。"]'),
('a12322d6-f43f-45cb-b696-3b62cfacf06e','和立齋抱膝吟三章  其一','王柏','宋','宋诗','song-poetry','','[]','帝腹加頑足，上干天象速。',56,'全唐诗/poet.song.210000.json','["帝腹加頑足，上干天象速。", "造膝論當世，從容金殿旭。", "人生莫不有行藏，誰把行藏較短長。", "要識行藏無所爲，時哉出處總輝光。"]'),
('fd0fb2fb-66f9-455a-81a7-5ba831a55bd3','和立齋抱膝吟三章  其二','王柏','宋','宋诗','song-poetry','','[]','誰卧草廬中，能耑一壑風。',56,'全唐诗/poet.song.210000.json','["誰卧草廬中，能耑一壑風。", "當時天地閉，豪傑不相容。", "中原河岳應如舊，虎豹出沒非人有。", "祗今不是龍卧時，自是君才掣君肘。"]'),
('56fabbd5-f42b-4130-8b8b-0e4cb1f5c75f','和立齋抱膝吟三章  其三','王柏','宋','宋诗','song-poetry','','[]','山澤兩癯叟，交情幾昏曉。',56,'全唐诗/poet.song.210000.json','["山澤兩癯叟，交情幾昏曉。", "擁衾風雪夜，奇論互傾倒。", "妙處不盡千張紙，直到無言忘寤寐。", "如何漏泄此高吟，一灑龍蛇駭塵世。"]'),
('36b6368f-5268-4791-bc05-f1c9f520ca4a','和易巖木犀韻','王柏','宋','宋诗','song-poetry','','[]','秋光未爲老，老桂開牆隈。',160,'全唐诗/poet.song.210000.json','["秋光未爲老，老桂開牆隈。", "雖與春風背，依吐心未灰。", "香浮玉宇遠，體破金粟微。", "詩翁被花惱，深夜燈重吹。", "今朝恰重九，更瀉茱萸巵。", "霜螯未堪把，菊蕊青滿畦。", "景物自冉冉，氣候猶遲遲。", "對花莫冷淡，行樂姑隨時。", "清歡既易遇，不飲復何爲。", "兄弟琴瑟合，子姪鴻雁隨。", "月明人影散，泚筆賡新詩。", "詩力籋天馬，不可銜勒羈。", "詩壇峻極謝推轂，莫學檀公三十六。"]'),
('bdc593cb-909c-4857-bef7-b6fa56bc8f66','和叔崇','王柏','宋','宋诗','song-poetry','','[]','人心乘氣機，投閑肆馳逐。',124,'全唐诗/poet.song.210000.json','["人心乘氣機，投閑肆馳逐。", "飛天忽淪淵，忘生以徇欲。", "大而名節喪，甚者邦家覆。", "一狂方寸亂，一安萬事足。", "簞瓢樂陋巷，粱肉怕書腹。", "平時工用深，舉動自絕俗。", "倀倀無所守，有爲皆碌碌。", "一墮荆榛中，終身困躑躅。", "世事豈有常，烏可執卷贖。", "學問在我毋自棄，富貴在天毋自辱。"]'),
('69ffec52-2638-4660-ba4f-7e3f9b25092b','和立齋元日韻','王柏','宋','宋诗','song-poetry','','[]','之子善遊遠，西征酹歐陽。',100,'全唐诗/poet.song.210000.json','["之子善遊遠，西征酹歐陽。", "亹亹歲月換，作詩思故鄉。", "老我絕世念，孤燈耿寒光。", "坐對三古書，繹繹搴純英。", "天地時一泰，吾道何時昌。", "莫以一日腴，博此千載香。", "苟不新厥德，正亦王春常。", "只今自煮一斗酒，待子醉我琴書旁。"]'),
('0d66afb3-1dfd-42fd-83fb-095c3d0983cd','壽立齋','王柏','宋','宋诗','song-poetry','','[]','思泉種德懋，后皇命淳美。',204,'全唐诗/poet.song.210000.json','["思泉種德懋，后皇命淳美。", "髧髦傳正學，一念不妄起。", "真固滿腔仁，兢兢日增累。", "甲子正一周，龐眉追甪綺。", "年年三月初，南極何煒煒。", "預酌長生尊，家慶合庭鯉。", "今歲南極光，一照千餘里。", "我有百靈丹，遠寄螺江邊。", "殷勤爲子壽，角亢光芒寒。", "一丸當一歲，送以華池泉。", "初進雙目清，再進華顛玄。", "三進毛骨換，四進還童顔。", "五進志氣神，六七八進生羽翰。", "進進誠不已，俯拍洪崖肩。", "不須駕黄鵠，炯炯天地之方圓。", "只恐獨立無與侶，不如歸來歲寒之下相周旋。"]'),
('48944d73-8161-4106-8d3a-061742b6a2e2','贈朱道人','王柏','宋','宋诗','song-poetry','','[]','道人跨鶴徧天涯，偉觀絕景收拾歸。',162,'全唐诗/poet.song.210000.json','["道人跨鶴徧天涯，偉觀絕景收拾歸。", "點頭濡墨茅屋下，乘興吐出胸中奇。", "百尺生綃冰樣潔，落筆一埽風雨馳。", "遠水拍天窮萬折，怪石磽确蹲熊羆。", "槎牙古木蛟龍走，斷雲寂寞無心飛。", "淡妝濃抹西子面，天梯石棧猿猱悲。", "野騎殘僧小橋險，酒帘漁棹摇斜暉。", "生綃有限意難盡，兀坐靜境窺天機。", "豈知造化無盡藏，奔會筆底無盈虧。", "射洪川幅非我有，且遣楮君百輩供指麾。"]'),
('8c58ffb5-2957-4d77-9c4b-c3e858a71737','夜宿赤松梅師房','王柏','宋','宋诗','song-poetry','','[]','梅師有松度，蕭散意態真。',92,'全唐诗/poet.song.210000.json','["梅師有松度，蕭散意態真。", "皮冠簪白雪，布褐貯陽春。", "房計任簡淡，了無一慮塵。", "茶一碗，酒一尊，熙熙天地一閑人。", "名山浮爽秀，朝暮瀹爾神。", "餐霞煉日氣，井竈求遺珍。", "希夷仙境本不遠，何用抱樸終其身。"]'),
('c7dbc68b-de61-4a3d-9797-bb63a840f6b3','汲齋吟','王柏','宋','宋诗','song-poetry','','[]','我有一泓水，清明如鑑開。',140,'全唐诗/poet.song.210000.json','["我有一泓水，清明如鑑開。", "妍醜自來往，曾不留纖埃。", "靜而涵萬古，動時濡九垓。", "人與我同得，是名爲靈臺。", "胡乃忍蕪穢，漂淪良可哀。", "當知克己如汲井，汲去汙濁清自回。", "洙泗淵源初不息，河洛流派空爭猜。", "爲學工夫孰大此，莫翻波浪驚兒孩。", "昌黎脩綆志徒苦，瘦島轆轤用未該。", "請觀朱子方塘喻，要識源頭活水來。"]'),
('f51deef1-6624-4ccc-8b3a-a4969e9e060e','壽藤杖行','王柏','宋','宋诗','song-poetry','','[]','君不見奇章咨嗟削方竹，老杜作詩誇紫玉。',198,'全唐诗/poet.song.210000.json','["君不見奇章咨嗟削方竹，老杜作詩誇紫玉。", "又不見東坡驚喜鐵鏗然，靈壽曾爲漢臣辱。", "我有怪藤幾千歲，老髯乳節雷斧斸。", "古苔蒼蘚封護祕，風刪雨剝枝榦禿。", "頭角軒昂曲虬勢，皮毛冷滑鳥蛇腹。", "鶴膝銅環不敢班，武夷湘水皆退縮。", "不借山翁荷蓧去，未逢太乙然藜讀。", "祥光閃閃意有在，殷勤來壽徐平叔。", "平叔樂道玄又玄，奼女嬰兒丹久熟。", "兩脚踏在真實地，一善滿載長生籙。", "採芝覓藥扶峻嶮，敲雲挑月相追逐。", "有時化作葛陂龍，先生騎上蓬萊宿。"]'),
('99259dba-2d2d-46b6-8d5e-f579ae561567','廣曾敬仲','王柏','宋','宋诗','song-poetry','','[]','功名須少年，老大意終懶。',140,'全唐诗/poet.song.210000.json','["功名須少年，老大意終懶。", "學問本無窮，青春嗟有限。", "用處不需多，雲霄路坦坦。", "賈生正英銳，郎潛自羞赧。", "文字浩如山，奏功五寸管。", "達者未必長，窮者未所短。", "人生窮達各有時，脩爲在我當自反。", "螢桉尚研摩，况有五花館。", "當年驕惰氣，猶頼世情剗。", "只有學道心，歉然不自滿。", "庭外槐花任爾黄，達人高視供一莞。"]'),
('170eee05-f864-462a-9f7b-511ba97da409','和立齋歲寒歌五章  其一','王柏','宋','宋诗','song-poetry','','[]','羌人生之秉貞兮孰無陽秋，惟澹而無欲兮斯能無求。',47,'全唐诗/poet.song.210000.json','["羌人生之秉貞兮孰無陽秋，惟澹而無欲兮斯能無求。", "宜此心之冰堅兮凜北風之正遒，歲寒之堂兮足以自修。"]'),
('0219c0cd-22f7-48e7-89d4-eac1bdb230f9','和立齋歲寒歌五章  其二','王柏','宋','宋诗','song-poetry','','[]','憶昔堅保兮銘著心腑，故迹堙蕪兮茫茫墜緒。',41,'全唐诗/poet.song.210000.json','["憶昔堅保兮銘著心腑，故迹堙蕪兮茫茫墜緒。", "瞻翠碧之萬竿兮猶有遺矩，歲寒之句儼然如覩。"]'),
('a08b73f6-a8a3-4ff2-9460-7d681626b764','和立齋歲寒歌五章  其三','王柏','宋','宋诗','song-poetry','','[]','聖人體物兮萬世之訓，究厥後凋兮基於不競。',41,'全唐诗/poet.song.210000.json','["聖人體物兮萬世之訓，究厥後凋兮基於不競。", "使與春爭妍兮曷保常真，歲寒之知兮寧不謂性。"]'),
('d86cc373-caa7-4e25-b414-3a5d0c58f3ab','和立齋歲寒歌五章  其四','王柏','宋','宋诗','song-poetry','','[]','有勗我人兮先君之思，有陟爾岵兮我心傷悲。',42,'全唐诗/poet.song.210000.json','["有勗我人兮先君之思，有陟爾岵兮我心傷悲。", "望松柏之蒼蒼兮我無令姿，歲寒之操兮炯炯心期。"]'),
('695d4dc0-7280-4dda-aea7-8973c6733e69','和立齋歲寒歌五章  其五','王柏','宋','宋诗','song-poetry','','[]','車馬南歸兮惠我五闋，一唱三歎兮亦孔之惙。',41,'全唐诗/poet.song.210000.json','["車馬南歸兮惠我五闋，一唱三歎兮亦孔之惙。", "盍置諸左右兮觀省昭揭，歲寒之歌兮聲聲激烈。"]'),
('f10b685f-0c36-416e-a75f-02de2dc7e7f3','和廬山高韻','王柏','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','北山之北幾千古兮，崷嵐層嶂數百疊，巋然橫枕乎浙江。',321,'全唐诗/poet.song.210000.json','["北山之北幾千古兮，崷嵐層嶂數百疊，巋然橫枕乎浙江。", "歷潛岳石磴綿延而上，是爲山橋之絕景兮，驚霆噴雪終歲聲擊撞。", "風柔日暖花氣發，綦屨杖策而一遊兮，躋攀分寸獵犖确，如躡太虛之渾庬。", "峭壁立之萬仞兮，著亭對峙窺谽谾。", "雲中泉石更磊磊，玉虹步步鳴淙淙。", "清風滿峽振衣袂，清湍脩竹飛斜矼。", "目極千里倚層檻，煙光晻曖兮，樓臺城疊隠隠呈紛哤。", "上有陽精陰魄走飛轂，下有蜷松偃柏驂旌𣄛。", "安期棋局在何處，時有平空特起雲車雙。", "洞陽有館足高卧，神融氣一澄世痝。", "參橫斗轉萬籟寂，夜夜山鬼窺燈缸。", "羨君胸中隘宇宙，通明疏暢開八窗。", "手闢書堂攬奇秀，芳聲聞帝所錫奎畫昭回五色琱貞玒。", "涵蓄平生霖雨志，不應懷寶迷其邦。", "羞芝餱菊我輩事，春猿秋鶴心空降。", "誠欲遂公赤松黄石約，更書旂常功業垂朱杠。"]'),
('b582718f-218e-4e14-bbcb-7e99d297833f','題玉澗八景八首  其一','王柏','宋','宋诗','song-poetry','','[]','畫出女牆月，老子興不淺。',24,'全唐诗/poet.song.210000.json','["畫出女牆月，老子興不淺。", "誰識春光中，解使平湖歛。"]'),
('8da1a047-53ac-4cd2-9f3c-ae288dfc255c','題玉澗八景八首  其二','王柏','宋','宋诗','song-poetry','','[]','斷嶼數行樹，孤舟一葉橫。',24,'全唐诗/poet.song.210000.json','["斷嶼數行樹，孤舟一葉橫。", "前山風雨暗，此岸已天明。"]'),
('efff5df2-b343-4bbf-972d-080555d34729','題玉澗八景八首  其三','王柏','宋','宋诗','song-poetry','','[]','山外江村晚，縱橫八九家。',24,'全唐诗/poet.song.210000.json','["山外江村晚，縱橫八九家。", "過橋無路處，人思渺天涯。"]'),
('5a766e15-50e8-4673-af6c-36f3d77d4f1e','題玉澗八景八首  其四','王柏','宋','宋诗','song-poetry','','[]','點點飛來鴈，空中若有音。',24,'全唐诗/poet.song.210000.json','["點點飛來鴈，空中若有音。", "詩翁正牢落，識汝別離心。"]'),
('7af80862-3751-4775-86c2-b18365b084ef','題玉澗八景八首  其五','王柏','宋','宋诗','song-poetry','','[]','梵宇出林杪，暝色歛烟樹。',24,'全唐诗/poet.song.210000.json','["梵宇出林杪，暝色歛烟樹。", "鐘聲有無中，聽於無聽處。"]'),
('8303fa47-a2f7-4db2-9fef-0f09d4953dea','題玉澗八景八首  其六','王柏','宋','宋诗','song-poetry','','[]','落日下大野，江邊漁事收。',24,'全唐诗/poet.song.210000.json','["落日下大野，江邊漁事收。", "小舟橫斷岸，長笛一聲秋。"]'),
('81d286c0-76de-406b-a357-f037cd70a347','題玉澗八景八首  其七','王柏','宋','宋诗','song-poetry','','[]','慘淡經營中，落筆景已換。',24,'全唐诗/poet.song.210000.json','["慘淡經營中，落筆景已換。", "不見片帆歸，危檣還泊岸。"]'),
('3e687799-5e4a-47a5-8fa2-d013f5c7701f','題玉澗八景八首  其八','王柏','宋','宋诗','song-poetry','','[]','獨跨藍關馬，茫茫道且長。',24,'全唐诗/poet.song.210000.json','["獨跨藍關馬，茫茫道且長。", "誰知寒徹骨，一雪到瀟湘。"]'),
('156b7c26-c3a9-417f-aec1-9187a273cd45','題時遁澤畫卷十首  其一','王柏','宋','宋诗','song-poetry','','[]','斷岸臨江渚，風聲瑟瑟寒。',24,'全唐诗/poet.song.210000.json','["斷岸臨江渚，風聲瑟瑟寒。", "蒼髯五君子，莫作大夫看。"]'),
('780f55eb-4433-431e-9767-ee109314c881','題時遁澤畫卷十首  其二','王柏','宋','宋诗','song-poetry','','[]','浩浩雲橫塢，霏霏雨不收。',24,'全唐诗/poet.song.210000.json','["浩浩雲橫塢，霏霏雨不收。", "野橋人少度，寂寞卧清秋。"]'),
('bf2733db-b26f-4b8d-92dc-2977e2d3594d','題時遁澤畫卷十首  其三','王柏','宋','宋诗','song-poetry','','[]','虎嘯風生壑，龍藏氣吐雲。',24,'全唐诗/poet.song.210000.json','["虎嘯風生壑，龍藏氣吐雲。", "草廬勿高卧，天地正絪縕。"]'),
('6b387495-c99b-4d66-846e-ede5fe5cba6b','題時遁澤畫卷十首  其四','王柏','宋','宋诗','song-poetry','','[]','礉礉石林立，滃滃雲壑閟。',24,'全唐诗/poet.song.210000.json','["礉礉石林立，滃滃雲壑閟。", "萬杉最深中，莫有前朝寺。"]'),
('5ac69118-b84a-4b8d-b6f5-50810838cb26','題時遁澤畫卷十首  其五','王柏','宋','宋诗','song-poetry','','[]','江村依密樹，目遠送征鴻。',24,'全唐诗/poet.song.210000.json','["江村依密樹，目遠送征鴻。", "不盡暮天碧，誰續蘆花風。"]'),
('d16bf58d-790b-49da-bde7-633f6a5f3a15','題時遁澤畫卷十首  其六','王柏','宋','宋诗','song-poetry','','[]','巨石聳鰲脊，飛泉潄雪濤。',24,'全唐诗/poet.song.210000.json','["巨石聳鰲脊，飛泉潄雪濤。", "一聲何處笛，呼雨到江臯。"]'),
('95008256-f6f7-4353-ab9f-0d889e12fa53','題時遁澤畫卷十首  其七','王柏','宋','宋诗','song-poetry','','[]','一壑雲屏展，江橫萬里長。',24,'全唐诗/poet.song.210000.json','["一壑雲屏展，江橫萬里長。", "漁舟下灘去，寂寞舞斜陽。"]'),
('4fabefe1-ecaa-43be-87e1-8d29a2bd57d4','題時遁澤畫卷十首  其八','王柏','宋','宋诗','song-poetry','','[]','一雲山萬重，天地混不分。',24,'全唐诗/poet.song.210000.json','["一雲山萬重，天地混不分。", "須臾風浪惡，舟楫泊江濆。"]'),
('b96412ec-126e-4301-88c2-0df1c5a65908','題時遁澤畫卷十首  其九','王柏','宋','宋诗','song-poetry','','[]','精藍夾江干，鐘鼓時相應。',24,'全唐诗/poet.song.210000.json','["精藍夾江干，鐘鼓時相應。", "兩山遮不斷，樓閣若爭勝。"]'),
('5a033c69-47c9-47d8-a281-529156c1dbb9','題時遁澤畫卷十首  其一○','王柏','宋','宋诗','song-poetry','','[]','浩浩乾坤闊，微微見斷山。',24,'全唐诗/poet.song.210000.json','["浩浩乾坤闊，微微見斷山。", "頗興浮海意，吾道正多艱。"]'),
('2f91677f-43a3-4c9a-81c8-b4a569cf26ca','題澤翁小卷  其一','王柏','宋','宋诗','song-poetry','','[]','綠陰最深處，樓閣出林杪。',24,'全唐诗/poet.song.210000.json','["綠陰最深處，樓閣出林杪。", "江闊野橋間，目斷行人少。"]'),
('531ae989-fedb-4ecd-8c30-4c93a79bcf2c','題澤翁小卷  其二','王柏','宋','宋诗','song-poetry','','[]','斷岸江波闊，迢迢十里寬。',24,'全唐诗/poet.song.210000.json','["斷岸江波闊，迢迢十里寬。", "人煙藏處密，霽色媚寒灘。"]'),
('f4c69e3f-de5e-40e3-8cec-f68ef3c428ce','題澤翁小卷  其三','王柏','宋','宋诗','song-poetry','','[]','石護山溪口，溪溪自有原。',24,'全唐诗/poet.song.210000.json','["石護山溪口，溪溪自有原。", "若非江海量，曷受百川奔。"]'),
('579e7afc-9173-4e79-bde0-c80e030d3aa8','題澤翁小卷  其四','王柏','宋','宋诗','song-poetry','','[]','寂寞小橋前，山人住何處。',24,'全唐诗/poet.song.210000.json','["寂寞小橋前，山人住何處。", "村童酤酒隨，策杖同歸去。"]'),
('09d8eb9f-54a8-4cdd-8e85-7308640eda74','題澤翁小卷  其五','王柏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','兩水匯長江，絕壁上蒼翠。',24,'全唐诗/poet.song.210000.json','["兩水匯長江，絕壁上蒼翠。", "前頭風浪惡，危檣且深避。"]'),
('adc61105-6f0e-4818-8853-34f3b7df5ec8','題澤翁小卷  其六','王柏','宋','宋诗','song-poetry','','[]','縹緲雲煙外，迢迢江水明。',24,'全唐诗/poet.song.210000.json','["縹緲雲煙外，迢迢江水明。", "數家藏密樹，一塔峭孤城。"]'),
('e65a9647-b7d3-4920-8d86-a0f9c06c3aa5','題澤翁小卷  其七','王柏','宋','宋诗','song-poetry','','[]','野渡人歸處，縱橫八九家。',24,'全唐诗/poet.song.210000.json','["野渡人歸處，縱橫八九家。", "晚來寒力健，風颭酒帘斜。"]'),
('c54f57c8-6e48-425c-b80e-2ba4a9e80d2a','題澤翁小卷  其八','王柏','宋','宋诗','song-poetry','','[]','晚得知心友，芳樽日日開。',24,'全唐诗/poet.song.210000.json','["晚得知心友，芳樽日日開。", "不辭江路遠，依舊抱琴來。"]'),
('dbd80491-b7da-4b49-a07a-ddad3679ea8f','題澤翁小卷  其九','王柏','宋','宋诗','song-poetry','','[]','名利驅馳急，江山自古今。',24,'全唐诗/poet.song.210000.json','["名利驅馳急，江山自古今。", "舟行水上意，人立渡頭心。"]'),
('34d7c8f7-781c-4d92-8dc3-4ef694587366','題澤翁小卷  其一○','王柏','宋','宋诗','song-poetry','','[]','到岸未爲了，行行萬里塗。',24,'全唐诗/poet.song.210000.json','["到岸未爲了，行行萬里塗。", "舉頭岐路惑，岩畔遇樵夫。"]'),
('46e8cb04-8e76-4d3e-aa24-7daf0a070f86','題潘氏山水壁','王柏','宋','宋诗','song-poetry','','[]','疊巘雲煙表，茅檐竹樹中。',24,'全唐诗/poet.song.210000.json','["疊巘雲煙表，茅檐竹樹中。", "起予深隠趣，筆底有高風。"]'),
('e07085ba-ab49-47a8-ba61-014c9f9f5685','呆官人三絕  其一','王柏','宋','宋诗','song-poetry','','[]','直道難行久，前程豈易裁。',24,'全唐诗/poet.song.210000.json','["直道難行久，前程豈易裁。", "遜齋姜辣口，奄有世間獃。"]'),
('540faa34-ff92-44a5-bfb5-fab2cc4176c0','呆官人三絕  其二','王柏','宋','宋诗','song-poetry','','[]','冷面無慚色，真心不脫空。',24,'全唐诗/poet.song.210000.json','["冷面無慚色，真心不脫空。", "雖然獃在我，終是與人忠。"]'),
('1d68692c-40ec-4a36-a1d1-72fb751bc8fa','呆官人三絕  其三','王柏','宋','宋诗','song-poetry','','[]','獃本非嘉德，如何樂此名。',24,'全唐诗/poet.song.210000.json','["獃本非嘉德，如何樂此名。", "能於獃外看，方見業之精。"]'),
('9075d87d-166e-44d0-b206-620ad191734a','題梅','王柏','宋','宋诗','song-poetry','','[]','萬物正摇落，梅花獨可人。',24,'全唐诗/poet.song.210000.json','["萬物正摇落，梅花獨可人。", "空中三五點，天地便精神。"]'),
('f35c9120-3e58-4638-872d-ccc1d42f1a9c','題流觴圖','王柏','宋','宋诗','song-poetry','','[]','東晉羣賢事已荒，却於紙上見清狂。',32,'全唐诗/poet.song.210000.json','["東晉羣賢事已荒，却於紙上見清狂。", "茂林脩竹今何在，一段風流付夕陽。"]'),
('ca22953d-9157-4044-8a24-8943860fc44c','題浴沂圖','王柏','宋','宋诗','song-poetry','','[]','一時言志聖師前，鼓瑟聲中三月天。',32,'全唐诗/poet.song.210000.json','["一時言志聖師前，鼓瑟聲中三月天。", "誰識詠歸真樂意，如何却向畫圖傳。"]'),
('8bb92395-4c48-4a1f-b4a0-bbc940aa5e36','題長江圖三絕  其一','王柏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一目長江萬里長，幾多興廢要商量。',32,'全唐诗/poet.song.210000.json','["一目長江萬里長，幾多興廢要商量。", "時人莫作畫圖看，說著源頭正可傷。"]'),
('cb65e580-2d26-4d8d-95ce-4e48e1fadf2c','題長江圖三絕  其二','王柏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','魚腹江邊八陣圖，嶙峋於此豈良謨。',32,'全唐诗/poet.song.210000.json','["魚腹江邊八陣圖，嶙峋於此豈良謨。", "後來浪道長蛇勢，用勢還須烈丈夫。"]'),
('92f8340a-23cb-4b7b-82fe-312485eccb15','題長江圖三絕  其三','王柏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','瓜步洲前水最深，幾人恃此縱荒淫。',32,'全唐诗/poet.song.210000.json','["瓜步洲前水最深，幾人恃此縱荒淫。", "誰云天意分南北，自是人無混一心。"]'),
('ac28ce8a-b07a-4e90-b244-dae71f179531','獨坐看海棠二絕  其一','王柏','宋','宋诗','song-poetry','','[]','萬翠千紅各賦形，源源生意到春深。',32,'全唐诗/poet.song.210000.json','["萬翠千紅各賦形，源源生意到春深。", "誰開錦帳藏妖豔，應是東皇有蕩心。"]'),
('2eceb8ae-a0be-4217-a1c9-ac516d24a412','獨坐看海棠二絕  其二','王柏','宋','宋诗','song-poetry','','[]','沈香亭下太真妃，一笑嫣然國已危。',32,'全唐诗/poet.song.210000.json','["沈香亭下太真妃，一笑嫣然國已危。", "當日杜陵深有恨，何心更作海棠詩。"]'),
('bb697a9f-6d97-45bd-835e-3387ee0f0a1a','題山橋十首  其一','王柏','宋','宋诗','song-poetry','','[]','軋軋飛車入翠微，人於妙處未深知。',32,'全唐诗/poet.song.210000.json','["軋軋飛車入翠微，人於妙處未深知。", "自從標榜新拈掇，碎却山橋一段奇。"]'),
('bf8c95a1-e366-4816-9a86-f9ab49796feb','題山橋十首  其二','王柏','宋','宋诗','song-poetry','','[]','北山之北兩山馳，一逕蜿蜒石作梯。',32,'全唐诗/poet.song.210000.json','["北山之北兩山馳，一逕蜿蜒石作梯。", "脚力倦時山始好，芙蓉東畔赤松西。"]'),
('b327fd2e-3b97-48e8-b674-8804db1d04d8','題山橋十首  其三','王柏','宋','宋诗','song-poetry','','[]','石磴斜蹊下水隈，玉虹噴雪掛崔嵬。',32,'全唐诗/poet.song.210000.json','["石磴斜蹊下水隈，玉虹噴雪掛崔嵬。", "雖然只是泉三疊，滂湃聲摇萬壑雷。"]'),
('e3c7cf5f-eac5-4f29-b3da-0d6247ce2547','題山橋十首  其四','王柏','宋','宋诗','song-poetry','','[]','危嵐鐵面太巖巖，少憩茅欄石下龕。',32,'全唐诗/poet.song.210000.json','["危嵐鐵面太巖巖，少憩茅欄石下龕。", "壁立晴空幾萬仞，承天一柱在東南。"]'),
('ba97e306-4b25-479a-a315-cb053dcc7a9f','題山橋十首  其五','王柏','宋','宋诗','song-poetry','','[]','世事難憑轉眼空，可人泉石在雲中。',32,'全唐诗/poet.song.210000.json','["世事難憑轉眼空，可人泉石在雲中。", "此心多少閑丘壑，且發微機與衆同。"]'),
('d529ceb5-e9fe-454c-9dff-eac8e19475d4','題山橋十首  其六','王柏','宋','宋诗','song-poetry','','[]','脩竹清湍記永和，山陰陳迹已消磨。',32,'全唐诗/poet.song.210000.json','["脩竹清湍記永和，山陰陳迹已消磨。", "四時佳興隨人寓，曲水流觴未足多。"]'),
('2c798225-e8c4-4b61-bf1a-a2a692e126d2','題山橋十首  其七','王柏','宋','宋诗','song-poetry','','[]','步隨流水覓清陰，亂石穿林窈窕深。',32,'全唐诗/poet.song.210000.json','["步隨流水覓清陰，亂石穿林窈窕深。", "澗谷未能忘磊磊，何如虛豁一生心。"]'),
('c8a6ed66-c3ef-4ed9-98bf-19bd01dd687b','題山橋十首  其八','王柏','宋','宋诗','song-poetry','','[]','吹盡塵襟亦快哉，心期千古一時開。',32,'全唐诗/poet.song.210000.json','["吹盡塵襟亦快哉，心期千古一時開。", "清風滿峽誰收拾，即此清風播後來。"]'),
