('c5bab491-c25a-420e-bf87-47bc0c27fc17','題立齋天台圖  其二','王柏','宋','宋诗','song-poetry','','[]','出處於人不偶然，當時已報赤城緣。',32,'全唐诗/poet.song.210000.json','["出處於人不偶然，當時已報赤城緣。", "丹青有筆誰能畫，聖則堂前月滿川。"]'),
('79e72e87-88c9-4966-b3db-d6a3c7e93619','元正  其一','王柏','宋','宋诗','song-poetry','','[]','開正又展一年期，霞臉醺醺酒半巵。',32,'全唐诗/poet.song.210000.json','["開正又展一年期，霞臉醺醺酒半巵。", "獨坐晴窗無一事，呼童和墨寫梅詩。"]'),
('9c438afa-d2ff-4639-8f1e-3ae638f02854','元正  其二','王柏','宋','宋诗','song-poetry','','[]','吟詩猶是少年情，要復當初赤子心。',32,'全唐诗/poet.song.210000.json','["吟詩猶是少年情，要復當初赤子心。", "心出入時何以御，手持一卷敬齋箴。"]'),
('29e09c87-4255-47a8-b795-95f8ec645b1b','和玉成書秋臺詩卷韻','王柏','宋','宋诗','song-poetry','','[]','龍蛇筆底盤枯藤，兩卷風騷泣鬼神。',32,'全唐诗/poet.song.210000.json','["龍蛇筆底盤枯藤，兩卷風騷泣鬼神。", "此是玉成衣鉢處，他年出語定驚人。"]'),
('72561afa-aedc-4ee1-ac93-06d9fd380a9b','韋軒遊山遇雨','王柏','宋','宋诗','song-poetry','','[]','踏碎羊山黄葉堆，天飛細雨相車回。',32,'全唐诗/poet.song.210000.json','["踏碎羊山黄葉堆，天飛細雨相車回。", "二皇應訝來何晚，不忍聽君話別杯。"]'),
('b2222b34-659c-4fe0-a6d9-742af61c1035','和前人韻  其一','王柏','宋','宋诗','song-poetry','','[]','名山終是欠徘徊，小隊輕車决意來。',32,'全唐诗/poet.song.210000.json','["名山終是欠徘徊，小隊輕車决意來。", "他日相思無覓處，殷勤先贈嶺頭梅。"]'),
('ff4505a5-0556-40a9-92d8-058d0ee781d4','和前人韻  其二','王柏','宋','宋诗','song-poetry','','[]','山靈豈是少恩哉，兩載從容自不來。',32,'全唐诗/poet.song.210000.json','["山靈豈是少恩哉，兩載從容自不來。", "羊石豈能留得住，和羹消息到寒梅。"]'),
('fe757a21-a4b2-45c6-a70f-9bf1e6511aaa','答子宣雪中惠吳中珍味','王柏','宋','宋诗','song-poetry','','[]','誰枉袁安雪裏車，忽然臺餽入吾廬。',32,'全唐诗/poet.song.210000.json','["誰枉袁安雪裏車，忽然臺餽入吾廬。", "平生安識吳中味，攪碎衰翁滿腹蔬。"]'),
('bd71da1c-035d-4f1c-b21b-e5906275ebc0','跋潘默成詩','王柏','宋','宋诗','song-poetry','','[]','不動心齋有素規，稜稜風骨太清奇。',32,'全唐诗/poet.song.210000.json','["不動心齋有素規，稜稜風骨太清奇。", "殘書斷帖人爭寶，誰識先生媿祿詩。"]'),
('9efc7a11-2cfc-4917-94d5-9ed91388e7e1','書補之梅','王柏','宋','宋诗','song-poetry','','[]','玉質敷腴宮樣妝，風流終媿水雲鄉。',32,'全唐诗/poet.song.210000.json','["玉質敷腴宮樣妝，風流終媿水雲鄉。", "一邨飛落人間世，添却逃禪百倍香。"]'),
('d64fdbc6-74ce-4fd1-9bc7-dfb446377b85','題王伯忠雪月圖','王柏','宋','宋诗','song-poetry','','[]','片紙裁成數寸慳，王孫風致寄毫端。',32,'全唐诗/poet.song.210000.json','["片紙裁成數寸慳，王孫風致寄毫端。", "只於天地交光裏，認得前程萬里寬。"]'),
('689f7ad4-b7b8-45f6-9662-e6a07c8963a1','除夜訪楊此齋  其一','王柏','宋','宋诗','song-poetry','','[]','除夕家家整世氛，老來天賜一閒身。',32,'全唐诗/poet.song.210000.json','["除夕家家整世氛，老來天賜一閒身。", "正當風雪翻空急，面拂冰花訪故人。"]'),
('e8959609-c183-4212-9d5e-35da88d8c7cf','除夜訪楊此齋  其二','王柏','宋','宋诗','song-poetry','','[]','一別癯仙已八年，伶俜鶴骨尚彈冠。',32,'全唐诗/poet.song.210000.json','["一別癯仙已八年，伶俜鶴骨尚彈冠。", "相逢逆旅歡然處，各著精神子細看。"]'),
('b7e7b40d-5ccf-4aed-8dc2-aba11200e2fe','秋興  其一','王柏','宋','宋诗','song-poetry','','[]','年少荒唐德頗慚，了無佳客伴清談。',32,'全唐诗/poet.song.210000.json','["年少荒唐德頗慚，了無佳客伴清談。", "相親幸有坡詩在，秋晚堂深燈一龕。"]'),
('24da6872-3875-4ca4-9dbc-760b25462689','秋興  其二','王柏','宋','宋诗','song-poetry','','[]','巷底蕭蕭絕市塵，供愁疎雨打黄昏。',32,'全唐诗/poet.song.210000.json','["巷底蕭蕭絕市塵，供愁疎雨打黄昏。", "悠然一曲泉鳴調，燒了夜香深閉門。"]'),
('254d0e98-3e21-4f05-9708-32f66bc01cc8','塗中即景','王柏','宋','宋诗','song-poetry','','[]','溪邊柳色露新芽，春透微波漠漠斜。',32,'全唐诗/poet.song.210000.json','["溪邊柳色露新芽，春透微波漠漠斜。", "一陣隨風香頗異，定知前面有梅花。"]'),
('63d717dd-c674-4923-9623-be6924941e48','宿寧庵聞溪聲','王柏','宋','宋诗','song-poetry','','[]','清溪瀉出瀑泉鳴，記得昌黎語不平。',32,'全唐诗/poet.song.210000.json','["清溪瀉出瀑泉鳴，記得昌黎語不平。", "要識中流多峙柱，故能千古振英聲。"]'),
('f8ebf223-629d-4502-8c81-715c732a6290','感舊三首  其一','王柏','宋','宋诗','song-poetry','','[]','年時清話幾黄昏，雙桂亭前竹外門。',32,'全唐诗/poet.song.210000.json','["年時清話幾黄昏，雙桂亭前竹外門。", "離合盛衰方感舊，忽逢新句動詩魂。"]'),
('675fb68f-6767-4995-b9be-0b75fdbce4b0','感舊三首  其二','王柏','宋','宋诗','song-poetry','','[]','交契綢繆事未磨，月窗再得共婆娑。',32,'全唐诗/poet.song.210000.json','["交契綢繆事未磨，月窗再得共婆娑。", "君今有子全無恨，顧我伶俜奈老何。"]'),
('359cbc99-22dc-4acf-9f27-57eeb5982361','感舊三首  其三','王柏','宋','宋诗','song-poetry','','[]','却爲清貧識世情，人於淡處味方珍。',32,'全唐诗/poet.song.210000.json','["却爲清貧識世情，人於淡處味方珍。", "未終舊話君還去，頼有梅花似故人。"]'),
('0f224385-c555-4b9d-8eb5-3c290bcc759b','湖上  其一','王柏','宋','宋诗','song-poetry','','[]','木落孤山分外孤，尖風索索響枯蘆。',32,'全唐诗/poet.song.210000.json','["木落孤山分外孤，尖風索索響枯蘆。", "暗香全未傳消息，和靖還曾著意無。"]'),
('5cec39ea-d480-4f3b-956e-7a865c134503','湖上  其二','王柏','宋','宋诗','song-poetry','','[]','笙歌只解閙花天，誰肯敲冰掉小船。',32,'全唐诗/poet.song.210000.json','["笙歌只解閙花天，誰肯敲冰掉小船。", "要識湖山真面目，偷他冷月訪三賢。"]'),
('a19e43a7-828f-41ed-86bd-6415988caeee','歸舟三絕  其一','王柏','宋','宋诗','song-poetry','','[]','江邊踏月入孤舟，水月流光一片浮。',32,'全唐诗/poet.song.210000.json','["江邊踏月入孤舟，水月流光一片浮。", "夜靜海門雷怒吼，潮頭凍殺未甘休。"]'),
('8cd3c7cd-ce9c-4c57-b34f-4ae8096c89a5','歸舟三絕  其二','王柏','宋','宋诗','song-poetry','','[]','波聲拍枕不成眠，擁被推篷月尚圓。',32,'全唐诗/poet.song.210000.json','["波聲拍枕不成眠，擁被推篷月尚圓。", "霜下夜深人正悄，數聲飛雁度林顛。"]'),
('9dcbd7c4-b860-4d5a-8ddb-0ae6dfad3a4b','歸舟三絕  其三','王柏','宋','宋诗','song-poetry','','[]','幸脫塵氛入帝城，又携幽恨滿歸程。',32,'全唐诗/poet.song.210000.json','["幸脫塵氛入帝城，又携幽恨滿歸程。", "鴈行不整關心事，深媿漢人千慮輕。"]'),
('1e3f942f-f337-43c7-94ba-3a954568e0f3','伯兄新樓十首  其一','王柏','宋','宋诗','song-poetry','','[]','歛牆縮地保鄰歡，巧作規模不見慳。',32,'全唐诗/poet.song.210000.json','["歛牆縮地保鄰歡，巧作規模不見慳。", "初轉層梯心似隘，一開窗了便寬閑。"]'),
('ca54ab86-3032-4c59-b41b-9d36ab7e4bf0','伯兄新樓十首  其二','王柏','宋','宋诗','song-poetry','','[]','不嫌陋巷據坡頭，旋斸煙萊著小樓。',32,'全唐诗/poet.song.210000.json','["不嫌陋巷據坡頭，旋斸煙萊著小樓。", "面面有山殊不惡，倚闌銷盡半生愁。"]'),
('aeb75c1c-fe91-4efa-a33d-a1b96f095b00','伯兄新樓十首  其三','王柏','宋','宋诗','song-poetry','','[]','東山護曉日葱曨，一簇樓臺紫翠中。',32,'全唐诗/poet.song.210000.json','["東山護曉日葱曨，一簇樓臺紫翠中。", "鴛瓦露漙鱗甲動，參差翬影掛斜紅。"]'),
('78ae8b19-806b-450b-ae53-b7e09c17746b','伯兄新樓十首  其四','王柏','宋','宋诗','song-poetry','','[]','野色晴暉展畫屏，綠槐古樾兩娉婷。',32,'全唐诗/poet.song.210000.json','["野色晴暉展畫屏，綠槐古樾兩娉婷。", "却嫌一带無情竹，只放金華半段青。"]'),
('71cc4729-7bbf-43b2-ab74-77cfb0799936','伯兄新樓十首  其五','王柏','宋','宋诗','song-poetry','','[]','投西眼力拓天寬，收得煙林透入關。',32,'全唐诗/poet.song.210000.json','["投西眼力拓天寬，收得煙林透入關。", "雙鶩斷霞飛不盡，九峰斜抹有無間。"]'),
('554e0286-a6ff-4e05-a8eb-ad6e858fe62b','伯兄新樓十首  其六','王柏','宋','宋诗','song-poetry','','[]','林間塔影鬰蒼蒼，向晚風傳供佛香。',32,'全唐诗/poet.song.210000.json','["林間塔影鬰蒼蒼，向晚風傳供佛香。", "燈焰萬龕時炯炯，恍然文筆吐光芒。"]'),
('be8e3a9d-72e5-4443-8ad4-f1b7a0ef7a38','伯兄新樓十首  其七','王柏','宋','宋诗','song-poetry','','[]','未說樓居即是仙，自然高處隔塵寰。',32,'全唐诗/poet.song.210000.json','["未說樓居即是仙，自然高處隔塵寰。", "誰家雙鶴鳴清曉，聲在東邊竹樹間。"]'),
('3941e8f8-2fad-4b88-a2d8-9eb3753e4652','伯兄新樓十首  其八','王柏','宋','宋诗','song-poetry','','[]','月滿闌干風滿衿，浪因景物動清吟。',32,'全唐诗/poet.song.210000.json','["月滿闌干風滿衿，浪因景物動清吟。", "鐘驚老鶴翻金剎，角引棲鴉投暮林。"]'),
('15aaf71e-708d-4b9c-a96b-ed2e2e500425','伯兄新樓十首  其九','王柏','宋','宋诗','song-poetry','','[]','樓頭小圃徑斜通，種竹休教勢倚空。',32,'全唐诗/poet.song.210000.json','["樓頭小圃徑斜通，種竹休教勢倚空。", "好是故廬猶在眼，未應脩篠障西風。"]'),
('6903ae6b-4e86-48c0-855f-f3f5ef6effbc','伯兄新樓十首  其一○','王柏','宋','宋诗','song-poetry','','[]','七絃之外數聯詩，裊裊爐煙酒半巵。',32,'全唐诗/poet.song.210000.json','["七絃之外數聯詩，裊裊爐煙酒半巵。", "豈獨對牀堪聽雨，不如話到月斜時。"]'),
('f37d9845-2fdd-4924-93c1-e1f393ae5771','謝葉聖予送笋','王柏','宋','宋诗','song-poetry','','[]','誰念篔簹一飯貧，蟄龍頭角正森森。',32,'全唐诗/poet.song.210000.json','["誰念篔簹一飯貧，蟄龍頭角正森森。", "殷勤惠我清貞節，減却君家幾畝陰。"]'),
('cd79d818-5cbf-4f6e-b3ed-597abbe04353','寄題江山葉氏翠香亭  其一','王柏','宋','宋诗','song-poetry','','[]','此君來與小山盟，共挹周揚一世英。',32,'全唐诗/poet.song.210000.json','["此君來與小山盟，共挹周揚一世英。", "何用偷它當日意，男兒自要立芳名。"]'),
('0079a644-d5ea-4b81-b3f1-3213329cfb82','寄題江山葉氏翠香亭  其二','王柏','宋','宋诗','song-poetry','','[]','遥想琅玕百頃强，旋栽應笑子猷忙。',32,'全唐诗/poet.song.210000.json','["遥想琅玕百頃强，旋栽應笑子猷忙。", "絕憐羽葆摇新綠，更有風來細細香。"]'),
('57741391-79b8-4eac-a368-0849cbe88ba5','寄題江山葉氏翠香亭  其三','王柏','宋','宋诗','song-poetry','','[]','誰竊清香下廣寒，霜風染就粟膚丹。',32,'全唐诗/poet.song.210000.json','["誰竊清香下廣寒，霜風染就粟膚丹。", "須知葉葉蒼圭色，花未開時自可觀。"]'),
('9a0ce6aa-6fcf-4346-8017-ca6ae19b9832','寄題江山葉氏翠香亭  其四','王柏','宋','宋诗','song-poetry','','[]','小詩越境論交情，不見新亭句未精。',32,'全唐诗/poet.song.210000.json','["小詩越境論交情，不見新亭句未精。", "寄語主人猶缺典，梅花應恨不同清。"]'),
('ba35db54-4a30-4d28-bcd3-e7a69bbabd13','白荷花','王柏','宋','宋诗','song-poetry','','[]','玉娥獨自到書屏，不管人間暑氣深。',32,'全唐诗/poet.song.210000.json','["玉娥獨自到書屏，不管人間暑氣深。", "待得詩成花已謝，應無好句愜花心。"]'),
('b8ad3252-d54f-4565-841c-21b6c6ffa76d','三衢紀所聞','王柏','宋','宋诗','song-poetry','','[]','青幙紅裾忠懿孫，如今流落不堪聽。',32,'全唐诗/poet.song.210000.json','["青幙紅裾忠懿孫，如今流落不堪聽。", "丹書鐵券山河誓，却與春閨贖濫刑。"]'),
('4afa4aeb-0d2e-4a90-a2ae-40ad40ce25af','過趙清獻故居','王柏','宋','宋诗','song-poetry','','[]','隠隠數間清獻宅，只在城東竹樹中。',32,'全唐诗/poet.song.210000.json','["隠隠數間清獻宅，只在城東竹樹中。", "龜鶴不知何處去，誰將白鹿繼高風。"]'),
('78e7e923-c771-4e6d-965a-d83ca756305a','題思泉庵','王柏','宋','宋诗','song-poetry','','[]','一時人物久飛仙，詩竹和庵盡變遷。',32,'全唐诗/poet.song.210000.json','["一時人物久飛仙，詩竹和庵盡變遷。", "尚有禪師風味在，野人門外汲寒泉。"]'),
('e3fa1570-1854-45ba-af68-b13d3bb38393','赤松夜宿','王柏','宋','宋诗','song-poetry','','[]','香火悠長仙力重，山川布濩妙難控。',32,'全唐诗/poet.song.210000.json','["香火悠長仙力重，山川布濩妙難控。", "詩魂飛繞翠屏中，冷雨疎風時入夢。"]'),
('5b044719-2a03-4c12-b72c-b950cb22fb2c','中秋','王柏','宋','宋诗','song-poetry','','[]','中秋天氣似重陽，幸有庭前桂子香。',32,'全唐诗/poet.song.210000.json','["中秋天氣似重陽，幸有庭前桂子香。", "書冊根邊無一事，任他風雨送淒涼。"]'),
('7ec4f6cb-e3f5-4720-808f-717e4301a613','寄題胡子升讀易亭韻','王柏','宋','宋诗','song-poetry','','[]','梅花亭外倚霜晴，讀易亭中一老成。',32,'全唐诗/poet.song.210000.json','["梅花亭外倚霜晴，讀易亭中一老成。", "亭在道旁還有意，幾多行客想風聲。"]'),
('bcca5aa7-00eb-4df7-9cfc-d87a76aa4d02','葉西廬惠冬菊三絕  其一','王柏','宋','宋诗','song-poetry','','[]','風緊東籬長舊荄，主人杖屨日徘徊。',32,'全唐诗/poet.song.210000.json','["風緊東籬長舊荄，主人杖屨日徘徊。", "後時獨立應無恨，少待梅花相伴開。"]'),
('83e0ccaa-955a-4b44-9d5d-c73c0148eb49','葉西廬惠冬菊三絕  其二','王柏','宋','宋诗','song-poetry','','[]','霜天無物不彫殘，忽見青蕤羽葆攢。',32,'全唐诗/poet.song.210000.json','["霜天無物不彫殘，忽見青蕤羽葆攢。", "欲制頹齡須耐冷，一陽定有落英餐。"]'),
('b461d01c-9cbf-4c87-a0f9-5c7c93a0d304','葉西廬惠冬菊三絕  其三','王柏','宋','宋诗','song-poetry','','[]','誰知造化用工深，處士陶潛獨返魂。',32,'全唐诗/poet.song.210000.json','["誰知造化用工深，處士陶潛獨返魂。", "白髮書生留晚節，從今歲歲典刑存。"]'),
('dee53e3d-40a0-44d5-b4ff-8eac747eab00','和乘雪遊山韻  其一','王柏','宋','宋诗','song-poetry','','[]','千丈層崖玉作堆，瑶林璀璨路縈回。',32,'全唐诗/poet.song.210000.json','["千丈層崖玉作堆，瑶林璀璨路縈回。", "寒光徹骨清無敵，第一軒中第一杯。"]'),
('6e7fab5e-20f3-4ee8-8b98-1d79fb947725','和乘雪遊山韻  其二','王柏','宋','宋诗','song-poetry','','[]','肅然窮巷凍堆堆，高卧袁生夢正回。',32,'全唐诗/poet.song.210000.json','["肅然窮巷凍堆堆，高卧袁生夢正回。", "擁鼻微吟燒榾柮，茅柴也薦兩三杯。"]'),
('e2d3cad3-bb41-49bd-a446-8921ff459092','三閭大夫贊','王柏','宋','宋诗','song-poetry','','[]','愛國憂民感慨深，沅湘浩浩魄沈沈。',32,'全唐诗/poet.song.210000.json','["愛國憂民感慨深，沅湘浩浩魄沈沈。", "懷沙哀郢成何事，日月爭光只此心。"]'),
('743df558-8344-4551-97aa-86fec74ed474','挽曹叔獻','王柏','宋','宋诗','song-poetry','','[]','野草何青青，野花亦莙莙。',144,'全唐诗/poet.song.210000.json','["野草何青青，野花亦莙莙。", "王園翳烟樹，東風開泉扃。", "靈辰倏祥練，祖載何因循。", "半生安陋巷，簞瓢澹無營。", "天命有窮達，書生多苦辛。", "北邙同一路，玄廬等枯榮。", "我本里中子，升堂託微婣。", "每懷桮渡語，惟士有常心。", "几杖雖疏闊，睠睠敬愛深。", "故家喬木瘁，不復典刑存。", "流水桃花窅，飄零薤露音。", "幽宮一以閟，清淚灑芳春。"]'),
('1d64f749-5c78-490d-8e0a-b647c3a829aa','挽汪帥參  其一','王柏','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','一世欽齋老，聲名四十年。',48,'全唐诗/poet.song.210000.json','["一世欽齋老，聲名四十年。", "冰融南省日，春滿洞庭天。", "笑語當時密，交情晚節堅。", "秀英今已矣，新閣獨巋然。"]'),
('edea3968-3cfe-42ad-a006-7228eee87fe4','挽汪帥參  其二','王柏','宋','宋诗','song-poetry','','[]','世路艱危極，人情政可歎。',48,'全唐诗/poet.song.210000.json','["世路艱危極，人情政可歎。", "未聞親子在，而有外邪干。", "軒冕多爲累，簞瓢未必寒。", "此皆身外事，且閟一丘安。"]'),
('eff96593-9f9b-4147-a759-bdb2f0c75ae2','挽潜齋王樞相  其一','王柏','宋','宋诗','song-poetry','','[]','忠簡流餘慶，文忠印此心。',48,'全唐诗/poet.song.210000.json','["忠簡流餘慶，文忠印此心。", "詞章傳世早，事業得君深。", "不盡風雲會，寧知歲月侵。", "九重驚殄瘁，讒者舌方瘖。"]'),
('b45fede6-af76-49f6-b0c7-428411c3f123','挽潜齋王樞相  其二','王柏','宋','宋诗','song-poetry','','[]','治命深衣歛，親題石像鎸。',48,'全唐诗/poet.song.210000.json','["治命深衣歛，親題石像鎸。", "精神傳巨扁，風月掩遺編。", "流落人間境，陶鎔物外天。", "建安名教在，它日配先賢。"]'),
('d36b48da-ab8c-4bab-9902-b0512c026145','挽潜齋王樞相  其三','王柏','宋','宋诗','song-poetry','','[]','總角思先友，同宗麗澤傳。',48,'全唐诗/poet.song.210000.json','["總角思先友，同宗麗澤傳。", "典刑諸老盡，文獻舊家全。", "交道從公晚，知音去我先。", "淵源誰與遡，愁絕伯牙絃。"]'),
('c7c7ee31-4c4f-4747-9223-bd3a522d28d4','挽潜齋王樞相  其四','王柏','宋','宋诗','song-poetry','','[]','精舍北之北，幽宮南復南。',48,'全唐诗/poet.song.210000.json','["精舍北之北，幽宮南復南。", "兩山生死寄，千古姓名諳。", "地勢蟠空壯，溪聲戰晚酣。", "青烏發天祕，萬壑拱遺龕。"]'),
('f17b98cb-d42c-481a-b4a9-c4efeb03b0ff','代挽王潜齋  其一','王柏','宋','宋诗','song-poetry','','[]','自立西山雪，聲名四十年。',48,'全唐诗/poet.song.210000.json','["自立西山雪，聲名四十年。", "清思奎畫重，忠簡物情憐。", "廊廟風雲斷，園林歲月遷。", "潜齋元不死，有子續遺編。"]'),
('f9916ace-83f9-4a46-838b-fda140854246','代挽王潜齋  其二','王柏','宋','宋诗','song-poetry','','[]','先世論交早，名公不忍忘。',48,'全唐诗/poet.song.210000.json','["先世論交早，名公不忍忘。", "共期霖雨施，忽掩斗樞光。", "北墅風煙慘，南山草木香。", "片雲開白日，卹典耀龍㡛。"]'),
('1f2c2c95-0497-4ab2-b1b7-5fd5b9098e2d','挽丁知縣','王柏','宋','宋诗','song-poetry','','[]','蚤識北平貴，從遊五十年。',48,'全唐诗/poet.song.210000.json','["蚤識北平貴，從遊五十年。", "遲遲登虎榜，急急到鳬仙。", "振起非無地，榮枯自有天。", "老成彫落盡，一壑鎖蒼烟。"]'),
('35b2abce-922f-4bf2-9636-b9d1afa1f7bb','挽施子華','王柏','宋','宋诗','song-poetry','','[]','哭子天倫變，賢哉更可傷。',48,'全唐诗/poet.song.210000.json','["哭子天倫變，賢哉更可傷。", "毅翁悲祚斷，學者悼師良。", "缺月窺元室，凄風鎖奧岡。", "身雖隨物幻，名筆起潜光。"]'),
('211a2e2a-9b3f-47ed-9ead-b404f07a0dc1','挽郡博士待班劉公歌','王柏','宋','宋诗','song-poetry','','[]','東風變九野，萬物負生意。',192,'全唐诗/poet.song.210000.json','["東風變九野，萬物負生意。", "素韠何欒欒，清血洒幽隧。", "猗歟靜壽翁，歸全可無愧。", "人生託溟涬，消息同一氣。", "過化來者續，自昔歎川逝。", "溫溫夙好修，甄陶瑚璉器。", "凝乎觚自度，澹乎靚且邃。", "詩書以爲糧，忠信以爲饎。", "人皆崇榮途，公獨徐攬轡。", "三轉坐臯比，五鶚爭自致。", "上培德誼種，下開文字瑞。", "一子通金閨，一子需大對。", "衣冠繪慶圖，豈料造物忌。", "學校失師模，鄉閭思善類。", "梅花已流水，草木誰臭味。", "惟有篤厚心，叮嚀期嗣世。"]'),
('0946bc6c-9e7a-4405-9f9d-60d4f3c5af01','桐花散翁挽詩','王柏','宋','宋诗','song-poetry','','[]','瀫水之西，巍然一峰。',240,'全唐诗/poet.song.210000.json','["瀫水之西，巍然一峰。", "是曰道堅，翔舞而東。", "林巒蓊蔚，丘壑渾融。", "雍雍聚落，惟金之宗。", "五世積累，鍾此散翁。", "散翁頎頎，生有異質。", "學敏而博，心廣而實。", "迺孝迺睦，迺大其識。", "教子一經，維寬而栗。", "教人盡己，維久無斁。", "選舉法壞，取士以文。", "决於一夫，升沈遂分。", "良才美德，所甘隠淪。", "負我求我，負人非人。", "兩語垂訓，風俗反淳。", "我之識翁，因翁二子。", "典刑是親，翼翼亹亹。", "曾不幾見，翁遽不起。", "我來哭翁，亦已晚矣。", "匍匐之義，真可愧死。", "我既哭翁，亦相佳城。", "千嶂矗矗，萬壑沄沄。", "一丘永閟，昭明上征。", "萬壑沄沄，千嶂矗矗。"]'),
('ae6f0acc-425b-4d8e-9100-7da008943226','哭錢學老','王柏','宋','宋诗','song-poetry','','[]','魯國黔婁死，升堂弔者誰。',48,'全唐诗/poet.song.210000.json','["魯國黔婁死，升堂弔者誰。", "不邪能至此，千載有妻知。", "凜凜默成德，清風百世師。", "舅甥貧到底，終老外家祠。"]'),
('6fcb241a-6036-47dc-98d2-247fe4bfc725','挽汪約叟  其一','王柏','宋','宋诗','song-poetry','','[]','幸有靈光在，天乎作麽亡。',48,'全唐诗/poet.song.210000.json','["幸有靈光在，天乎作麽亡。", "生來最真實，病裏亦康强。", "和氣留丹鼎，清塵凝筆床。", "溪山呈秀處，風露悄凄凉。"]'),
('00c7829f-2597-4937-9258-b72c1506321a','挽汪約叟  其二','王柏','宋','宋诗','song-poetry','','[]','憶昔先君子，金蘭氣味投。',48,'全唐诗/poet.song.210000.json','["憶昔先君子，金蘭氣味投。", "中間有生死，一別幾春秋。", "曉漏傳幽夢，英魂覓舊游。", "城東烟月冷，應是訪新丘。"]'),
('2ed1b984-30df-4779-b46e-ac452fd554b1','挽鄧夫人','王柏','宋','宋诗','song-poetry','','[]','霜冷留賓髮，心融篆貝經。',48,'全唐诗/poet.song.210000.json','["霜冷留賓髮，心融篆貝經。", "疏金重錦誥，琢玉璨芝庭。", "方祿參軍養，俄丹壽母銘。", "可憐萱草露，也解泣儀形。"]'),
('e1327c88-55f2-45c1-891f-e59605bfb4d3','挽司直兄  其一','王柏','宋','宋诗','song-poetry','','[]','老厭鴛行武，騎鯨不肯留。',48,'全唐诗/poet.song.210000.json','["老厭鴛行武，騎鯨不肯留。", "空存丹棘讞，未告紫宸猷。", "黄老辜初志，青山颺晚謀。", "夕陽無限好，心事竟悠悠。"]'),
('49fcd16a-8800-4c8f-8fac-72b16f8ecbe1','挽司直兄  其二','王柏','宋','宋诗','song-poetry','','[]','典重班諸老，聲名始璧流。',48,'全唐诗/poet.song.210000.json','["典重班諸老，聲名始璧流。", "開尊口佳士，襥被闖前脩。", "月冷金閨籍，塵生玉杖鳩。", "梅巖傷目處，鴈影正賓秋。"]'),
('a6e7cfa7-0430-4209-9ab0-a6d98b17a0ff','挽司直兄  其三','王柏','宋','宋诗','song-poetry','','[]','晚始親荆玉，劬愉氣誼稠。',48,'全唐诗/poet.song.210000.json','["晚始親荆玉，劬愉氣誼稠。", "泰壇霜月下，暑枕夜江頭。", "一困關公念，連書釋我憂。", "平生知己淚，寂寞灑新楸。"]'),
('289d0ef9-bf82-4061-920d-5e8b1e8c1c7f','挽朱侍郎  其一','王柏','宋','宋诗','song-poetry','','[]','國論多同異，身名有險夷。',48,'全唐诗/poet.song.210000.json','["國論多同異，身名有險夷。", "一從離紫橐，再不上丹墀。", "慷慨風雲斷，飄零歲月移。", "却因閒得早，冷眼看人癡。"]'),
('2b0313e5-c84c-4c88-b16f-cb897cdce57a','挽朱侍郎  其二','王柏','宋','宋诗','song-poetry','','[]','渺渺康湖水，峨峨蜀野山。',48,'全唐诗/poet.song.210000.json','["渺渺康湖水，峨峨蜀野山。", "是翁元不死，蛻骨此中間。", "草木券臺綠，莓苔翁仲斑。", "白雲傷北望，清淚更潸潸。"]'),
('abba583c-376e-4236-a7ee-bb310c2328a0','宗夫人挽章','王柏','宋','宋诗','song-poetry','','[]','勳烈高忠簡，夫人衍慶源。',48,'全唐诗/poet.song.210000.json','["勳烈高忠簡，夫人衍慶源。", "春風南澗藻，秋雨北堂萱。", "鸞鑑傷孤影，芝庭茂兩孫。", "清霜凝素仗，璀璨滿西原。"]'),
('9050ee15-a920-4976-8a43-e1a01e8695f9','挽何無適','王柏','宋','宋诗','song-poetry','','[]','二五之英，清通瑩徹。',200,'全唐诗/poet.song.210000.json','["二五之英，清通瑩徹。", "有鍾于躬，非賢則哲。", "烏乎無適，自幼卓絕。", "奴僕選騷，銓衡莊列。", "鞭霆走電，不可追籋。", "一操而存，肅整轡轍。", "著書未就，不幸短折。", "既賦以奇，未易泯滅。", "世外精神，筆頭風月。", "有閲斯立，有妥斯魄。", "既妥爾魄，既築爾阡。", "是曰反終，是曰歸全。", "人生斯世，豈必百年。", "欲動情勝，萬事出焉。", "孰好孰惡，孰媸孰妍。", "孰過而改，孰善而遷。", "一征物表，浩浩其天。", "風定水止，月印萬川。", "陰陽不獨，動靜不偏。", "既靜復動，太極烱然。"]'),
('242495cb-54b4-42af-95e8-e94bc54f1bdc','馬華父母葉氏挽章','王柏','宋','宋诗','song-poetry','','[]','力疾呼兒語，民方弄潢池。',144,'全唐诗/poet.song.210000.json','["力疾呼兒語，民方弄潢池。", "兒職不可緩，母疾尚可爲。", "綉衣纔出境，蕭斧旋芟夷。", "百姓得奠枕，歸來拜慈帷。", "母訓不敢墜，母喜開雙眉。", "陰功覃雨露，慶報當期頤。", "孟夏草木長，庭萱何遽萎。", "平生事儉約，猶有嬪時衣。", "熏爐經卷靜，不復朝莫披。", "西風秋又晚，萸菊思年時。", "瞿瞿臨祖奠，清血應漣洏。", "明朝鶴巖道，舊冢連新悲。"]'),
('fdce8a99-464e-404b-ba6b-7914f740bf69','挽頤軒張朝奉  其一','王柏','宋','宋诗','song-poetry','','[]','藹然一氣備天和，不盡人間歲月多。',64,'全唐诗/poet.song.210000.json','["藹然一氣備天和，不盡人間歲月多。", "鄉里同聲稱佛子，兒孫相繼奮儒科。", "蠲租捐廩今無有，刲豕然燈可奈何。", "德在人心真不朽，幾多麟碣汙山河。"]'),
('74a629ff-ba28-4f67-a8bb-d35c4d3e7a84','挽頤軒張朝奉  其二','王柏','宋','宋诗','song-poetry','','[]','挺挺長松施女蘿，平生能得幾相過。',64,'全唐诗/poet.song.210000.json','["挺挺長松施女蘿，平生能得幾相過。", "繐帷遠辱雙絇臨，淚眼猶瞻兩鬢皤。", "曾未經年成契闊，至今一慟竟蹉跎。", "吉人已矣難重見，山口悽悽薤露歌。"]'),
('cae4efc2-bbf5-49c2-b1b1-3f79a16f3de8','挽張佛子  其一','王柏','宋','宋诗','song-poetry','','[]','嘉慶圖傳世所稀，夫何佛子遽西歸。',64,'全唐诗/poet.song.210000.json','["嘉慶圖傳世所稀，夫何佛子遽西歸。", "平生施予心無爲，時事艱難衆有依。", "德誼百年猶積累，詩書五世漸光輝。", "兒童父老傾山谷，洒淚追隨丹旐飛。"]'),
('f4d111b1-6f7e-4e40-be04-14c21aa6cbf2','挽張佛子  其二','王柏','宋','宋诗','song-poetry','','[]','陟屺雖頻莫慰心，見公猶幸母如存。',64,'全唐诗/poet.song.210000.json','["陟屺雖頻莫慰心，見公猶幸母如存。", "東山何事遽陳迹，西路如今又斷魂。", "柳翣忽臨新冢道，林花空滿舊時園。", "一衿和氣歸何處，化作功名遺子孫。"]'),
('92aa5ff3-872c-4cc2-a14d-39ed1679f8b8','挽徐郎中','王柏','宋','宋诗','song-poetry','','[]','郎潜不復坦衿期，留得清名舉世知。',64,'全唐诗/poet.song.210000.json','["郎潜不復坦衿期，留得清名舉世知。", "老矣空還新虎節，歸來只是舊鴻禧。", "危言寧免班行忌，已死猶聞海內推。", "病裏僅能成大厦，當時燕雀不勝悲。"]'),
('a6227b13-2d5a-4698-8887-d0ba1619b6b9','挽趙龍泉','王柏','宋','宋诗','song-poetry','','[]','滿擬田廬樂莫年，誰知鳬舄遽飛仙。',64,'全唐诗/poet.song.210000.json','["滿擬田廬樂莫年，誰知鳬舄遽飛仙。", "鶚書連走文場捷，麟趾多推正脈賢。", "晚錫藍衫更鶡弁，徑分蒲璧鎮龍泉。", "春風滿縣開桃李，回首松楸鎖翠烟。"]'),
('781dbdf0-dafb-48a5-a4ae-718e31afbdf9','挽思泉居士  其一','王柏','宋','宋诗','song-poetry','','[]','平生不蓄買山錢，晚得佳城豈偶然。',64,'全唐诗/poet.song.210000.json','["平生不蓄買山錢，晚得佳城豈偶然。", "官職叢中韜素志，風波險處謁名賢。", "只將和氣占心地，尚想清尊養性天。", "宗黨典刑難倒指，忍看庭玉淚濺濺。"]'),
('69ce59b7-60eb-40ff-9864-79393ba11de5','挽思泉居士  其二','王柏','宋','宋诗','song-poetry','','[]','猶記年時訪故山，細聆舊話侍清閒。',64,'全唐诗/poet.song.210000.json','["猶記年時訪故山，細聆舊話侍清閒。", "汲泉倚杖臨荒甃，尋塔呼僮斸野菅。", "回首恍如前日事，傷心已隔夜泉關。", "手携菖歜歌清些，淚染含風細葛班。"]'),
('0c1e67b0-ef62-461d-a4b6-bed5751b48dc','挽朱侍郎','王柏','宋','宋诗','song-poetry','','[]','蚤亞魁躔入諫坡，却因忠讜蹈風波。',64,'全唐诗/poet.song.210000.json','["蚤亞魁躔入諫坡，却因忠讜蹈風波。", "龍墀一去江湖遠，鶴骨歸來歲月多。", "紫橐將隨時事轉，丹旌無奈夜舟何。", "萬松蒼翠皆親種，月露凄凄泣隴阿。"]'),
('98f2148b-e8cb-4f31-a81f-ceb13550a3af','挽朱宜人','王柏','宋','宋诗','song-poetry','','[]','蜀峰飛來不記年，嶪峨崒嵂青綿聯。',144,'全唐诗/poet.song.210000.json','["蜀峰飛來不記年，嶪峨崒嵂青綿聯。", "康湖演漾吞萬壑，風雷日夜噴飛泉。", "水西葱鬰氣方壯，水南重得黄牛眠。", "深山大澤絕異處，造物冥錮難輕捐。", "龍翔鳳舞萃英淑，豈非天授夫人賢。", "綵雲落月相珪璧，山花庭草摇香鈿。", "虎羊甲士儼成列，萬松磨颭生蒼烟。", "夫君筆力扛九鼎，親著幽德熏蘭荃。", "應有山靈乘赤豹，千年呵護青瑶鎸。"]'),
('2aec0c74-8307-4856-a597-cc94ad942f00','挽何南坡  其一','王柏','宋','宋诗','song-poetry','','[]','刻苦工夫真實心，一言體用已全陳。',64,'全唐诗/poet.song.210000.json','["刻苦工夫真實心，一言體用已全陳。", "聖賢斷續三千載，伯仲漸摩八十春。", "保護斯文勤且讓，作成吾黨敬而親。", "我來不復瞻耆德，流水蒼烟迹已塵。"]'),
('c5c0c476-b639-46d1-9b3b-30674dc672d9','挽何南坡  其二','王柏','宋','宋诗','song-poetry','','[]','少公稟氣後三年，易簀翻居三日先。',64,'全唐诗/poet.song.210000.json','["少公稟氣後三年，易簀翻居三日先。", "學數弟兄猶間有，壽隨父母獨誰全。", "悲哉易感精神往，造化難憑禍福遷。", "應恨南山人遠去，從今獨卧北山阡。"]'),
('d93ecd51-309f-4a86-a8fa-7a8185b532cd','挽何南坡  其三','王柏','宋','宋诗','song-poetry','','[]','籬落縱橫一逕分，平生杖屨幾登臨。',64,'全唐诗/poet.song.210000.json','["籬落縱橫一逕分，平生杖屨幾登臨。", "某山某水機緘露，彼室彼廬精分深。", "檢校舊規心欲折，摩挲新誌淚難禁。", "素車白馬人歸後，鶴唳猿啼總些音。"]'),
('bca5a092-b748-493f-9c57-a86196a0773e','林省吾挽辭','王柏','宋','宋诗','song-poetry','','[]','羌若人兮大带而深衣，張拱徐趨兮儼乎其若思。',157,'全唐诗/poet.song.210000.json','["羌若人兮大带而深衣，張拱徐趨兮儼乎其若思。", "動有則兮神定，澹無欲兮心夷。", "便儇嶔巇之紛吾前兮，醢雞起滅。", "忠信傳習之省吾躬兮，聖賢我師。", "伊春陽之冉冉兮，生意方懋。", "何雪霜之不仁兮，荃蘭遽萎。", "搴三后之純英兮，時不得而榮瘁。", "抱太極而永歸兮，哀與我之其誰。", "雲沈沈兮凄巘，風稜稜兮斷澌。", "長田長田兮，寂寂永夜。", "暢旨獨立兮，千古名垂。"]'),
('6b11fabb-27ed-4ec5-b944-14fd8eec35b4','滕勿齋內楊氏挽詞  其一','王柏','宋','宋诗','song-poetry','','[]','東風捲地兮摧千紅，松柏青葱兮啟幽宮。',54,'全唐诗/poet.song.210000.json','["東風捲地兮摧千紅，松柏青葱兮啟幽宮。", "龍㡛廣柳兮辭簾櫳，埋香掩玉兮甘長終。", "芳草萋萋兮春又空，東君寂寞兮誰與同。"]'),
('8c1cd87b-4c02-4602-b846-878e5b644d9c','滕勿齋內楊氏挽詞  其二','王柏','宋','宋诗','song-poetry','','[]','吳門山少兮烟水寬，一鍤千金兮尚云慳。',54,'全唐诗/poet.song.210000.json','["吳門山少兮烟水寬，一鍤千金兮尚云慳。", "夫人勤儉兮同艱難，子荆苟美兮營玄關。", "平生首丘兮志應寒，雙溪渺渺兮何時還。"]'),
('6b829438-792b-44d4-940c-0d6500814385','滕勿齋內楊氏挽詞  其三','王柏','宋','宋诗','song-poetry','','[]','憶昔登堂兮拜淑儀，小子丱角兮勤將携。',54,'全唐诗/poet.song.210000.json','["憶昔登堂兮拜淑儀，小子丱角兮勤將携。", "夫君念我兮力不遺，歲月滔邁兮鬢成絲。", "西望紫翣兮清魂飛，椷哀千里兮空漣洏。"]'),
('8d043e3a-fee2-4d38-b15d-02e9a3d3b017','陳卿內邵氏挽詞','王柏','宋','宋诗','song-poetry','','[]','羣山峨峨兮屏下環，鍾爲人英兮司賢關。',158,'全唐诗/poet.song.210000.json','["羣山峨峨兮屏下環，鍾爲人英兮司賢關。", "風雅解頤兮簪佩珊珊，有女穎悟兮拱聽帷間。", "識性情之正兮婦德閑，雞鳴警戒兮夜漫漫。", "冰清玉潤兮卿月相傳，夫君騎鯨兮今幾年。", "綱紀繩繩兮閨門肅然，樂山堂兮花木正妍。", "蕙槁蘭萎兮棄釵鈿，淒淒東塢兮藏風烟。", "畫翣流雲兮去翩翩，飛絮寂寞兮隨珠軿。", "忍看雙璧兮沈黄泉，龜趺螭首兮何時鎸。", "山靈呵護兮祚綿綿。"]'),
('bac4676f-73ff-4c67-afb1-ab88378afc4b','鄭寺正挽辭  其一','王柏','宋','宋诗','song-poetry','','[]','北山崚嶒兮配井絡之勳名，子孫繩繩兮聿彰厥聲。',59,'全唐诗/poet.song.210000.json','["北山崚嶒兮配井絡之勳名，子孫繩繩兮聿彰厥聲。", "一麾不顧兮番禺君，甘領祠官兮挂長纓。", "操存益固兮涵養益深，臨行一念兮尤清明。"]'),
('20730547-fd07-4ff2-b773-aced0011204e','鄭寺正挽辭  其二','王柏','宋','宋诗','song-poetry','','[]','坦溪渺渺兮配流慶之深長，園林带宅兮風月無疆。',59,'全唐诗/poet.song.210000.json','["坦溪渺渺兮配流慶之深長，園林带宅兮風月無疆。", "鷗鷺受盟兮舉清觴，胡不百年兮長徜徉。", "澡身更服兮愙氣安詳，遺頌灑然兮墨耿光。"]'),
('83a2cac5-72f1-4658-938c-8fc83d54f148','鄭寺正挽辭  其三','王柏','宋','宋诗','song-poetry','','[]','北山寂寞兮號東風，坦溪嗚咽兮繞玄宮。',56,'全唐诗/poet.song.210000.json','["北山寂寞兮號東風，坦溪嗚咽兮繞玄宮。", "曉露滴滴兮泣蒼松，芳草萋萋兮券臺窿窿。", "體魄永藏兮魂徂太空，一聲蒿里兮春無容。"]'),
('ff92d6c6-23bc-4203-aa40-11b2bc60053f','馬華父母葉氏挽詞  其一','王柏','宋','宋诗','song-poetry','','[]','苕溪猩鬼兮呼嘯幽篁，綉衣一出兮血膏斧鋩。',100,'全唐诗/poet.song.210000.json','["苕溪猩鬼兮呼嘯幽篁，綉衣一出兮血膏斧鋩。", "笳鼓歸來兮拜舞北堂，潢池夷靖兮母訓是將。", "慈顔開喜兮家國之祥，薰風自南兮草木正長。", "胡不百年兮俾壽而康，庭萱夜殞兮奩玉晝藏。", "使者菲屨兮桐杖皇皇，一道生靈兮悲如我傷。"]'),
('5386498b-f01f-4bd7-8812-70a98884bc29','馬華父母葉氏挽詞  其二','王柏','宋','宋诗','song-poetry','','[]','瑶巖嵯峨兮龍翔鳳飛，玄廬肅啟兮松楸露晞。',99,'全唐诗/poet.song.210000.json','["瑶巖嵯峨兮龍翔鳳飛，玄廬肅啟兮松楸露晞。", "東望宰隴兮券臺依依，靈辰不留兮夷牀曉移。", "紫萸黄菊兮奠祖一巵，熏爐經卷兮儼如生時。", "靈幄香銷兮猶有嬪衣，音容寂寂兮萬古永歸。", "龍㡛黼翣兮驂神魌，一聲萬里兮風號谷悲。"]'),
('9407ebd4-81b7-4f9d-91cf-201ef480f6e2','李三朝奉哀詞','王柏','宋','宋诗','song-poetry','','[]','羌與公別兮幾二十年，思渺渺兮路曼曼。',317,'全唐诗/poet.song.210000.json','["羌與公別兮幾二十年，思渺渺兮路曼曼。", "棹剡溪兮乘興，訪故迹兮愴然。", "下晉齊之拜兮如夢，挑燈道舊兮猶平生歡。", "我少公兮六歲，悼彼此兮華顛。", "解予佩兮授予館，言未終兮歲已闌。", "會公疾兮孔熾，怛醫窮兮技殫。", "聞易簀兮數語，意穆穆兮詞嚴。", "湛神爽兮不變，驗學力兮深堅。", "自磐川與玉局兮，交一世之名賢。", "宜公之好脩兮，羞芳蕙而糗荃蘭。", "退靜處而莫我知兮，老冉冉其流連。", "厭塵世之轇轕兮，倏昭明而遂仙。", "幸與公兮永訣，撫往事兮自憐。", "言告言歸兮邁邁，有懷渭水兮淵淵。", "棲遲故隠兮，全純愚而孤處。", "當歲莫之急景兮，聞公窀穸之有端。", "皎皎兮懿行，卓卓兮瑶鎸。", "函泳以適意兮，鳳岡樵隠之遺稿。", "纂記以廣業兮，春秋族系之巨編。", "豈待是而不朽，掩既往之孤搴。", "蘭風之臯兮望不極，歌薤露兮有淚懸泉。"]'),
('3efda50b-05d4-4440-93b7-3a098b8df407','蔣叔行挽辭  其一','王柏','宋','宋诗','song-poetry','','[]','萬山蟠兮有宅一區，吁嗟吉士兮心古而色愉。',118,'全唐诗/poet.song.210000.json','["萬山蟠兮有宅一區，吁嗟吉士兮心古而色愉。", "平生激烈兮談忠義之事，求師教子兮必有道之儒。", "流德誼兮鼎鼎，浸策足兮功名之途。", "引壺觴兮自適，玩日月之雙車。", "有淑兮爾配，絲枲兮劬劬。", "指期頤兮二豎立病，既偕老兮亦相繼而長徂。", "望雙旌兮有慟，酹一束兮生芻。"]'),
('9e9c8bc9-93a2-4b5b-b6c2-c5f75c0916ff','蔣叔行挽辭  其二','王柏','宋','宋诗','song-poetry','','[]','萬山蟠兮新此一丘，吁嗟乎，吉士兮靈辰不留。',111,'全唐诗/poet.song.210000.json','["萬山蟠兮新此一丘，吁嗟乎，吉士兮靈辰不留。", "佳城鬰鬰兮馬跼不進，前岡隠隠兮牛眠是求。", "竁蜿蜒兮有隧，枕臯隰兮沃流。", "東望兮廬舍，西望兮松楸。", "白雲兮生死同壑，黄壚兮杖屨昔游。", "孤哀哀兮罔極，悼愁愁兮千秋。", "悵素紼兮莫執，相爾些兮商謠。"]'),
('1eb77a10-ff80-46f3-a554-e460c6db4187','朱昭父挽些','王柏','宋','宋诗','song-poetry','','[]','春風初開兮別君南浦，誄君輁軸兮冬又暮。',171,'全唐诗/poet.song.210000.json','["春風初開兮別君南浦，誄君輁軸兮冬又暮。", "曾歲律之未改兮生死異路，吁嗟乎實齋兮有前脩之風度。", "瑟瑟僩僩兮凝然寒素，不忮不求兮未嘗偭繩墨而改錯。", "視萬馬之奔逸兮歛組轡而獨駐，安於一實兮豈斯世之足語。", "天何賦之厚兮而奪之遽，何旅翣之未返兮合豺虎而哮呼。", "凜世道之腭兮良士瞿瞿，想君一笑於冥冥兮豁然大悟。", "山靡靡兮旁圍，水潺潺兮在下。", "付萬事兮雲空，顓一壑兮千古。"]'),
('2b71700a-9fc6-4779-a00b-9770fc275cee','悼蔡修齋','王柏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','羌世運之緯繣兮，何故老之不憗遺。',345,'全唐诗/poet.song.210000.json','["羌世運之緯繣兮，何故老之不憗遺。", "持寸膠而救千丈渾兮，誰與同而共治。", "身一約而蹈遺烈兮，不沽直而不徇時。", "西極八桂東連吳會兮，貫南紀以周馳。", "以節用愛人兮，以靜重爲威。", "謂直方大之德才學識之長兮，親結上知。", "方增重乎本朝兮，而疾疢以乘之。", "猶癯癯乎筆削之志兮，浩浩乎汗青之未期。", "遺稿山積兮，孰續而孰維。", "擅一代之鉅典兮，疑造物之好虧。", "吁嗟乎，修齋之典刑兮，蹇長歌乎已而。", "余幼好此奇服兮，今冉冉而華顛。", "悼窘步之數奇兮，安陋巷之瓢簞。", "公獨閔其寂落兮，擥微芳而遐搴。", "時舒愛而申情兮，曾不間夫郵傳。", "弭婺節而西來兮，拱茂行之淵淵。", "吸松齋之沆瀣兮，飽坐嘯之蘭荃。", "鳳高飛而莫縶兮，徒延佇而路曼曼。", "何音問之不淑兮，駭騎箕而遂仙。", "睇長江而太息兮，涕淫淫而惘然。", "撫巨編之遺則兮，神馳乎洋奧之佳阡。", "念歲律之云莫兮，奈狂風之鼓天。"]'),
('dc72cf32-4c93-4af3-83f5-abdda718bf72','挽時僉判  其一','王柏','宋','宋诗','song-poetry','','[]','靈辰不留兮，挽者何悲。',77,'全唐诗/poet.song.210000.json','["靈辰不留兮，挽者何悲。", "羌茂行之皎皎兮，而今已而。", "惟孝友百行之首兮，何習俗之日醨。", "惟不虧其降衷兮，何足尚乎浮辭。", "靈辰不留兮，斯人永歸。", "薤露一聲兮，行人淚垂。"]'),
('45e524d2-643d-44f7-b4b7-9c1a3e66637e','挽時僉判  其二','王柏','宋','宋诗','song-poetry','','[]','靈辰不留兮，挽者徘徊。',78,'全唐诗/poet.song.210000.json','["靈辰不留兮，挽者徘徊。", "羌若人之秉德兮，佩先訓之不回。", "以直道事人兮，任當路之疑猜。", "坎壈一官兮，窮達何有於我哉。", "靈辰不留兮，啟社塘之夜臺。", "薤露再歌兮，亦孔之哀。"]'),
('7b4a3ae3-d524-4711-98f9-11c1aa9c5e4e','挽時僉判  其三','王柏','宋','宋诗','song-poetry','','[]','靈辰不留兮，挽者邁邁。',90,'全唐诗/poet.song.210000.json','["靈辰不留兮，挽者邁邁。", "羌前脩之典刑兮，何後生之昧昧。", "平鄉常人之號兮，豈直欲以之而自悔。", "靜觀世道之日詭兮，蓋亦惡夫奇奇而怪怪。", "靈辰不留兮，路曼曼乎長夜。", "歌薤露之三章兮，識者爲之永嘅。"]'),
('212da166-f139-4b44-882c-23169a96de2c','徐制參挽歌  其一','王柏','宋','宋诗','song-poetry','','[]','北風高兮歲律將殘，望東隴兮目斷旌丹。',107,'全唐诗/poet.song.210000.json','["北風高兮歲律將殘，望東隴兮目斷旌丹。", "有美君子兮擥衆芳而自飾，直哉惟清兮不亢不激。", "鬰十五年之朝望兮，僅彯纓於列院。", "參幙府以自詭兮，乃劬劬而忘倦。", "宜表世而厲俗兮，曷止於斯。", "靈辰不留兮，祖奠載期。", "薤歌之一章兮，孰不孔悲。"]'),
('bac691ca-a127-4a26-9bb1-636a4ee2f8d1','徐制參挽歌  其二','王柏','宋','宋诗','song-poetry','','[]','歲律殘兮北風正南，渡梅花之橋兮龍㡛鑣鑣。',117,'全唐诗/poet.song.210000.json','["歲律殘兮北風正南，渡梅花之橋兮龍㡛鑣鑣。", "有美君子兮蒼梧翠竹，善繼善述兮恢韋齋之芳躅。", "羌世道之緯繣兮，孰識夫異體而同氣。", "惟不忘其所由生兮，合羣從而一視。", "慨垂絕之叮嚀兮，欲蛻而理融。", "靈人不留兮，將永閟于幽宮。", "再歌薤靈之章兮，號萬壑之長松。"]'),
('09e2dbc1-fc82-46ab-9818-2092a41a70d2','徐制參挽歌  其三','王柏','宋','宋诗','song-poetry','','[]','北風北風兮歲律告終，豈惟歲律兮嗟世道之益窮。',110,'全唐诗/poet.song.210000.json','["北風北風兮歲律告終，豈惟歲律兮嗟世道之益窮。", "有美君子兮，非斯世之人物。", "有古人之風兮，有無我之德。", "我亦何知兮，託先世之餘契。", "兩書相勞苦兮，藹然敬愛之意。", "迹雖疏兮此心不忘，死生契闊兮悵十二里之高岡。", "歌薤露之卒章兮，有淚滂滂。"]'),
('4ccf2afe-9883-4f0e-a21f-c1a80ee931e2','挽邵公容春  其一','王柏','宋','宋诗','song-poetry','','[]','北風獵獵兮申原之幽，玄扉啟兮靈辰不留。',51,'全唐诗/poet.song.210000.json','["北風獵獵兮申原之幽，玄扉啟兮靈辰不留。", "蘇黄之像兮儼其如在，容春之人兮杳不可求。", "一棺兮厚德，萬古兮高丘。"]'),
('97afb956-b53f-4649-97f6-ae977ed221d5','挽邵公容春  其二','王柏','宋','宋诗','song-poetry','','[]','申原幽幽兮北風正高，薤露一聲兮山鬼夜號。',48,'全唐诗/poet.song.210000.json','["申原幽幽兮北風正高，薤露一聲兮山鬼夜號。", "吉人考終兮如蛻，遺編不朽兮風騷。", "一丘兮安固，萬古兮滔滔。"]'),
('7f6c7277-ee34-4408-a3c2-173229fcdd1f','挽邵公容春  其三','王柏','宋','宋诗','song-poetry','','[]','北風北風兮丹旐飛飛，申原邁邁兮鐸聲孔悲。',53,'全唐诗/poet.song.210000.json','["北風北風兮丹旐飛飛，申原邁邁兮鐸聲孔悲。", "素韁欒欒兮二子皇皇，如有望兮魂其來歸。", "地有靈兮人傑，表爾隧兮豐碑。"]'),
('7c2a38f1-9dcd-401a-a119-f0af01a66f34','宋史館檢閲所性先生時天彝父挽些','王柏','宋','宋诗','song-poetry','','[]','大專槃物兮剛柔盪摩，五行雜糅兮顓蒙孔多。',199,'全唐诗/poet.song.210000.json','["大專槃物兮剛柔盪摩，五行雜糅兮顓蒙孔多。", "陶一氣之奇佹兮奄宇宙之幾何，握異采之陸離兮蹇儃佪而逶迤。", "襲正軌之茂則兮恥踐迹而循科，御長轅而獵太空兮摧九折之峨峨。", "孑不羣而介立兮衆囂囂而肆呵，玄虬蹶泥兮浸雄虹於頹波。", "隴廉孟娵之莫辨兮世揜揜其層睋，神藐藐而上征兮訴緯繣於太和。", "忽脩靈之聿皇兮任侏儒之傞傞，咎將誰執兮豈天賦之未薖。", "落日下大墅兮慨高風之吟哦，羌若人之莫見兮感生意於庭柯。", "卓豐詞兮九里，亙千秋兮不磨。"]'),
('f2d92af5-7356-4f07-8479-7ed4a4b65d53','挽蔡文叔  其一','王柏','宋','宋诗','song-poetry','','[]','南風之薰兮五弦絕，可以解慍兮憂心益惙。',193,'全唐诗/poet.song.210000.json','["南風之薰兮五弦絕，可以解慍兮憂心益惙。", "念寓形於溟涬兮，藐一漚之起滅。", "前乎數千年之名世兮，後方來而未歇。", "往者不我留兮，來者不我接。", "何彼頑之弗夭兮，而獨萎乎此哲。", "非夫人之立極兮，凜世路之迫阨。", "惟聖斯惻兮，建學校以壽吾道之脈。", "士不可辱兮又焉可殺，孰悟我聖明兮幾襲秦之亂轍。", "我公之忠憤貫日兮，所以疾驅而朅朅。", "一去國兮一陰方猾，再去國兮重陰栗烈。", "鄙夫熟視兮，壯羣邪之蟠結。", "目斷留田兮，歌南風之闋。"]'),
('97e7ab27-c1ec-48cc-ab3f-f83e56887881','挽蔡文叔  其二','王柏','宋','宋诗','song-poetry','','[]','南風之時兮吹彼棘薪，喬木斯壞兮棟梁曷任。',195,'全唐诗/poet.song.210000.json','["南風之時兮吹彼棘薪，喬木斯壞兮棟梁曷任。", "櫨櫨椳闑與扂楔兮，匠瞇瞇而弗尋。", "况承天之八柱兮，窮歲月而莫登。", "天豈不生材兮，鬰牛山之嶙峋。", "雨露之所潤兮，存日夜之肫肫。", "及大厦之將顛兮，無一木之可乘。", "羌小民之怨咨兮，謂天不仁。", "非道通乎三極兮，孰識天心。", "天既仁愛我民兮篤生偉人，一去就兮治亂攸分。", "天亦仁愛我公兮，不使見犬羊之駭奔，危機發兮衆寐昏昏。", "秉離明以爲燭兮，魂營營而上征。", "目斷留田兮，歌南風之再吟。"]'),
('ce61967c-ae7a-4120-90bf-1e73b13dbd28','挽蔡文叔  其三','王柏','宋','宋诗','song-poetry','','[]','南風南風兮，莫甦槁質。',212,'全唐诗/poet.song.210000.json','["南風南風兮，莫甦槁質。", "坎離互宅兮，已翩翩乎月窟。", "駕朱鳥以啟路兮，潛玄宮而永息。", "終長夜之漫漫兮，委人間之正則。", "道所以經世兮，名不可以虛得。", "方一去而即悟兮，可以淑艾乎士習。", "倘再去而能悟兮，庶姦諛之屏迹。", "使長孺居中司馬遂相兮，狂酋當爲之怵惕。", "又何至於闖江踰嶺兮，喋血上國。", "思魏徵而奠九齡兮，吁其何及。", "公雖九原兮，疑遺忠之尚盡。", "我被公之知兮，始終如一。", "不得哭公于堂兮，不得執公之紼。", "我何負於神明兮，兩足如縶。", "歌南風之三疊兮，恨無極。"]'),
('82e1ed4e-6bd5-4f2a-9d57-245e706e60df','哀倪孟容父詞','王柏','宋','宋诗','song-poetry','','[]','憶昔見公兮，季原之堂。',190,'全唐诗/poet.song.210000.json','["憶昔見公兮，季原之堂。", "兄弟怡怡兮，清約是將。", "藹子姓之弦歌兮，頭角昂昂。", "來者起敬兮，知德義之日昌。", "造化無情兮，慨有季之先亡。", "氣象少異兮，燈火淒涼。", "幸二子之自奮兮，視前有光。", "何祿養之不久兮，遽驚風木之傷。", "痛日月之未改兮，已變故常。", "以公之剛介兮，豈北面於緇黄。", "我知公之心兮，縈不足以挽其恨之長。", "東風作惡兮雪絮正狂，黄壚曉啟兮松楸蒼蒼。", "勞生兮永佚，世事兮茫茫。", "交之道兮日落，老有淚兮滂滂。"]'),
('b30663ad-7285-4649-9220-e514bbf6706a','盛化州挽些','王柏','宋','宋诗','song-poetry','','[]','悼世習之緯繣兮，爭騖乎險阨。',314,'全唐诗/poet.song.210000.json','["悼世習之緯繣兮，爭騖乎險阨。", "藴異采而儃佪兮，已喧豗而吠怪。", "孰視衣冠之故宇兮，腥羶菅蒯。", "酣一盎之醯蚋兮，較得失乎晻曖。", "公胡爲乎高搴兮，提一劍以北指。", "恐脩名之不立兮，氣軒軒而有偉。", "捫虱以談當世之務兮，江東莫比。", "燼世讎於蔡焰兮，同雪國恥。", "驅馳乎蠶叢魚鳬兮，上功萬里。", "中原咫尺兮，莫歸寸疆。", "素志剝落兮，怊惝恍而淒涼。", "霾輪縶馬兮，猛思故鄉。", "晚得一障兮，遥遥乎南荒。", "時繽紛而易變兮，又何可以久留。", "謫星墮境內兮，吾將奚求。", "魂營營而上征兮，叩太儀之幽幽。", "歛智囊而不售兮，遺恨千秋。", "夙聞公名兮，意卓犖而不羈。", "解后公之揮麈兮，心朗氣夷。", "嘗叩公之所歷兮，動中事機。", "將款密乎山扉兮，杳璜佩而莫追。", "悲風起兮江村，白日下兮大墅。", "表獨立兮雄碑，間一丘兮今古。"]'),
('4d794621-5f2b-4336-84df-8f853b8ff0f6','挽通守陳帑院','王柏','宋','宋诗','song-poetry','','[]','羌西屴之屹然兮，鍾此奇才。',184,'全唐诗/poet.song.210000.json','["羌西屴之屹然兮，鍾此奇才。", "方世道之緯繣兮，棄騏驥而駕駑駘。", "以一尉而誅二凶兮，宜異言之喧豗。", "炯此念而安民兮，皇恤乎身災。", "公論雖屢蝕兮，猶有時而復開。", "開之何未久兮，而終不能遂公之壯懷。", "詩書兮自適，優游兮力齋。", "扶疾而告修善之訓兮，俄怛焉而順隤。", "彼西屴之無情兮，忍璜佩之沈薶。", "生於是死於是兮，湛一氣之去來。", "惟心無媿而氣不餒之言兮，萬古莫得而塵埃。", "況有不朽之銘兮，表獨立於崔嵬。"]'),
('346806cb-d1f3-4e20-afa1-3199861d48b9','挽施子華','王柏','宋','宋诗','song-poetry','','[]','二五交運兮，雜糅乎剛柔。',144,'全唐诗/poet.song.210000.json','["二五交運兮，雜糅乎剛柔。", "美惡厚薄兮，何稟生之不侔。", "厚者未必薰兮，薄者未必蕕。", "羌寓形於溟涬兮，藐起滅之一漚。", "惟父母之哭子兮，蹇彼蒼之大尤。", "吾嘗抱此至痛兮，知毅翁之恨難收。", "雖我不識子兮，知謹實而好修。", "撫新碑而感慨兮，相鐸聲之口謳。", "奧山兮泉瀏，淒巘兮雲幽。", "夫子有命矣夫之嘆兮，可以釋而翁之憂憂。"]'),
('a6dad99b-bbc2-4272-8392-b0a3734cdc94','挽王夫人  其一','王柏','宋','宋诗','song-poetry','','[]','秋山蕭蕭兮，連山之岡。',88,'全唐诗/poet.song.210000.json','["秋山蕭蕭兮，連山之岡。", "有幽一宮兮，千古其藏。", "毓野堂之世則兮，綿瓜瓞以承芳。", "來宗牖而自度兮，如奉姑嫜。", "相君子之婉婉兮，發軔康莊。", "囿一世之天兮，遽瘞佩而沈璜。", "秋風蕭蕭兮，連山之岡。"]'),
('63f3d3e0-099c-4154-8c26-1137f783c3b6','挽王夫人  其二','王柏','宋','宋诗','song-poetry','','[]','連山之岡兮，秋風蕭蕭。',84,'全唐诗/poet.song.210000.json','["連山之岡兮，秋風蕭蕭。", "有永千古兮，幽宮迢迢。", "一編之女訓兮，慨遺音之寂寥。", "藹清芬其如在兮，鞶帨彯彯。", "忍雙親之望望兮，遲女歸而魂消。", "靈辰不留，誰其擬招。", "連山之岡，秋風蕭蕭。"]'),
('d7183193-5ad7-4bc5-83ef-1125465688fe','懷古呈通守鄭定齋  其一','王柏','宋','宋诗','song-poetry','','[]','東方有猗桐，菀彼雲之岑。',60,'全唐诗/poet.song.210000.json','["東方有猗桐，菀彼雲之岑。", "良工一斤斧，斲爲膝上琴。", "朱絃輕拂抹，盎然太古音。", "不彈箕子操，不調離騷聲。", "安得夔典樂，天下終和平。"]'),
('b48d5134-5070-4715-a8cb-7fc52b0f8bac','懷古呈通守鄭定齋  其二','王柏','宋','宋诗','song-poetry','','[]','南方有良藥，神妙難具寫。',60,'全唐诗/poet.song.210000.json','["南方有良藥，神妙難具寫。", "沉疴一刀圭，無不立愈者。", "性烈必瞑眩，色惡如土苴。", "倉公一見之，寶愛不忍捨。", "欲起國膏肓，先當醫苟且。"]'),
('6f882136-309e-4f24-ae1d-681796abc269','懷古呈通守鄭定齋  其三','王柏','宋','宋诗','song-poetry','','[]','西方有精鐵，淬以百鍊堅。',60,'全唐诗/poet.song.210000.json','["西方有精鐵，淬以百鍊堅。", "範爲三尺劍，烱烱雙花寒。", "勿以埋厚地，勿以投深淵。", "未染蛟龍腥，未睨姦雄元。", "丈夫纔把握，且以破拘攣。"]'),
('f02316c5-7a5c-4f71-9166-464b397d73a2','懷古呈通守鄭定齋  其四','王柏','宋','宋诗','song-poetry','','[]','北方有大井，深潛幾萬尋。',60,'全唐诗/poet.song.210000.json','["北方有大井，深潛幾萬尋。", "煎爲東阿膠，瑩徹如球琳。", "持此一寸微，可救千丈渾。", "世道一以濁，貪風方襄陵。", "誰能汲此水，凈滌四海心。"]'),
('8ccc40be-60c0-4a02-81b3-35312b7f8896','西倅廳冰雪樓次韻','王柏','宋','宋诗','song-poetry','','[]','我生山水窟，一靜了萬境。',204,'全唐诗/poet.song.210000.json','["我生山水窟，一靜了萬境。", "登臨始識奇，已與凡目並。", "大哉飛躍間，一物具一性。", "冰雪有妙理，言言苦難聽。", "開藏古制存，以抑揚氣騁。", "稜稜六花嚴，中有生意瑩。", "非貞曷爲元，妙幹舒慘正。", "燮調不可偏，相資不相病。", "陽和一以泄，品彙反不競。", "新政冰雪清，洗濯炎蒸凈。", "陰痼一陽微，震裂萬蟄儆。", "酬酢極變態，不失本來靜。", "一樓駕高明，俯仰動微省。", "深恐神鑒昏，萬事如捕影。", "繰藉嚴冷名，賡歌歲寒詠。", "即此友求心，已見無不敬。", "行到百尺頭，脚力須用勁。"]'),
('e8b6a3a3-f458-4d25-b8ae-7011f0bdf617','迷道有感次韻','王柏','宋','宋诗','song-poetry','','[]','未識大安道，行行多路岐。',48,'全唐诗/poet.song.210000.json','["未識大安道，行行多路岐。", "人言訛近遠，山路倍嶔巇。", "自有康莊處，多因便捷移。", "我今知堠子，萬里不須疑。"]'),
('11746579-f129-4224-9b8c-41585d610719','新竹次韻','王柏','宋','宋诗','song-poetry','','[]','瞻彼依依竹，來依夫子牆。',48,'全唐诗/poet.song.210000.json','["瞻彼依依竹，來依夫子牆。", "密含千畝勢，清閟一窗凉。", "直指生來瘦，貞標靜裏香。", "緬懷儀鳳意，不記歲年長。"]'),
('f5b77939-33d1-43ee-a919-8a2a36d7c761','張子房','王柏','宋','宋诗','song-poetry','','[]','圯上相逢一老翁，誅秦蹙項笑談中。',32,'全唐诗/poet.song.210000.json','["圯上相逢一老翁，誅秦蹙項笑談中。", "報韓偶得劉郎用，更有商山聽下風。"]'),
('b5ff5cc6-5975-4405-88c8-3fb1c6bbb0ad','題諸葛武侯畫像','王柏','宋','宋诗','song-poetry','','[]','隆中高卧匪無情，鼎峙規模豈素心。',32,'全唐诗/poet.song.210000.json','["隆中高卧匪無情，鼎峙規模豈素心。", "自是將軍三顧晚，坐看世變轉移深。"]'),
('70470bd0-bd37-4cc6-aea7-d4c9e3f23e82','羊叔子畫像','王柏','宋','宋诗','song-poetry','','[]','天下三分事未終，已施德惠過江東。',32,'全唐诗/poet.song.210000.json','["天下三分事未終，已施德惠過江東。", "誰知叔子深長計，但道中興是茂弘。"]'),
('7b068b06-f3af-4091-9ea0-3d4a8d5ec4ad','陶淵明','王柏','宋','宋诗','song-poetry','','[]','義熙鼎向寄奴輕，歸去來兮絕宦情。',32,'全唐诗/poet.song.210000.json','["義熙鼎向寄奴輕，歸去來兮絕宦情。", "特筆誰書晉處士，千年心事一朝明。"]'),
('353c4b1b-01e5-491f-85df-ed2424d0c69a','元夕獨坐','王柏','宋','宋诗','song-poetry','','[]','頗聞燈火閙熒熒，何似書窗一點青。',32,'全唐诗/poet.song.210000.json','["頗聞燈火閙熒熒，何似書窗一點青。", "尚喜今年民意樂，一般簫鼓兩般聽。"]'),
('4ce58bf4-edc6-4d12-990b-322a0370f6b2','贈尋賢趙相士','王柏','宋','宋诗','song-poetry','','[]','赤脚佯聾術有神，賢才未必要賢尋。',32,'全唐诗/poet.song.210000.json','["赤脚佯聾術有神，賢才未必要賢尋。", "尋賢牌子非賢物，自是君王坐右箴。"]'),
('3e1c14f9-db38-4ea1-a5a2-ff91d808afa2','蘭亭記','王柏','宋','宋诗','song-poetry','','[]','風流盛集數蘭亭，刻石紛紛豈有真。',32,'全唐诗/poet.song.210000.json','["風流盛集數蘭亭，刻石紛紛豈有真。", "嗟老感時何足慕，千年誰記浴沂人。"]'),
('38b4db79-b564-41c8-a709-dbf4441e7d77','題書目','王柏','宋','宋诗','song-poetry','','[]','博而寡要豈通儒，三萬牙籤亦太虛。',32,'全唐诗/poet.song.210000.json','["博而寡要豈通儒，三萬牙籤亦太虛。", "一編論語用不盡，世間何必許多書。"]'),
('134d4bd9-801f-4f96-9800-7d4b696bd70c','題愚齋梅軸','王柏','宋','宋诗','song-poetry','','[]','悄然筆下有心期，寫出寒梢玉立時。',32,'全唐诗/poet.song.210000.json','["悄然筆下有心期，寫出寒梢玉立時。", "何事巧藏烟雨裏，孤標深不願人知。"]'),
('e385fbf0-f7da-4df9-a3f7-c2b0f80edfdb','端平乙未新元','王柏','宋','宋诗','song-poetry','','[]','臺曆更新德未新，讀書未濟腹中貧。',64,'全唐诗/poet.song.210000.json','["臺曆更新德未新，讀書未濟腹中貧。", "屢因快意行來錯，却向閒中認得真。", "性性不忘千聖旨，惺惺毋欠滿腔仁。", "榮枯冷暖自消長，但見流行總是春。"]'),
('2cf885c5-9b5b-4cf8-baf8-67f74ec46a96','時充之訪盤溪有詩次韻','王柏','宋','宋诗','song-poetry','','[]','聖賢不出此心公，有爲爲之未必充。',64,'全唐诗/poet.song.210000.json','["聖賢不出此心公，有爲爲之未必充。", "絕學當歸三洞左，正源欲障百川東。", "坐春立雪誰能繼，弄月吟風豈浪從。", "方己烏頭力應鮮，因循又過一年終。"]'),
('aaaa1559-6358-4239-bb90-33b514c1b66c','何無適同宿山中次韻','王柏','宋','宋诗','song-poetry','','[]','虎踞龍蟠釋子宮，藥香時出小橋東。',64,'全唐诗/poet.song.210000.json','["虎踞龍蟠釋子宮，藥香時出小橋東。", "人眠依約三更後，月在清明一氣中。", "千古心期應共遠，半生懷抱此時融。", "清泉白日分明記，出處他年未必同。"]'),
('56f36b0c-b77a-42a9-a5ff-ba48f6a972ba','科舉','王柏','宋','宋诗','song-poetry','','[]','紛紛衿佩止時文，競巧趨新做日程。',64,'全唐诗/poet.song.210000.json','["紛紛衿佩止時文，競巧趨新做日程。", "一試奔馳天下士，三年冷暖世間情。", "清朝不許人心壞，舉子安知天爵榮。", "所用是人行是學，不知何日可升平。"]'),
('f33ee8b8-f190-415c-bfb0-6c0537536312','有人說用','王柏','宋','宋诗','song-poetry','','[]','寄語紛紛利欲人，不知何者是經綸。',64,'全唐诗/poet.song.210000.json','["寄語紛紛利欲人，不知何者是經綸。", "行藏未可便輕議，學問先須辨得真。", "莫把空言來誤世，要明明德去新民。", "大凡體立方言用，且著工夫檢自身。"]'),
('cccbcf72-874e-4ec7-beed-67fdc2535299','和伯兄適莊訪立齋','王柏','宋','宋诗','song-poetry','','[]','園林襟带兩三家，翁季怡怡意度嘉。',64,'全唐诗/poet.song.210000.json','["園林襟带兩三家，翁季怡怡意度嘉。", "時把酒杯傾月影，或燒石鼎煮天花。", "青編有味毋吾隠，白髮無情任汝加。", "翠竹數竿新映石，歲寒只此是生涯。"]'),
('53c9e3c0-dd30-4a76-a146-bd6c2d8143cf','送趙素軒去婺守爲本道倉使','王柏','宋','宋诗','song-poetry','','[]','人物乾淳舊典型，滿腔全是遠菴仁。',64,'全唐诗/poet.song.210000.json','["人物乾淳舊典型，滿腔全是遠菴仁。", "來時懶作三刀夢，去日留爲一道春。", "千里桑麻深雨露，雙溪風月更精神。", "出門父老歡迎處，猶有文公舊郡民。"]'),
('7e16091f-7a44-46ac-94e6-832a99229a9b','烏傷行','王柏','宋','宋诗','song-poetry','','[]','惟皇降衷于下民，暴秦莫殄心之仁。',160,'全唐诗/poet.song.210000.json','["惟皇降衷于下民，暴秦莫殄心之仁。", "孝哉顔氏一有感，畢逋銜土成丘塋。", "彼亦莫知其所以，自甘血觜含餘辛。", "志壹動氣氣動志，鳳儀麟出理亦均。", "環百里地畫疆井，千有餘載蒙嘉名。", "繡衣使者迂六轡，下馬肅拜心凌兢。", "大書瑰辭鎮松柏，便有山鬼呵崖陰。", "明刑弼教期無刑，何如先使教化明。", "流傳墨本到此屋，有人心者俱作興。", "但願人人常此心，安得作亂干章程。"]'),
('11304882-3375-45ce-984f-5425036afbb4','和詠飛春蔬  其一','王柏','宋','宋诗','song-poetry','','[]','東軒清節樂春蔬，傳到孫支百載餘。',32,'全唐诗/poet.song.210000.json','["東軒清節樂春蔬，傳到孫支百載餘。", "一朝拂袖竟歸去，應嗤介甫未忘魚。"]'),
('120e6149-de64-49df-bcd4-4f47bdc1b2bb','和詠飛春蔬  其二','王柏','宋','宋诗','song-poetry','','[]','社日何曾夢蹴蔬，遯翁波及實君餘。',32,'全唐诗/poet.song.210000.json','["社日何曾夢蹴蔬，遯翁波及實君餘。", "菜根牢咬真吾事，明義從知合舍魚。"]'),
('36aae259-df06-484d-8b74-fda33223ccf8','早梅有感','王柏','宋','宋诗','song-poetry','','[]','新陽來復未十日，窗外梅花已狼籍。',128,'全唐诗/poet.song.210000.json','["新陽來復未十日，窗外梅花已狼籍。", "晴光烘過冰雪融，微風不動暗香密。", "急呼清樽相尉藉，無數落英墜巾帙。", "兒童但喜花開早，太早翻令我心慄。", "今年寒色苦未老，戶穴不固泄萬蟄。", "造化不翕何以張，不然生道幾於息。", "明言歲事未足言，深憂南氣日馳北。", "誰道東君庾嶺來，煮酒銀瓶薦嘉實。"]'),
('de4a2b6e-4b43-4f27-9b2a-1e8527f9394a','古梅行','王柏','宋','宋诗','song-poetry','','[]','蒼龍蟄大澤，浩莫知歲華。',268,'全唐诗/poet.song.210000.json','["蒼龍蟄大澤，浩莫知歲華。", "不肯作霖雨，偃蹇眠烟霞。", "玉皇欲强起，六丁下谽谺。", "紫蛇掣金電，霹靂轉香車。", "振鬣欲騰奮，夭矯勢攫拏。", "神通學蟬蛻，僵作老樹丫。", "大枝露鱗爪，雨蝕成眢汙。", "小枝半朽折，苔蘚封楂牙。", "生意未甘寂，時著三五花。", "花少香氣壯，積雪應難遮。", "牧豎惡皴皵，梓匠嗔虬斜。", "日月自今古，獨免斤斧加。", "可謂遁世巧，全真傲幽遐。", "豈知好事者，僻性尋枯髽。", "叢薄一見面，倚杖生驚嗟。", "携鉏劚明月，移入蓮宇誇。", "詩翁爭著句，詩價方喧譁。", "老我有深意，默默不汝嘉。", "戒汝更藏拙，慎勿抽新芽。", "寒崖枯木上，何用開冰葩。", "古樵當厭汝，乞與山人家。", "我即乘之上河漢，千載不數張騫槎。"]'),
('e0390c95-96f2-493e-a606-44a79d577b94','重聘古梅行','王柏','宋','宋诗','song-poetry','','[]','千金卜得繇非熊，木德將興獵太公。',192,'全唐诗/poet.song.210000.json','["千金卜得繇非熊，木德將興獵太公。", "槐安與國已陳迹，盛衰直與陰陽通。", "知羹自昔親受記，飲冰齧雪工磨礲。", "此中洞洞無所有，徹上徹下俱玲瓏。", "苔膚蛻骨半榮悴，連峯峭厲飛銅騣。", "生意雖偏未嘗斷，猶有王氣居南東。", "南柯突出已奇甚，連蜷夭矯翔虬龍。", "東邊新梢更絕特，轉要作勢將騰空。", "風號竹塢月黯淡，露灑松壑泉琤琮。", "一花玉立蒼鬣表，萬花辟易難爲容。", "轍環四海無處覓，只今歲晚纔相逢。", "酹酒高歌盟萬古，天意决不寒孤風。"]'),
('4c746634-2389-4ce9-87de-654444b1edba','題墨梅  其一','王柏','宋','宋诗','song-poetry','','[]','歲寒無與偶，獨抱幽貞長。',24,'全唐诗/poet.song.210000.json','["歲寒無與偶，獨抱幽貞長。", "筆下孤梢瘦，冰花紙上香。"]'),
('0e163e6f-79e2-4694-8569-41c3916f4562','題墨梅  其二','王柏','宋','宋诗','song-poetry','','[]','筆頭開造化，花外越精神。',24,'全唐诗/poet.song.210000.json','["筆頭開造化，花外越精神。", "偃蹇蟉龍表，新梢最可人。"]'),
('c4c4392f-d445-45de-a55b-fadabe72bf97','題墨梅  其三','王柏','宋','宋诗','song-poetry','','[]','冰蕤開雪穎，墨妙發孤香。',24,'全唐诗/poet.song.210000.json','["冰蕤開雪穎，墨妙發孤香。", "不襲逃禪印，枝頭有異光。"]'),
('d3f03b2b-4ee8-46f0-8657-b907938bf360','題墨梅  其四','王柏','宋','宋诗','song-poetry','','[]','窮冬天地閉，萬物正彫殘。',24,'全唐诗/poet.song.210000.json','["窮冬天地閉，萬物正彫殘。", "玉立清梢表，天然獨耐寒。"]'),
('98653386-9bb8-499c-8690-c13afc084d6a','題墨梅  其五','王柏','宋','宋诗','song-poetry','','[]','胸中含靜操，筆下走寒梢。',24,'全唐诗/poet.song.210000.json','["胸中含靜操，筆下走寒梢。", "一見孤山客，清香盡拆苞。"]'),
('474ee212-4290-4b90-90dc-11286c1e1fa9','題墨梅  其六','王柏','宋','宋诗','song-poetry','','[]','素質天然靜，清芬繞鼻根。',24,'全唐诗/poet.song.210000.json','["素質天然靜，清芬繞鼻根。", "更於翹楚上，一筆起冰魂。"]'),
('1ed289c0-9b35-44b7-9089-cc39029ba673','題墨梅  其七','王柏','宋','宋诗','song-poetry','','[]','一枝橫出曉，霜外數花開。',24,'全唐诗/poet.song.210000.json','["一枝橫出曉，霜外數花開。", "誰識生綃上，清香靜處來。"]'),
('2891681f-4091-4f79-b13b-a72f93aca042','和諸庵花光十梅頌  其一','王柏','宋','宋诗','song-poetry','','[]','一筆劃斷寒崖，疎蘂數枝低亞。',28,'全唐诗/poet.song.210000.json','["一筆劃斷寒崖，疎蘂數枝低亞。", "不待雪壓霜摧，已自全體放下。"]'),
('2f3da718-0b40-4eda-a4f0-e3d634963d1d','和諸庵花光十梅頌  其二','王柏','宋','宋诗','song-poetry','','[]','孤山樹槁神枯，一段底死工夫。',28,'全唐诗/poet.song.210000.json','["孤山樹槁神枯，一段底死工夫。", "脈脈不知機轉，忽然嘴眼皆甦。"]'),
('da1238e9-51a7-4691-8bb7-21526a9b5b75','和諸庵花光十梅頌  其三','王柏','宋','宋诗','song-poetry','','[]','空裏翻身透出，風前玉立精神。',28,'全唐诗/poet.song.210000.json','["空裏翻身透出，風前玉立精神。", "百草頭邊未覺，還他獨占先春。"]'),
('5b4e080f-372d-46c9-9855-705b58f2032b','和諸庵花光十梅頌  其四','王柏','宋','宋诗','song-poetry','','[]','不問東風來未，冷冰冰中得意。',28,'全唐诗/poet.song.210000.json','["不問東風來未，冷冰冰中得意。", "誰於筆外相知，更有無味之味。"]'),
('3dbb45d7-2750-4bda-ae72-8a38ec4e5d96','和諸庵花光十梅頌  其五','王柏','宋','宋诗','song-poetry','','[]','接得少林枝葉，滿腰風雪馨香。',28,'全唐诗/poet.song.210000.json','["接得少林枝葉，滿腰風雪馨香。", "一自飄零庾嶺，花光也解流芳。"]'),
('11adfaf4-ab88-4b5d-9c3d-408b9c1e9843','和諸庵花光十梅頌  其六','王柏','宋','宋诗','song-poetry','','[]','江頭千樹紛紛，紙上不堪狼藉。',28,'全唐诗/poet.song.210000.json','["江頭千樹紛紛，紙上不堪狼藉。", "翻思洞口風流，忽見半梢橫出。"]'),
('f0cab568-4979-4c21-86d8-b2940f1cf92a','和諸庵花光十梅頌  其七','王柏','宋','宋诗','song-poetry','','[]','孤標向背從地，枝頭各自精彩。',28,'全唐诗/poet.song.210000.json','["孤標向背從地，枝頭各自精彩。", "堂堂妙用縱橫，誰識筆根所在。"]'),
('c5864261-636f-4c18-8e26-a8aa21c8aa14','和諸庵花光十梅頌  其八','王柏','宋','宋诗','song-poetry','','[]','大化元無揀擇，墨光隨手高低。',28,'全唐诗/poet.song.210000.json','["大化元無揀擇，墨光隨手高低。", "但得歲寒風度，自然處處皆宜。"]'),
('604b51a3-2000-410f-b07c-c57d3f5c1399','和諸庵花光十梅頌  其九','王柏','宋','宋诗','song-poetry','','[]','幾度落花流水，何待空枝方省。',28,'全唐诗/poet.song.210000.json','["幾度落花流水，何待空枝方省。", "要須投筆虛空，幻習與之俱盡。"]'),
('b2bd88ff-55be-42ee-a576-3a406f6bf1dd','和諸庵花光十梅頌  其一○','王柏','宋','宋诗','song-poetry','','[]','推出突欒本相，雨肥葉底清黄。',28,'全唐诗/poet.song.210000.json','["推出突欒本相，雨肥葉底清黄。", "熟後何曾酸澀，舌根自不尋常。"]'),
('cb4415f9-f875-4d4e-8095-ea47390af7fe','題畫梅','王柏','宋','宋诗','song-poetry','','[]','枝頭寂寞若爲情，喚起毛錐爲寫神。',32,'全唐诗/poet.song.210000.json','["枝頭寂寞若爲情，喚起毛錐爲寫神。", "月下風前長玉立，娟娟一紙四時春。"]'),
('9fe957d5-95a5-4694-a752-7905b2ab7c4d','題花光梅十首 懸崖放下','王柏','宋','宋诗','song-poetry','','[]','著脚孤高太出奇，馮空斜落兩三枝。',32,'全唐诗/poet.song.210000.json','["著脚孤高太出奇，馮空斜落兩三枝。", "大風動地吹崖裂，正是冰姿藴藉時。"]'),
('0427daf0-a151-4afd-bc8c-edffc947613e','題花光梅十首 絕後再甦','王柏','宋','宋诗','song-poetry','','[]','深山大澤老龍僵，不染樵人斧上霜。',32,'全唐诗/poet.song.210000.json','["深山大澤老龍僵，不染樵人斧上霜。", "月魄存存枯槁裏，忽然枝上弄精光。"]'),
('13c0ea6c-3836-4cfb-86a4-50a9b3bd2998','題花光梅十首 平地回春','王柏','宋','宋诗','song-poetry','','[]','見說前村破雪開，我來雪影浸蒼苔。',32,'全唐诗/poet.song.210000.json','["見說前村破雪開，我來雪影浸蒼苔。", "平生不識春風面，却道春從花底來。"]'),
('8d83e189-00a8-4996-a99c-d298ec3629cf','題花光梅十首 淡中有味','王柏','宋','宋诗','song-poetry','','[]','一丘一壑似夷齊，勁雪繁霜特立時。',32,'全唐诗/poet.song.210000.json','["一丘一壑似夷齊，勁雪繁霜特立時。", "瘦影橫斜清峭峭，世間幾箇赴心期。"]'),
('5b2f606e-b57a-46c1-b740-53972c5975c0','題花光梅十首 五葉聯芳','王柏','宋','宋诗','song-poetry','','[]','裁冰鏤雪幾多工，次第開時箇箇同。',32,'全唐诗/poet.song.210000.json','["裁冰鏤雪幾多工，次第開時箇箇同。", "夜半傳香來庾嶺，至今拈起作家風。"]'),
('6975288e-739f-4998-86ee-0af6520ee360','題花光梅十首 一枝橫出','王柏','宋','宋诗','song-poetry','','[]','踏雪尋香幾度吟，吟詩那得似花人。',32,'全唐诗/poet.song.210000.json','["踏雪尋香幾度吟，吟詩那得似花人。", "水村雲壑抽身出，月掛疎籬別有春。"]'),
('2110d829-8d72-4602-b380-0031ff7cd143','題花光梅十首 偏正自在','王柏','宋','宋诗','song-poetry','','[]','枝南枝北出天然，雪艷烟痕若可憐。',32,'全唐诗/poet.song.210000.json','["枝南枝北出天然，雪艷烟痕若可憐。", "冷面崢嶸無向背，何嘗有意向人妍。"]'),
('f70137d3-d1f3-4470-bf13-0a0e218e8b2b','題花光梅十首 高下隨宜','王柏','宋','宋诗','song-poetry','','[]','亞水凌空任短長，枝枝風度要平章。',32,'全唐诗/poet.song.210000.json','["亞水凌空任短長，枝枝風度要平章。", "一樽月下吞花影，剔在須頭點點香。"]'),
('3d603989-a172-4e67-9453-61cdf1583583','題花光梅十首 幻花減盡','王柏','宋','宋诗','song-poetry','','[]','孤標不肯結春緣，細雨黄昏臘正殘。',32,'全唐诗/poet.song.210000.json','["孤標不肯結春緣，細雨黄昏臘正殘。", "望斷落花流水遠，枝枝點點是微酸。"]'),
('0214014b-d9db-4665-a03e-b69af2cb134d','題花光梅十首 實相圓常','王柏','宋','宋诗','song-poetry','','[]','青青葉底未堪嘗，已作商家鼎鼐香。',32,'全唐诗/poet.song.210000.json','["青青葉底未堪嘗，已作商家鼎鼐香。", "四月江南煙雨闊，安心且待那時黄。"]'),
('1254c486-342c-4b29-915d-b56f2cbd7e0f','和遯澤韻取臨江叔父墨梅','王柏','宋','宋诗','song-poetry','','[]','我翁久駕白雲歸，誰寶冰綃一舊枝。',64,'全唐诗/poet.song.210000.json','["我翁久駕白雲歸，誰寶冰綃一舊枝。", "疎影暗香浮戯墨，光風霽月惠仙姿。", "只疑和靖舊爭長，縱是逃禪甘伏雌。", "寄語古樵毋睥睨，青氈歸我不應遲。"]'),
('522eaf70-1e15-4b20-9b32-9d866bc027f5','和仰菴池上梅韻','王柏','宋','宋诗','song-poetry','','[]','窗外梅兄不可無，山人一見兩眉舒。',64,'全唐诗/poet.song.210000.json','["窗外梅兄不可無，山人一見兩眉舒。", "江頭千樹應難得，池上數根宜有餘。", "蟾魄浮香無定相，虬枝壓水可常居。", "只愁疎影翻多事，一片清光不得虛。"]'),
('b86e25b6-07df-4ca8-8acf-d6448b918176','憶昔一首','趙崇嶓','宋','宋诗','song-poetry','','[]','憶昔城南會，珮馬輕春風。',84,'全唐诗/poet.song.210000.json','["憶昔城南會，珮馬輕春風。", "芳華感人心，折贈以爲容。", "俯仰一相失，去若南飛鴻。", "青青女蘿衣，蔚蔚石上松。", "歲寒無夕秀，安得長相從。", "願爲日月光，落君懷袖中。", "三五如循環，千里宛可同。"]'),
('1f31066d-00b4-445c-bc94-76e2cf880824','題彈梟','趙崇嶓','宋','宋诗','song-poetry','','[]','彈梟莫彈鶴，惜此孤飛翰。',48,'全唐诗/poet.song.210000.json','["彈梟莫彈鶴，惜此孤飛翰。", "鶴舉即千里，渺在青雲端。", "彈之固無益，瘦不充君盤。", "却恐梧桐枝，無復棲鳳鸞。"]'),
('5ac6ad6f-fbcc-403a-9d7a-3ce593f0cda4','擬人生不滿百','趙崇嶓','宋','宋诗','song-poetry','','[]','人生不滿百，譬如朝露晞。',60,'全唐诗/poet.song.210000.json','["人生不滿百，譬如朝露晞。", "白日入虞淵，胡不秉燭嬉。", "大耋嗟晷短，多憂亦奚爲。", "君看玄廬道，輀車無停時。", "伺晨當及旦，佳會當及期。"]'),
('8c635132-fcbe-4738-83ba-dec2568ae4f9','故人','趙崇嶓','宋','宋诗','song-poetry','','[]','故人西南風，遺我一束詩。',72,'全唐诗/poet.song.210000.json','["故人西南風，遺我一束詩。", "長哦結幽想，慌惚若見之。", "游雲靄層霄，聚散安可期。", "虛空聞妙音，意重千金貲。", "相思若行月，一夕天之涯。", "閑窗穿夢魂，碧草春離離。"]'),
('ee939197-0bb7-4887-bfe7-53972b667b18','美人貌如花','趙崇嶓','宋','宋诗','song-poetry','','[]','美人貌如花，獨立古道邊。',48,'全唐诗/poet.song.210000.json','["美人貌如花，獨立古道邊。", "芳年抱幽思，艷裔春風前。", "春風固無情，桃李終欲言。", "不剪紅豆枝，相思獨懸懸。"]'),
('397df7bf-9a15-45d7-b604-642eae2a5e81','適趣','趙崇嶓','宋','宋诗','song-poetry','','[]','賦資在山林，適趣非任放。',60,'全唐诗/poet.song.210000.json','["賦資在山林，適趣非任放。", "乾坤入我牖，得此一昭曠。", "雨露日以深，禾黍日以長。", "妻兒喜相謂，一飽知可望。", "飯蔬適我願，此意應勿爽。"]'),
('0ebcc7a4-4d54-45b5-95ca-ba2a148afd63','反輓歌二首  其一','趙崇嶓','宋','宋诗','song-poetry','','[]','生人送死人，哀哀淚如霰。',60,'全唐诗/poet.song.210000.json','["生人送死人，哀哀淚如霰。", "生人閲寒暑，冉冉亦如電。", "來去遞相送，展轉不可見。", "丘樊謹封殖，陵谷猶有變。", "萬古長如斯，何庸致深辯。"]'),
('5cc027f3-b21f-4b0c-9a3b-f777d601e4dc','反輓歌二首  其二','趙崇嶓','宋','宋诗','song-poetry','','[]','死生雖異塗，昭晰本一理。',60,'全唐诗/poet.song.210000.json','["死生雖異塗，昭晰本一理。", "崦嵫落圓景，一訣非永逝。", "達人隨元化，生死一劇耳。", "生生常癡冥，安知非真死。", "死當安吾歸，生當適吾意。"]'),
('f5aa5a1f-2a2c-4640-a320-4bbfb3e03618','用看雲體','趙崇嶓','宋','宋诗','song-poetry','','[]','上有懸石崖，下有滑石道。',84,'全唐诗/poet.song.210000.json','["上有懸石崖，下有滑石道。", "中有觀空人，容顔半枯槁。", "坐息窮年歲，抱此希世寶。", "雖然欠奇俊，塵翳已一掃。", "或云大道初，不剩亦不少。", "用力勤修爲，苦辛坐中老。", "新州有樵人，此意極了了。"]'),
('fab52358-fe8e-45eb-8c4b-1c0c3bc524bb','穠華','趙崇嶓','宋','宋诗','song-poetry','','[]','穠華侈春艷，松柏凌霜雪。',72,'全唐诗/poet.song.210000.json','["穠華侈春艷，松柏凌霜雪。", "芳時若轉盼，萬族畏銷歇。", "人生金石交，所貴在黄髮。", "同衾異寒燠，抱藴應未察。", "貧賤張與陳，利達胡與越。", "安得皎潔心，長年似明月。"]'),
('521fddd3-5af2-4794-a2ac-38fe9bb07d35','野馬','趙崇嶓','宋','宋诗','song-poetry','','[]','野馬紛驅馳，競此光一隙。',48,'全唐诗/poet.song.210000.json','["野馬紛驅馳，競此光一隙。", "世事若頷髭，朝摘暮還出。", "惟應壯與老，冉冉如過客。", "歲寒山上松，稍稍見其實。"]'),
('f5f0f02e-1aeb-4b4b-a4a4-b840b992f26c','詠竹生花','趙崇嶓','宋','宋诗','song-poetry','','[]','竹老方作花，清氣應自結。',48,'全唐诗/poet.song.210000.json','["竹老方作花，清氣應自結。", "結實成琅玕，中心抱冰雪。", "世人弗肯食，欲獻終不屑。", "鳳凰在高岡，音響方節節。"]'),
('36900f4f-493d-426b-b675-b729f98bd144','失題','趙崇嶓','宋','宋诗','song-poetry','','[]','雲臺會功臣，際會若風虎。',72,'全唐诗/poet.song.210000.json','["雲臺會功臣，際會若風虎。", "獨有嚴子陵，垂竿富春渚。", "相求對幽藐，相知有平素。", "吾寢惟吾真，君意應勿忤。", "歸來拂苔石，整我竿上縷。", "煌煌道義間，足以照今古。"]'),
('d1030f24-90f5-496a-a300-94beeb6402ee','春日','趙崇嶓','宋','宋诗','song-poetry','','[]','勾芒暢生意，惠風改繁霜。',84,'全唐诗/poet.song.210000.json','["勾芒暢生意，惠風改繁霜。", "日月天清明，桃李春輝光。", "庶情悉萌達，衆羽同飛翔。", "乘時各有適，皡皡齊康莊。", "山人感物化，欣愜殊未央。", "回視元氣初，萬端一微茫。", "我欲觀其微，因之問鴻荒。"]'),
('8388f51e-bfa7-4dbb-a481-a4404a6e3061','田家','趙崇嶓','宋','宋诗','song-poetry','','[]','方春事鋤犂，晚節多黍稌。',60,'全唐诗/poet.song.210000.json','["方春事鋤犂，晚節多黍稌。", "雞豚樂豐歲，一飽輕萬事。", "少長情熙熙，呼喚相爾汝。", "雖無禮節拘，氣象應近古。", "先進不可期，無懷在農圃。"]'),
('38a01c77-a556-4561-a432-ee80ad838fc6','一蓮','趙崇嶓','宋','宋诗','song-poetry','','[]','一蓮瓶中枯，一蓮池中子。',48,'全唐诗/poet.song.210000.json','["一蓮瓶中枯，一蓮池中子。", "結子心雖苦，而猶勝枯死。", "賞心一日期，詎非得生理。", "君看千歲樗，荒郊永淪棄。"]'),
('8b05557a-2bad-4295-bc1e-ee837f8a5ac6','飲少','趙崇嶓','宋','宋诗','song-poetry','','[]','平生不善飲，飲少醉已極。',60,'全唐诗/poet.song.210000.json','["平生不善飲，飲少醉已極。", "恨不如淵明，陶陶少虛日。", "桑嵫無停景，寸晷足可惜。", "今人與古人，展轉不相識。", "孰能制頹齡，擾擾竟何益。"]'),
('10cb0a36-501f-4ba1-8cae-7912a79be3f5','白蓮','趙崇嶓','宋','宋诗','song-poetry','','[]','池上白蓮花，秋風洗香雪。',44,'全唐诗/poet.song.210000.json','["池上白蓮花，秋風洗香雪。", "坐令紅黛皆塵俗，一種凄凉不堪折。", "微波脈脈露光漙，姑射仙人步烟月。"]'),
('a57785f6-e4ee-46a0-a2f1-c434e7d8a6b4','征婦怨','趙崇嶓','宋','宋诗','song-poetry','','[]','梧桐葉葉生凉秋，燕山早寒已知遒。',64,'全唐诗/poet.song.210000.json','["梧桐葉葉生凉秋，燕山早寒已知遒。", "則則力力歎不休，堂前月光使人愁。", "停針罷線淚沾裳，朔風漸高天雨霜。", "妾憂欲死幸未死，未死猶堪寄衣去。"]'),
('bad4ea09-cd08-421b-816d-7f18eeeb37f0','皎皎','趙崇嶓','宋','宋诗','song-poetry','','[]','皎皎白玉堂，有女白於玉。',60,'全唐诗/poet.song.210000.json','["皎皎白玉堂，有女白於玉。", "門前車馬任西東，門裏苔痕四時綠。", "春風撩亂飛伯勞，櫻桃花重紅夭夭。", "夜深撲落金剪刀，烏龍睡穩蟾蜍高。"]'),
('14f8d344-1166-4742-8a57-1778e93fe8db','代贈','趙崇嶓','宋','宋诗','song-poetry','','[]','雙綰玉釵垂，相逢暗斂眉。',56,'全唐诗/poet.song.210000.json','["雙綰玉釵垂，相逢暗斂眉。", "紅潮初上臉，未語兩心知。", "羅襪凌波拂暗塵，露桃烟柳不勝春。", "珊瑚枝下重相見，曾是鴛鴦夢裏人。"]'),
('88cc0e05-48b1-4135-93ed-fdac0a02eea6','高樓曲','趙崇嶓','宋','宋诗','song-poetry','','[]','高樓漠漠東風塵，花鬚落溪生綠雲。',64,'全唐诗/poet.song.210000.json','["高樓漠漠東風塵，花鬚落溪生綠雲。", "艷歌美酒消好春，千金難解青娥顰。", "燕鶑語言鳳凰意，畫空不成天似水。", "潮紅暈臉濃蛾低，門前采蘩春正遲。"]'),
('e6e2221f-ace9-4c06-ba00-2e6dda7df2fa','進酒行','趙崇嶓','宋','宋诗','song-poetry','','[]','玉槽夜壓葡萄碧，石溜寒泉響凌歷。',64,'全唐诗/poet.song.210000.json','["玉槽夜壓葡萄碧，石溜寒泉響凌歷。", "水精壺中澂琥珀，醉呼酒星下瑶席。", "小鬟春風花滿頭，堂堂一曲真珠喉。", "六國三朝春江流，眼花落井消千愁。"]'),
('c0f5431d-4621-4ca9-a1d3-2a2ead8cb0fa','難忘曲','趙崇嶓','宋','宋诗','song-poetry','','[]','弱花低繡檻，月滿綠楊津。',48,'全唐诗/poet.song.210000.json','["弱花低繡檻，月滿綠楊津。", "一笑領深意，過於三月春。", "樽前停妙舞，堂上設華裀。", "上客不須醉，相將夜向晨。"]'),
('79356125-3007-497c-8203-0f9ffd369365','幽居','趙崇嶓','宋','宋诗','song-poetry','','[]','不作無輿歎，幽居體自胖。',48,'全唐诗/poet.song.210000.json','["不作無輿歎，幽居體自胖。", "能貧蔬食足，投老敝裘安。", "濁酒融春意，青燈話歲寒。", "外頭無限事，忙殺不相干。"]'),
('9d93bbc0-82a1-4419-ab6b-0d2e89c7bcf4','識得','趙崇嶓','宋','宋诗','song-poetry','','[]','識得聱牙字，三生拙未除。',48,'全唐诗/poet.song.210000.json','["識得聱牙字，三生拙未除。", "閑居兩疏傳，餘事二王書。", "老任衣冠古，貧從俎豆疎。", "農人適相告，早晚出犂鋤。"]'),
('1748d1c3-b789-497a-a74e-14b3a3c8bae4','翠雲寺','趙崇嶓','宋','宋诗','song-poetry','','[]','杖屨入雲端，天空眼力寬。',48,'全唐诗/poet.song.210000.json','["杖屨入雲端，天空眼力寬。", "地因山氣濕，窗带瀑聲寒。", "隠几俗氛遠，捲簾僧夢殘。", "相逢隠淪者，妙語亦翻瀾。"]'),
('3ed93ff4-d50d-4aae-b623-f55b3b1d402d','漢地','趙崇嶓','宋','宋诗','song-poetry','','[]','漢地文書密，胡天歲月深。',48,'全唐诗/poet.song.210000.json','["漢地文書密，胡天歲月深。", "但高蘇武節，不察李陵心。", "過鴈西風急，荒臺朔氣沉。", "同生不同恨，萬里一霑襟。"]'),
('837f73d0-4585-453e-9a46-1b8826888059','地僻','趙崇嶓','宋','宋诗','song-poetry','','[]','地僻逢迎少，吾生信杳冥。',48,'全唐诗/poet.song.210000.json','["地僻逢迎少，吾生信杳冥。", "清談養生論，兀坐太玄經。", "性拙貧逾樂，神清夢數靈。", "亭亭歲寒友，相對眼終青。"]'),
('1eec81e0-bb0b-434d-8b08-4c160d1b17d6','咫尺','趙崇嶓','宋','宋诗','song-poetry','','[]','咫尺越山海，其如千里何。',48,'全唐诗/poet.song.210000.json','["咫尺越山海，其如千里何。", "祗應憐命薄，不道賦情多。", "墜綰交枝玉，纖圍百疊羅。", "清宵無限思，枕席起微波。"]'),
('5f0c6310-ac82-4b37-82e8-123a3eef1ae9','臘月','趙崇嶓','宋','宋诗','song-poetry','','[]','臘月二十五，人家祓舊年。',24,'全唐诗/poet.song.210000.json','["臘月二十五，人家祓舊年。", "山人無可禱，睡著不知天。"]'),
('988c82d3-b4b5-4e4a-b581-cd0979b85d36','窗前','趙崇嶓','宋','宋诗','song-poetry','','[]','窗前尋丈地，種得一株梅。',24,'全唐诗/poet.song.210000.json','["窗前尋丈地，種得一株梅。", "明月清風我，紅塵不復來。"]'),
('2fd8051a-a741-4776-a9ba-0be93232189d','失題','趙崇嶓','宋','宋诗','song-poetry','','[]','白玉誰家郎，紅粉何處女。',24,'全唐诗/poet.song.210000.json','["白玉誰家郎，紅粉何處女。", "秀色總堪憐，春風密相許。"]'),
('aaf4ea56-f845-4bda-b940-ab6df1dcde5d','幽意','趙崇嶓','宋','宋诗','song-poetry','','[]','開簾野水聲，倚杖青山色。',24,'全唐诗/poet.song.210000.json','["開簾野水聲，倚杖青山色。", "幽意在人間，人間不相識。"]'),
('ebcb074f-0675-4944-a388-d066f01366c6','春朝偶書','趙崇嶓','宋','宋诗','song-poetry','','[]','一夕春歸桃李根，清寒猶勒艷陽魂。',32,'全唐诗/poet.song.210000.json','["一夕春歸桃李根，清寒猶勒艷陽魂。", "雪霜雨露年年事，惟有梅花地位尊。"]'),
('65802b49-a63f-4b78-a1dc-89a7c450fe96','淮河水','趙崇嶓','宋','宋诗','song-poetry','','[]','秋風淮水白蒼茫，中有英雄淚幾行。',32,'全唐诗/poet.song.210000.json','["秋風淮水白蒼茫，中有英雄淚幾行。", "流到海門流不去，會隨潮汐過錢塘。"]'),
('1af2473a-e9c2-4819-ba0a-482be3e88d4d','天寶禁中','趙崇嶓','宋','宋诗','song-poetry','','[]','外庭班退壽王歸，別有驕兒侍禁闈。',32,'全唐诗/poet.song.210000.json','["外庭班退壽王歸，別有驕兒侍禁闈。", "解事老奴寧及遠，君恩如許政忘機。"]'),
('03f5cd32-a0ee-47c4-a067-b8082fa8325f','廣寒宮','趙崇嶓','宋','宋诗','song-poetry','','[]','碧海沉沉桂殿幽，滿天風露四時秋。',32,'全唐诗/poet.song.210000.json','["碧海沉沉桂殿幽，滿天風露四時秋。", "寒宮白兔參差老，一種凄凉各自愁。"]'),
('9ab92220-9b39-4b48-82e1-c9461195a54c','臨汝道中','趙崇嶓','宋','宋诗','song-poetry','','[]','野水平田稻正青，肩輿軋軋趁新晴。',32,'全唐诗/poet.song.210000.json','["野水平田稻正青，肩輿軋軋趁新晴。", "髼頭奴子無拘束，牛背醉眠歌太平。"]'),
('4bae1f91-a784-4440-b0f0-767832d22ca8','送還吳山稿','趙崇嶓','宋','宋诗','song-poetry','','[]','萬卷文書一幅巾，不將風鑑落埃塵。',32,'全唐诗/poet.song.210000.json','["萬卷文書一幅巾，不將風鑑落埃塵。", "桂花未綠槐花謝，獨佩江蘺有幾人。"]'),
('61a2ea96-3312-4a91-aaa1-e6dda38e168d','移梅','趙崇嶓','宋','宋诗','song-poetry','','[]','鄰家爭乞麗春栽，玉手輕分带月培。',32,'全唐诗/poet.song.210000.json','["鄰家爭乞麗春栽，玉手輕分带月培。", "窗下老翁迂入骨，清齋三日爲移梅。"]'),
('92695d5a-f97e-497e-b637-3597f6ba10e6','癡貓','趙崇嶓','宋','宋诗','song-poetry','','[]','愛汝斒斕任汝癡，了無殺意上鬚眉。',32,'全唐诗/poet.song.210000.json','["愛汝斒斕任汝癡，了無殺意上鬚眉。", "通宵鼠子喧人睡，政爾相忘也大奇。"]'),
('b11330ce-b119-4906-879d-b97463ac98fd','醉起','趙崇嶓','宋','宋诗','song-poetry','','[]','醉起西窗日欲斜，新煙初試雨前茶。',32,'全唐诗/poet.song.210000.json','["醉起西窗日欲斜，新煙初試雨前茶。", "川原春意無聊頼，開盡桐花到柿花。"]'),
('7fbec760-1b61-4bed-ab8c-359dbeeee5a6','幽齋','趙崇嶓','宋','宋诗','song-poetry','','[]','幽齋宜清復宜溫，高卧騰騰百不聞。',32,'全唐诗/poet.song.210000.json','["幽齋宜清復宜溫，高卧騰騰百不聞。", "贏得神安無夢事，從教黄葉夜紛紛。"]'),
('857ecd88-7649-44ad-95a0-4aef26016b52','大廷','趙崇嶓','宋','宋诗','song-poetry','','[]','大廷新革晉春秋，王氣寧知在荻洲。',32,'全唐诗/poet.song.210000.json','["大廷新革晉春秋，王氣寧知在荻洲。", "泉下髯參心獨快，不教司馬恨枋頭。"]'),
('ca765337-b52e-460d-94e5-3fd4aa7b2a0b','有感','趙崇嶓','宋','宋诗','song-poetry','','[]','舞罷歌停歲月深，當時勝蹟盡銷沉。',32,'全唐诗/poet.song.210000.json','["舞罷歌停歲月深，當時勝蹟盡銷沉。", "飛雲捲雨人爭賞，留得佳名尚到今。"]'),
('d0b5ec67-8997-4d73-ac2c-d57b4eef42b9','倚樓','趙崇嶓','宋','宋诗','song-poetry','','[]','平楚連天獨倚樓，樓頭日日望行舟。',32,'全唐诗/poet.song.210000.json','["平楚連天獨倚樓，樓頭日日望行舟。", "相思飛盡梅花雪，江上晴雲片片愁。"]'),
('66bcf66d-f769-43b4-b268-6adb81d2affa','田家','趙崇嶓','宋','宋诗','song-poetry','','[]','雞豚白酒樂豐年，飽即高眠不問天。',32,'全唐诗/poet.song.210000.json','["雞豚白酒樂豐年，飽即高眠不問天。", "少長有恩相爾汝，淳風應似伏羲前。"]'),
('1ccd371e-987d-4075-aa3a-a4a45dd8bed6','西施捧心圖','趙崇嶓','宋','宋诗','song-poetry','','[]','吳苑風光越水春，兩山眉裏笑顰分。',32,'全唐诗/poet.song.210000.json','["吳苑風光越水春，兩山眉裏笑顰分。", "腹心別有堪憂處，狂殺君王藐不聞。"]'),
('5461e537-18bd-41c0-afcc-7dd0cdbdb4ec','晚立','趙崇嶓','宋','宋诗','song-poetry','','[]','古徑苔深晝掩關，外頭塵土不曾閑。',32,'全唐诗/poet.song.210000.json','["古徑苔深晝掩關，外頭塵土不曾閑。", "雨晴天氣明如鏡，靜倚孤松看遠山。"]'),
('f7165bd6-bf25-41a5-a7eb-4603bbad4a9f','獨立','趙崇嶓','宋','宋诗','song-poetry','','[]','片雲收雨入西山，望極蒼茫杳靄間。',32,'全唐诗/poet.song.210000.json','["片雲收雨入西山，望極蒼茫杳靄間。", "蕩蕩太虛無一事，祗應日月不曾閑。"]'),
('5202b31a-9fa2-41e2-b502-cdb168eb5c67','譙樓','趙崇嶓','宋','宋诗','song-poetry','','[]','霜滿譙樓報五更，道人睡穩幾曾聽。',32,'全唐诗/poet.song.210000.json','["霜滿譙樓報五更，道人睡穩幾曾聽。", "金街應有朝天客，珮馬禁寒望曉星。"]'),
('53155ada-0cc5-4bf1-ad4d-38fdc47a5a0b','小窗','趙崇嶓','宋','宋诗','song-poetry','','[]','小窗風定曲肱眠，骨冷魂清夢易圓。',32,'全唐诗/poet.song.210000.json','["小窗風定曲肱眠，骨冷魂清夢易圓。", "蝴蝶不飛花自落，海棠枝下月娟娟。"]'),
('bb60fb43-44c5-4d0a-979b-7cad0ff79e32','小窗對客','趙崇嶓','宋','宋诗','song-poetry','','[]','紙帳梅花自一真，小窗對語坐無裀。',32,'全唐诗/poet.song.210000.json','["紙帳梅花自一真，小窗對語坐無裀。", "詩家供給惟風月，病與詩疏始覺貧。"]'),
('c462065d-296d-433d-b152-dee62f307307','元日雲安道','趙崇嶓','宋','宋诗','song-poetry','','[]','元日度巴雲，時逢朐䏰人。',48,'全唐诗/poet.song.210000.json','["元日度巴雲，時逢朐䏰人。", "野梅空自落，山鳥暗知春。", "不醉新年酒，徒悲異域身。", "無窮倦行意，亭柳漫風塵。"]'),
('c39b3eb4-162e-4174-8375-ebb6d31807e6','立春夜宿西充山驛聞雪','趙崇嶓','宋','宋诗','song-poetry','','[]','獨宿西充館，雲雰灑竹關。',48,'全唐诗/poet.song.210000.json','["獨宿西充館，雲雰灑竹關。", "薄寒生永夜，亂響度空山。", "殘月猶共白，春風相與還。", "一枝梅未寄，歸夢越巴蠻。"]'),
('be8ec8b2-1f01-4654-88fd-971bdb9747eb','立春日舟次藕池阻雪有懷','趙崇嶓','宋','宋诗','song-poetry','','[]','楚澤多芳草，春風昨夜生。',48,'全唐诗/poet.song.210000.json','["楚澤多芳草，春風昨夜生。", "空江寒欲凍，亂雪灑無聲。", "獨坐孤舟穩，能忘萬里情。", "手持新歲酒，空繞落梅行。"]'),
('6c5a4f29-3dc0-4ea3-9903-c90e486de133','立春後三日山行喜雨','趙崇嶓','宋','宋诗','song-poetry','','[]','窮冬陽爲沴，旱氣蒸黄埃。',48,'全唐诗/poet.song.210000.json','["窮冬陽爲沴，旱氣蒸黄埃。", "春風三夜動，春雨隨風來。", "萬類萌甲喜，愁人生意開。", "我行竟何事，欣爾登崔嵬。"]'),
('9796e2bc-4c9e-49b5-90d3-4d5e728a83f7','寒食雨晴書事','趙崇嶓','宋','宋诗','song-poetry','','[]','如何夜來雨，欲妬清明天。',48,'全唐诗/poet.song.210000.json','["如何夜來雨，欲妬清明天。", "皎皎日華曉，千門羅管絃。", "風吹綺襦艷，深入楊柳烟。", "我與君子意，歸心皆浩然。"]'),
('bc75de97-0b27-45b9-89c6-c78d27a9bf3e','寅卯二年八月十五夜皆不見月','趙崇嶓','宋','宋诗','song-poetry','','[]','萬里不自照，清光隨雨休。',48,'全唐诗/poet.song.210000.json','["萬里不自照，清光隨雨休。", "可堪幽魄死，還似去年秋。", "有笛悲遥夜，無人在遠樓。", "共誰高枕卧，相與夢滄洲。"]'),
('cfa14655-7002-4f5b-a850-046eb13fb001','除日萬州臨江亭','趙崇嶓','宋','宋诗','song-poetry','','[]','南浦逢除日，天涯有去舟。',48,'全唐诗/poet.song.210000.json','["南浦逢除日，天涯有去舟。", "蠻城和雨閉，峽水带春流。", "不負新年感，唯多故國愁。", "寧無賀親酒，徒此事羈囚。"]'),
('c7c2d576-9d6a-48df-a966-948d7635a6eb','閨詞','趙崇嶓','宋','宋诗','song-poetry','','[]','恨殺庭前鵲，難憑卜遠期。',24,'全唐诗/poet.song.210000.json','["恨殺庭前鵲，難憑卜遠期。", "朝朝來報喜，誤妾畫雙眉。"]'),
('22590e4c-96c3-4b81-a137-bb378c6759c4','采蓮詞','趙崇嶓','宋','宋诗','song-poetry','','[]','別浦潮生花夢寒，片紅飛下粉痕乾。',32,'全唐诗/poet.song.210000.json','["別浦潮生花夢寒，片紅飛下粉痕乾。", "預知妾面如花面，泣向西風不忍看。"]'),
('2ae54016-1540-427f-81f1-310b8abd9c29','人生歎','趙崇嶓','宋','宋诗','song-poetry','','[]','壯老互淪謝，百年如奔霆。',84,'全唐诗/poet.song.210000.json','["壯老互淪謝，百年如奔霆。", "競將無窮憂，勞此有盡形。", "生時一幻化，死即歸杳冥。", "亦有賢達人，視死如未生。", "亦有醉夢人，既死心未平。", "逆旅朝暮閒，八風無時停。", "擾擾安足計，熙然慰吾情。"]'),
('647c32c5-a2d5-4a17-b860-31a593001c03','古意','趙崇嶓','宋','宋诗','song-poetry','','[]','阿母带兒出，兒行自回皇。',48,'全唐诗/poet.song.210000.json','["阿母带兒出，兒行自回皇。", "兒不倦行路，遣兒心內傷。", "問兒何所傷，兒語不敢詳。", "將兒雇織作，不忍織鴛鴦。"]'),
('dbc6eb8f-7e8c-43a9-914b-03a048985e72','松柏','趙崇嶓','宋','宋诗','song-poetry','','[]','松柏生高岡，不依貴者門。',36,'全唐诗/poet.song.210000.json','["松柏生高岡，不依貴者門。", "松柏長青青，却蔭貴者墳。", "生非門牆交，而與丘隴親。"]'),
('9f2fbb4c-1f5d-47e1-a281-4219dc1a27c8','龍翔宮','趙崇嶓','宋','宋诗','song-poetry','','[]','地闢金光界，龍飛析木津。',48,'全唐诗/poet.song.210000.json','["地闢金光界，龍飛析木津。", "指麾開輦路，祠祀拜元辰。", "天近雲光煖，花濃雨脈春。", "君王自仁壽，閒殺華封人。"]'),
('86858968-7ba3-4462-8f6a-46d8886f9007','詠梅','趙崇嶓','宋','宋诗','song-poetry','','[]','大雅終不羣，古心應自許。',24,'全唐诗/poet.song.210000.json','["大雅終不羣，古心應自許。", "對之鄙吝消，疑是黄叔度。"]'),
('2ffd037f-71c9-42d5-8403-f52915fffe6d','趙飛燕姊妹','趙崇嶓','宋','宋诗','song-poetry','','[]','甲帳初停燕子飛，小雛相趁共差池。',32,'全唐诗/poet.song.210000.json','["甲帳初停燕子飛，小雛相趁共差池。", "春風吹水粼粼長，又有披香博士知。"]'),
('3187342b-5b21-49ca-a103-b6e93ed4eeca','折柳詞','趙崇嶓','宋','宋诗','song-poetry','','[]','行人須折柳，折取最長條。',24,'全唐诗/poet.song.210000.json','["行人須折柳，折取最長條。", "明日天涯路，無人看舞腰。"]'),
('be1e3a29-7e30-4846-9ea8-b7ea8b187869','詠張麗華','趙崇嶓','宋','宋诗','song-poetry','','[]','陳事分明屬綺羅，香塵吹盡井無波。',32,'全唐诗/poet.song.210000.json','["陳事分明屬綺羅，香塵吹盡井無波。", "行軍長史何勞怒，次第論功妾更多。"]'),
('7e253c8f-2ff7-4d02-a952-a2c24df98def','讀陶詩  其一','趙崇嶓','宋','宋诗','song-poetry','','[]','端居洗塵慮，細讀淵明詩。',72,'全唐诗/poet.song.210000.json','["端居洗塵慮，細讀淵明詩。", "疇昔慕此翁，寤寐忘調饑。", "此翁非詩人，而有天然姿。", "紛紛世事中，采采黄菊枝。", "此語人共賞，此意疇復知。", "知即翁之徒，高風接皇羲。"]'),
('39f3d606-12ff-4999-8fe4-839c4a894f70','讀陶詩  其二','趙崇嶓','宋','宋诗','song-poetry','','[]','有籬可種菊，有琴可無絃。',48,'全唐诗/poet.song.210000.json','["有籬可種菊，有琴可無絃。", "適趣不待聲，種菊真偶然。", "南山有佳氣，得意終忘言。", "薄酣空庭中，一笑凉風前。"]'),
('f7d8f9d8-d1be-4bf2-ad49-431509aeda11','讀陶詩罷','趙崇嶓','宋','宋诗','song-poetry','','[]','一山秋意入柴扉，細讀淵明采菊詩。',32,'全唐诗/poet.song.210000.json','["一山秋意入柴扉，細讀淵明采菊詩。", "讀罷依然成一莞，閑拈野草調兒嬉。"]'),
('b219e85a-466c-4506-ad42-42cd9ff9ac6f','偶成','趙崇嶓','宋','宋诗','song-poetry','','[]','負郭二頃田，貿易辦喪祭。',60,'全唐诗/poet.song.210000.json','["負郭二頃田，貿易辦喪祭。", "喪祭幸已周，啼饑坐終歲。", "長貧固非病，時運矧復爾。", "幽居日月閑，糜粥勝甘膩。", "明日春風生，它山蕨薇紫。"]'),
('acca0012-be7d-4fee-82ed-804bad4e1e50','過鄱陽湖','趙崇嶓','宋','宋诗','song-poetry','','[]','烟波三萬頃，著我木蘭船。',48,'全唐诗/poet.song.210000.json','["烟波三萬頃，著我木蘭船。", "望際疑無地，寰中別有天。", "長空孤鳥沒，四海一雲連。", "浩蕩平生意，南風正渺然。"]'),
('3911a5f5-58a8-4655-9893-a6b20441ca5c','西湖','趙崇嶓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','洞府煙霞錦綉叢，車如流水馬如龍。',32,'全唐诗/poet.song.210000.json','["洞府煙霞錦綉叢，車如流水馬如龍。", "東風爛熳花時節，也有人行九里松。"]'),
('9eff812c-3f1e-45e6-833c-74260b940cf4','畫花歌與曾舜賢','趙崇嶓','宋','宋诗','song-poetry','','[]','小曾與花爲莫逆，夢作花神住花國。',128,'全唐诗/poet.song.210000.json','["小曾與花爲莫逆，夢作花神住花國。", "分將天巧入畫圖，花不役君君自役。", "東風一夜入芳叢，春在煙塵霧雨中。", "披香閲紅會花趣，工與造化相流通。", "閉門三月芳事退，馬嵬春泥葬香珮。", "臨邛道士神不靈，約束丹青駐光彩。", "朱門種花錦作窠，畫花絕少種花多。", "百金花價千金畫，羞死當年郭橐駝。"]'),
('082d3d68-adb0-4e6f-8750-ed25e5902069','春宮','趙崇嶓','宋','宋诗','song-poetry','','[]','小苑風酣雨露香，紅情綠意爲春忙。',32,'全唐诗/poet.song.210000.json','["小苑風酣雨露香，紅情綠意爲春忙。", "五雲獨遶瓊花夢，三十六宮清漏長。"]'),
('59efc573-a2e7-45fc-9cf0-216a25e8d818','憑遠亭','趙崇嶓','宋','宋诗','song-poetry','','[]','莎庭日日報平安，幽處依然絕往還。',32,'全唐诗/poet.song.210000.json','["莎庭日日報平安，幽處依然絕往還。", "平野四圍天一幅，有人踏雪看南山。"]'),
('a72a1165-0b25-446b-a575-a8abc01bd1a1','勸農','趙崇嶓','宋','宋诗','song-poetry','','[]','邊頭幾日靜干戈，見說朝家已講和。',32,'全唐诗/poet.song.210000.json','["邊頭幾日靜干戈，見說朝家已講和。", "猶惜人家有湯鑊，攢眉終日爲催科。"]'),
('dffdce9d-ecc0-4eca-bf5e-8291df66af06','遊金精山','趙崇嶓','宋','宋诗','song-poetry','','[]','飛泉灑靈雨，玉田閟青芝。',120,'全唐诗/poet.song.210000.json','["飛泉灑靈雨，玉田閟青芝。", "中有神仙人，宛然姑射姿。", "天巧從古今，虛竇開烟霏。", "歲深語亦誕，目極神爲馳。", "我亦泉石人，夙昔夢見之。", "登臨悟三生，毛髮何森縰。", "未脫區中緣，玉顔畏磷緇。", "仙春醉青桃，蘿風吹輕絲。", "凡事俱爾爾，居然駭癡兒。", "留詩遺仙靈，詎解山中疑。"]'),
('241a7b9a-1ec7-4251-930b-74f8e603a9d4','句  其一','趙崇嶓','宋','宋诗','song-poetry','','[]','苑牆當北斗，宮樹近朝陽。',12,'全唐诗/poet.song.210000.json','["苑牆當北斗，宮樹近朝陽。"]'),
('67fbaee3-c2b5-4c81-a238-06f988f605da','句  其二','趙崇嶓','宋','宋诗','song-poetry','','[]','漢月通江白，秦雲入塞黄。',12,'全唐诗/poet.song.210000.json','["漢月通江白，秦雲入塞黄。"]'),
('043a354e-6c36-4e10-85aa-85acf5ebb011','句  其三','趙崇嶓','宋','宋诗','song-poetry','','[]','鷺依江渚冷，雁入楚雲深。',12,'全唐诗/poet.song.210000.json','["鷺依江渚冷，雁入楚雲深。"]'),
('149f8dd1-363e-4251-b2b3-ff80809ee0f0','句  其四','趙崇嶓','宋','宋诗','song-poetry','','[]','湖海三生夢，乾坤一寸心。',12,'全唐诗/poet.song.210000.json','["湖海三生夢，乾坤一寸心。"]'),
('77590cb4-1f92-4f5f-85ab-262de2320ca1','句  其五','趙崇嶓','宋','宋诗','song-poetry','','[]','天形低赴海，潮勢直通吳。',12,'全唐诗/poet.song.210000.json','["天形低赴海，潮勢直通吳。"]'),
('b7511ecc-9d02-48ff-a64c-f110b0bdb3be','句  其六','趙崇嶓','宋','宋诗','song-poetry','','[]','月入星辰大，山明天地秋。',12,'全唐诗/poet.song.210000.json','["月入星辰大，山明天地秋。"]'),
('d6103d70-7b68-4a59-ac91-efdfc28b74ed','調漁者','趙崇鉘','宋','宋诗','song-poetry','','[]','山明松雪水明沙，一曲清溪著釣槎。',32,'全唐诗/poet.song.210000.json','["山明松雪水明沙，一曲清溪著釣槎。", "我已浮湛君漫浪，謾煎我水試君茶。"]'),
('6b5792b5-8eb9-477a-8ee5-e1f24d4eb393','頗愛','趙崇鉘','宋','宋诗','song-poetry','','[]','頗愛樂天齊物我，夢隨吟賞洛中橋。',32,'全唐诗/poet.song.210000.json','["頗愛樂天齊物我，夢隨吟賞洛中橋。", "桃花細馬載楊柳，半面春潮紅未消。"]'),
('c723f8a8-756f-4240-a08b-0f6680f66c8c','食化','趙崇鉘','宋','宋诗','song-poetry','','[]','海食多詭心，豢食令人魯。',24,'全唐诗/poet.song.210000.json','["海食多詭心，豢食令人魯。", "山中食薺人，幽吟肺腸苦。"]'),
('7e370be8-74d0-4fae-842e-3ff87bbb9f1d','青陽','趙崇鉘','宋','宋诗','song-poetry','','[]','青陽滿芳蕤，流連度丘園。',24,'全唐诗/poet.song.210000.json','["青陽滿芳蕤，流連度丘園。", "眄睞不忍折，恐傷造物恩。"]'),
('a68dd4b8-f0a5-4a4d-85c9-efc928d872aa','夜坐','趙崇鉘','宋','宋诗','song-poetry','','[]','自炷芳蕭讀道書，玄文豁落走龍魚。',32,'全唐诗/poet.song.210000.json','["自炷芳蕭讀道書，玄文豁落走龍魚。", "松梢露色掛北斗，一夜風前學步虛。"]'),
('9e96a85f-4efb-410e-8ebf-b545e9d8f3b8','尋真夕對','趙崇鉘','宋','宋诗','song-poetry','','[]','春雲弄月黄金絲，春山草木皆仙姿。',64,'全唐诗/poet.song.210000.json','["春雲弄月黄金絲，春山草木皆仙姿。", "松根對坐日西夕，群峰當前列青壁。", "鏗鏗虛壑含古音，靜聽宛是商山吟。", "洞石微開月當戶，剪水弦冰心手語。"]'),
('08aaa023-cb75-4f3a-ad48-ee3bdcfc41d5','有贈','趙崇鉘','宋','宋诗','song-poetry','','[]','別意參差繞碧欄，外頭斜月逼人寒。',32,'全唐诗/poet.song.210000.json','["別意參差繞碧欄，外頭斜月逼人寒。", "鈎簾恐礙雙棲鵲，乍可桃花隔霧看。"]'),
('a27180ea-b9a4-469d-87b3-758ff4ae40a1','簡雲卧','趙崇鉘','宋','宋诗','song-poetry','','[]','憶君心事如流水，流向江頭作暮潮。',32,'全唐诗/poet.song.210000.json','["憶君心事如流水，流向江頭作暮潮。", "想得潮平沙有雪，自鏗鐵版和吹簫。"]'),
('35d553ee-d790-4faa-9cd3-6015b6ab71df','空城雀','趙崇鉘','宋','宋诗','song-poetry','','[]','空城雀，黄口莫啾啾。',26,'全唐诗/poet.song.210000.json','["空城雀，黄口莫啾啾。", "空城無人種禾黍，飲啄飛鳴由得汝。"]'),
('1604d6e5-84fd-4f95-b112-7adc10088570','山間','趙崇鉘','宋','宋诗','song-poetry','','[]','山回霧氣濕，生意鞠砰隠。',24,'全唐诗/poet.song.210000.json','["山回霧氣濕，生意鞠砰隠。", "石道苔蘚春，松花鬰金粉。"]'),
('745e331c-2fcc-4668-b068-3f482aa20476','東風','趙崇鉘','宋','宋诗','song-poetry','','[]','東風吹梅梢，飄摇泣香雪。',24,'全唐诗/poet.song.210000.json','["東風吹梅梢，飄摇泣香雪。", "下有野草根，嶄然競時節。"]'),
('2a575625-d368-4eb9-9512-ddf42238aab5','野園','趙崇鉘','宋','宋诗','song-poetry','','[]','野園對客無杯勺，共坐茅檐理釣車。',32,'全唐诗/poet.song.210000.json','["野園對客無杯勺，共坐茅檐理釣車。", "片月漸低風露冷，隔牆山鬼嘯梨花。"]'),
('8aec18f7-c10c-46c6-9c5b-eac281b5f04c','至後','趙崇鉘','宋','宋诗','song-poetry','','[]','愔愔雲氣繞江城，至後寒輕詎可憑。',32,'全唐诗/poet.song.210000.json','["愔愔雲氣繞江城，至後寒輕詎可憑。", "兩日南風將雪信，床前蝙蝠夜翻燈。"]'),
('3d67c42e-d880-4c12-af8e-0a27af0a3cb9','大孤','趙崇鉘','宋','宋诗','song-poetry','','[]','大孤溶溶决眼青，小孤江色春冥冥。',64,'全唐诗/poet.song.210000.json','["大孤溶溶决眼青，小孤江色春冥冥。", "隔江淮壖幾千里，枯荻蕭椮朔風起。", "佳人何在遥相望，我無羽翼從君翔。", "爲君暗整真珠裳，綠蘅翠芷參差香。"]'),
('c5e5d635-a3ff-45da-97f3-02fae19680d4','壯節亭二松','趙崇鉘','宋','宋诗','song-poetry','','[]','壯節亭前野碧滋，髯龍飛去忽經時。',32,'全唐诗/poet.song.210000.json','["壯節亭前野碧滋，髯龍飛去忽經時。", "祇應黄犢蒼藤路，尚有清泉白石知。"]'),
('00b6343b-1382-41ac-a975-64ce637a4925','東風吹桃花','趙崇鉘','宋','宋诗','song-poetry','','[]','東風吹桃花，花光射春林。',48,'全唐诗/poet.song.210000.json','["東風吹桃花，花光射春林。", "相看各媚娬，豔冶摇人心。", "憩蝶下新綠，游魚上清潯。", "百年一須臾，冥觀契飛沉。"]'),
('6081fc5c-ff29-4bfb-bebc-26b360e6b0d2','曉起','趙崇鉘','宋','宋诗','song-poetry','','[]','雨漂窗紙濕成瑕，風壓瓷瓶卧枕沙。',32,'全唐诗/poet.song.210000.json','["雨漂窗紙濕成瑕，風壓瓷瓶卧枕沙。", "曉起無悰餳粥冷，自添新水救梨花。"]'),
('700f078d-456f-469d-8d5e-e4b23dd028cb','江上','趙崇鉘','宋','宋诗','song-poetry','','[]','清露初生紅蓼秋，爽風先到木蘭舟。',32,'全唐诗/poet.song.210000.json','["清露初生紅蓼秋，爽風先到木蘭舟。", "釣絲不捲波痕穩，夢入蘆花數白鷗。"]'),
('6e24e46b-824c-42ba-9ce2-dcac597d59ea','仙思  其一','趙崇鉘','宋','宋诗','song-poetry','','[]','水殿風清急景斜，靈君初下五雲車。',32,'全唐诗/poet.song.210000.json','["水殿風清急景斜，靈君初下五雲車。", "碧羅寶扇雙題字，記是誰人詠落花。"]'),
('ed8bbbd2-5da4-42fd-b519-6a94081dc047','仙思  其二','趙崇鉘','宋','宋诗','song-poetry','','[]','麻姑擗麟不肯食，飛猿嶺上餐松實。',32,'全唐诗/poet.song.210000.json','["麻姑擗麟不肯食，飛猿嶺上餐松實。", "月冷天空涵曙光，露色凝煙白如蜜。"]'),
('e98423f6-0aa4-44db-b633-315c7f5967ee','東溪夜泊','趙崇鉘','宋','宋诗','song-poetry','','[]','雪滿汀洲風滿林，霽光空澈夜深深。',32,'全唐诗/poet.song.210000.json','["雪滿汀洲風滿林，霽光空澈夜深深。", "推篷恰受梅花月，自噴橫簫調楚吟。"]'),
('fc699f31-3673-42c4-ae5b-b09a79b7a10b','甕天名賢集下有天字','趙崇鉘','宋','宋诗','song-poetry','','[]','不見甕天人，但見石上字。',48,'全唐诗/poet.song.210000.json','["不見甕天人，但見石上字。", "誰能負甕去，奪我寥天思。", "甕破奚有餘，甕在奚不足。", "吟作甕天辭，摩挲石苔綠。"]'),
('223cd150-663c-4923-9bb0-9eb8d3deb008','雜興  其一','趙崇鉘','宋','宋诗','song-poetry','','[]','潮平煙斂月明高，霽宇涵空見羽毛。',32,'全唐诗/poet.song.210000.json','["潮平煙斂月明高，霽宇涵空見羽毛。", "我自無能君了了，檣桿獨倚調離騷。"]'),
('e22c7fa1-5c6d-4f26-adf1-679ef2a1596e','雜興  其二','趙崇鉘','宋','宋诗','song-poetry','','[]','日日西風坐石苔，手捫蒼壁倚雲開。',32,'全唐诗/poet.song.210000.json','["日日西風坐石苔，手捫蒼壁倚雲開。", "却來平地觀空色，不信碧虛天際來。"]'),
('cc06a501-af17-4d8b-b7dd-f60de1bd9793','都昌書事','趙崇鉘','宋','宋诗','song-poetry','','[]','世事可無酒，春藤還有花。',48,'全唐诗/poet.song.210000.json','["世事可無酒，春藤還有花。", "山雲欲到地，街鼓又催衙。", "風緊魚休市，官貧飯带沙。", "天機不得問，暮色欲棲鴉。"]'),
('5a1fb172-80e1-4e33-b711-9608b25814de','丫頭巖','趙崇鉘','宋','宋诗','song-poetry','','[]','煙雨斑斕石蘚春，墜雲誰夢寶花顰。',32,'全唐诗/poet.song.210000.json','["煙雨斑斕石蘚春，墜雲誰夢寶花顰。", "行人總被虛名誤，到得傾城又誤人。"]'),
('461e0524-5ed7-4a78-a17b-2fee2d3e89ef','月巖','趙崇鉘','宋','宋诗','song-poetry','','[]','玉丹仙蛻馭飛翰，便作琉璃世界看。',32,'全唐诗/poet.song.210000.json','["玉丹仙蛻馭飛翰，便作琉璃世界看。", "大地山河渾忘却，謾依桂樹舞青鸞。"]'),
('4710d48c-0752-49e6-ae4b-9a9f01bba8bd','壁間韻  其一','趙崇鉘','宋','宋诗','song-poetry','','[]','雨又入簾風又斜，東風吹客客思家。',32,'全唐诗/poet.song.210000.json','["雨又入簾風又斜，東風吹客客思家。", "浣紗西去誰家子，青絹圍裙插杏花。"]'),
('1afb8597-69cf-45d2-a765-392cd254204f','壁間韻  其二','趙崇鉘','宋','宋诗','song-poetry','','[]','山月溪風兩自由，紫蘭綠桂等離憂。',32,'全唐诗/poet.song.210000.json','["山月溪風兩自由，紫蘭綠桂等離憂。", "狂歌鬰鬰成何事，一片夕陽蘆荻秋。"]'),
('1a91e80a-4213-4d5a-bb8e-08f3f83356f4','壁間韻  其三','趙崇鉘','宋','宋诗','song-poetry','','[]','海棠開盡故清寒，漠漠梨花暮色閑。',32,'全唐诗/poet.song.210000.json','["海棠開盡故清寒，漠漠梨花暮色閑。", "酒滿綠樽愁滿酒，醉凭枕障認巫山。"]'),
('10834a07-fa00-43c9-9f54-2d8998e121ff','壁間韻  其四','趙崇鉘','宋','宋诗','song-poetry','','[]','半髧嬋娟垂兩鴉，驚潮微隠寶簪斜。',32,'全唐诗/poet.song.210000.json','["半髧嬋娟垂兩鴉，驚潮微隠寶簪斜。", "客愁政自遊絲亂，莫戴釵頭百結花。"]'),
('2ec7084f-238d-429f-9d45-e842cba33c29','往體  其一','趙崇鉘','宋','宋诗','song-poetry','','[]','積雪久不解，下有希世珍。',36,'全唐诗/poet.song.210000.json','["積雪久不解，下有希世珍。", "志士縕袍間，苦心終不伸。", "安得白日光，能照清夜顰。"]'),
('7b0360d2-9509-46c0-b059-2ee7d1b86959','往體  其二','趙崇鉘','宋','宋诗','song-poetry','','[]','皓彩青雲端，飛光落溟渤。',36,'全唐诗/poet.song.210000.json','["皓彩青雲端，飛光落溟渤。", "渾河與清沚，同受明月魄。", "勿以清濁殊，天光本無隔。"]'),
('bdec7cbf-a3c3-4835-8a59-e9a15a6d89de','往體  其三','趙崇鉘','宋','宋诗','song-poetry','','[]','志士惜流光，遊子念長道。',48,'全唐诗/poet.song.210000.json','["志士惜流光，遊子念長道。", "流光如奔霆，長路漫浩浩。", "饑人忽夢飽，百憂悉傾倒。", "真妄安足論，榮名以爲寶。"]'),
('819f0baa-2c9d-42f2-918f-bf7011c9fc0d','松下','趙崇鉘','宋','宋诗','song-poetry','','[]','松梢凉露警孤鶴，潭面北風蟠老蛟。',32,'全唐诗/poet.song.210000.json','["松梢凉露警孤鶴，潭面北風蟠老蛟。", "蛟老涎腥波浪惡，獨吟碎月看松梢。"]'),
('b29626ff-50f9-42ee-96c9-e02a6d3b7041','癸卯除夕客中','趙崇鉘','宋','宋诗','song-poetry','','[]','膝下傳觴事已非，瓣香千里隔庭闈。',32,'全唐诗/poet.song.210000.json','["膝下傳觴事已非，瓣香千里隔庭闈。", "摧心遠憶新阡上，寂寂低松雪乍晞。"]'),
('5fb56e07-2b7b-44a0-b9da-d7456d8fe2dd','數日','趙崇鉘','宋','宋诗','song-poetry','','[]','數日東風欺病骨，侵凌曉色作輕寒。',32,'全唐诗/poet.song.210000.json','["數日東風欺病骨，侵凌曉色作輕寒。", "客來坐久無談柄，共看游絲上井欄。"]'),
('2a863d39-051c-4f7a-9283-92bf096d3b81','梅','趙崇鉘','宋','宋诗','song-poetry','','[]','新陽斡坤軸，枯朽皆光榮。',120,'全唐诗/poet.song.210000.json','["新陽斡坤軸，枯朽皆光榮。", "棱層冰雪中，復見天地精。", "姑射神所爲，伯夷聖之清。", "太白抱轗軻，靈均擁芳馨。", "是子心魂間，不受纖芥縈。", "獨立萬化先，皎皎非近名。", "溪流鑑寒柯，游風吹落英。", "山明霧氣濕，月落參旗橫。", "群虛妙香發，一洗萬慮輕。", "紛紛兒女姿，慚愧東風情。"]'),
('02e499d1-daff-4d50-82a2-6a9995071a0f','狹斜','趙崇鉘','宋','宋诗','song-poetry','','[]','吳姬凌寒吹玉笛，手彊誤作遲遲聲。',64,'全唐诗/poet.song.210000.json','["吳姬凌寒吹玉笛，手彊誤作遲遲聲。", "却來拋眼調行客，中有二月東風情。", "東風二月楊花滿，伯勞朝啼芳思亂。", "狹斜綉轂易爲愁，解后相逢莫腸斷。"]'),
('1dd8e0f1-52db-4bfc-a04c-019590be48ef','破褐','趙崇鉘','宋','宋诗','song-poetry','','[]','生松鬰寒灰，破褐出殘絮。',24,'全唐诗/poet.song.210000.json','["生松鬰寒灰，破褐出殘絮。", "童兒不耐煩，微吟起身去。"]'),
('83d15256-26c0-4618-afe8-103babdb96a6','湖中','趙崇鉘','宋','宋诗','song-poetry','','[]','汀蒲獵獵起凉颸，碧藕香中獨立時。',32,'全唐诗/poet.song.210000.json','["汀蒲獵獵起凉颸，碧藕香中獨立時。", "機事兩忘吾喪我，扁舟吟過水仙祠。"]'),
('b97f70b7-1d14-4998-b2b2-3510e3acbba6','新堤','趙崇鉘','宋','宋诗','song-poetry','','[]','淡煙衰草雨絲絲，小醉微吟倒接籬。',32,'全唐诗/poet.song.210000.json','["淡煙衰草雨絲絲，小醉微吟倒接籬。", "吟到水西雲影北，莞然一笑已無詩。"]'),
('491d312b-c1f4-4aea-8568-cebd3b9e5599','書事','趙崇鉘','宋','宋诗','song-poetry','','[]','東鄰老翁寒不寐，百結懸鶉抆悲涕。',96,'全唐诗/poet.song.210000.json','["東鄰老翁寒不寐，百結懸鶉抆悲涕。", "自云子孫學灌園，不識江湖與風水。", "大兒里胥縛送州，小兒遁逃卒未休。", "老夫忍饑特未死，犂耙典盡春無牛。", "身爲王民合徭役，運米操舟操不得。", "江湖風水未足愁，檝喪檣傾誤人國。"]'),
('19f8d783-310f-47a6-869d-367562384bf8','答碧山','趙崇鉘','宋','宋诗','song-poetry','','[]','欲種梅花無古根，手移蘭茁上瓷盆。',32,'全唐诗/poet.song.210000.json','["欲種梅花無古根，手移蘭茁上瓷盆。", "却憂偪仄傷蘭性，自下清招爲返魂。"]'),
('14374ac8-c592-43b6-9104-09327e03eeb5','答維溪','趙崇鉘','宋','宋诗','song-poetry','','[]','維溪插架三千軸，葺茝紉蘭得自娛。',32,'全唐诗/poet.song.210000.json','["維溪插架三千軸，葺茝紉蘭得自娛。", "會須握手論活法，靜看碧水生玄珠。"]'),
('e8faa370-51c6-4001-a060-1cf0c006348c','學詩','趙崇鉘','宋','宋诗','song-poetry','','[]','神仙不可學，願學長不死。',48,'全唐诗/poet.song.210000.json','["神仙不可學，願學長不死。", "學詩如學仙，吞霞潔塵滓。", "渚花流水香，煙霏暮山紫。", "凉颸入脩竹，一笑鳴綠綺。"]'),
('60e94589-2193-4528-8504-69669657a724','雀','趙崇鉘','宋','宋诗','song-poetry','','[]','短翅遍斕貝花紫，逐食飛行曉霜裏。',64,'全唐诗/poet.song.210000.json','["短翅遍斕貝花紫，逐食飛行曉霜裏。", "祇知嘴爪求自肥，肥甘累人心弗知。", "天寒日暮向何處，前路多山慎勿去。", "吳兒織網連素空，一落牢籠腥血紅。"]'),
('febd26eb-fb22-4467-9e01-8a64d7e3b0c8','南內','趙崇鉘','宋','宋诗','song-poetry','','[]','已剪諸郎百慮輕，驕兒長大又生獰。',32,'全唐诗/poet.song.210000.json','["已剪諸郎百慮輕，驕兒長大又生獰。", "祇愁南內無歸日，南內歸來萬古情。"]'),
('0b175e70-3ead-4611-97fb-61047419b7b3','題心游樓','劉翼','宋','宋诗','song-poetry','','[]','一自浮光抵玉融，東林山曲世爲農。',64,'全唐诗/poet.song.210000.json','["一自浮光抵玉融，東林山曲世爲農。", "前場歲計禾麻麥，後圃年深竹荔松。", "博我多聞千載史，喚人深省五更鐘。", "不消更會楞嚴語，面面披雲挹曉峯。"]'),
('f2432767-0e3c-4249-b648-0af6ed872751','心游樓即事','劉翼','宋','宋诗','song-poetry','','[]','禪坐寧離此，意行何所如。',48,'全唐诗/poet.song.210000.json','["禪坐寧離此，意行何所如。", "稻粱詩七月，果木賦閑居。", "活水嘗新茗，顛風落舊書。", "無才甘用拙，不是隠樵漁。"]'),
('c1e1c4d8-20fc-4804-9cd9-b8688bc4d8ad','癸卯十月同林子宜拜掃先師樂軒墓因和南谷寺壁間韻','劉翼','宋','宋诗','song-poetry','','[]','秋風颯颯已華顛，男女猶賒嫁娶錢。',64,'全唐诗/poet.song.210000.json','["秋風颯颯已華顛，男女猶賒嫁娶錢。", "問道西軒空有夢，繙經南谷恐無緣。", "登墳薦酒徒爲爾，對佛拈花亦偶然。", "回首白雲無叫處，青山長在淚痕邊。"]'),
('919eac34-6d78-45d5-94d8-1bace9ca0f9d','答林昌宗詩筌韻','劉翼','宋','宋诗','song-poetry','','[]','經鋤小暇弄詩筌，老去仍知默是禪。',32,'全唐诗/poet.song.210000.json','["經鋤小暇弄詩筌，老去仍知默是禪。", "滄海移舟盡琴趣，雖然終不似無絃。"]'),
('511cbb45-2297-4c8f-93e8-8e86b2b7b07d','題東皋詩卷','劉翼','宋','宋诗','song-poetry','','[]','雪竹霜松不老身，儘教後進笑陳人。',32,'全唐诗/poet.song.210000.json','["雪竹霜松不老身，儘教後進笑陳人。", "相逢亦有吟詩客，誰似先生語意真。"]'),
('282da0b0-7d7e-4a70-becc-bf5e0b895d54','書情','劉翼','宋','宋诗','song-poetry','','[]','蕭疏遠市囂，山窟雜耕樵。',48,'全唐诗/poet.song.210000.json','["蕭疏遠市囂，山窟雜耕樵。", "窮鬼乘吾拙，錢神挾汝驕。", "世途自巇嶮，真性本逍遥。", "尚想榮期樂，綸巾傲漢貂。"]'),
('e37976e3-2cc0-43ef-9a56-29bc7063f404','夜意','劉翼','宋','宋诗','song-poetry','','[]','平生萬事水東流，獨有多情是風癢。',32,'全唐诗/poet.song.210000.json','["平生萬事水東流，獨有多情是風癢。", "夜長無寐月窺牀，擁被孤吟起遐想。"]'),
('02ac4184-e03d-404e-b804-381639d6992a','伯言見和拙作以漢隸書之謝以七韻','劉翼','宋','宋诗','song-poetry','','[]','李潮善八分，求歌杜陵叟。',84,'全唐诗/poet.song.210000.json','["李潮善八分，求歌杜陵叟。", "有人和我詩，半紙餘科斗。", "風雲生其懷，劍戟出其手。", "石經中郎蔡，新樣元和柳。", "元常文不傳，退之書何有。", "待我農隙時，載筆隨君後。", "袖手眼亦明，聊與之飲酒。"]'),
('bf90c614-1906-47a3-b0a6-52ac3988a9e5','偶見官舍梅花作','劉翼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天然標格自瀟疏，底用松篁水月俱。',32,'全唐诗/poet.song.210000.json','["天然標格自瀟疏，底用松篁水月俱。", "但是梅花皆可愛，何關東閣與西湖。"]'),
('ee6d3240-c6bd-453a-9177-b6121ebb2a14','挽敖儀仲  其一','劉翼','宋','宋诗','song-poetry','','[]','半面春風已有情，別來重見眼終青。',32,'全唐诗/poet.song.210000.json','["半面春風已有情，別來重見眼終青。", "空齋夜雨十年後，一醉黄花叫不醒。"]'),
('8529bc75-1e3f-45ef-ba70-53dad0412b84','挽敖儀仲  其二','劉翼','宋','宋诗','song-poetry','','[]','對坐茶甌日兩迴，胸懷真率向人開。',32,'全唐诗/poet.song.210000.json','["對坐茶甌日兩迴，胸懷真率向人開。", "茶甌對客如前度，不見先生杖屨來。"]'),
('9ce2e3c1-c3ed-4664-9eb1-ee5e9b69690d','挽敖儀仲  其三','劉翼','宋','宋诗','song-poetry','','[]','晝倚籃輿餞一杯，殷勤別語到簾幃。',32,'全唐诗/poet.song.210000.json','["晝倚籃輿餞一杯，殷勤別語到簾幃。", "那知此夜成長往，書屋無人月掩扉。"]'),
('081488a4-2c06-4bc6-bce8-d2ef82687f57','挽敖儀仲  其四','劉翼','宋','宋诗','song-poetry','','[]','書中有種復何愁，酒興詩狂卒未休。',32,'全唐诗/poet.song.210000.json','["書中有種復何愁，酒興詩狂卒未休。", "莫唱橫塘斷腸句，不堪斜日獨登樓。"]'),
('b45aa625-3324-4425-b0e7-53e1c3e2427d','送二子從子宜讀書','劉翼','宋','宋诗','song-poetry','','[]','三代讀書無寸功，又將此法教兒童。',32,'全唐诗/poet.song.210000.json','["三代讀書無寸功，又將此法教兒童。", "旁人笑我背時好，不背旁人背樂翁。"]'),
('7d6b875e-b259-4f04-a6cc-1c6b3aed8cef','山寺聽雨','劉翼','宋','宋诗','song-poetry','','[]','問道論詩也一宗，燒柴煨芋佛家風。',32,'全唐诗/poet.song.210000.json','["問道論詩也一宗，燒柴煨芋佛家風。", "要知真樂人間少，聽雨空山破寺中。"]'),
('5a6742ee-0eae-4dda-8582-1b9e0f72df85','戲和劉雪巢題壁韻','劉翼','宋','宋诗','song-poetry','','[]','吟懷祗怕俗塵迷，若慕唐人也自癡。',32,'全唐诗/poet.song.210000.json','["吟懷祗怕俗塵迷，若慕唐人也自癡。", "要識性情根極處，請觀三百五篇詩。"]'),
('036bb7c5-8c03-40db-a1d8-681c81620bd4','題平遠軒呈竹溪玉堂','劉翼','宋','宋诗','song-poetry','','[]','溪堂闢小軒，此景絕可愛。',132,'全唐诗/poet.song.210000.json','["溪堂闢小軒，此景絕可愛。", "蔡松道東邊，千載典刑在。", "高低萬頃田，面勢溪向背。", "生綃一幅寬，晴雨不盡態。", "中有謫仙人，來尋莘野耒。", "畎畝雖不忘，知進不如退。", "乾坤入醉眼，風月出吟喙。", "我非人境遊，亭在人境內。", "心平水不波，見遠山無礙。", "時携琰石遊，間以劉白輩。", "僕忝老諸生，來扣佛三昧。"]'),
('10f87e90-b4bb-46e7-9ef5-b0aece31acc5','題簡上人西亭詩文後','劉翼','宋','宋诗','song-poetry','','[]','真如非字義，綺語道之疵。',48,'全唐诗/poet.song.210000.json','["真如非字義，綺語道之疵。", "未見西亭作，長爲北磵欺。", "晚因僧媚遠，初實客從㬢。", "多少才名士，沉淪世不知。"]'),
('d373fe66-33c0-414e-bee3-ffdf8f2b4a71','夢呈樂軒先生既覺不失一字錄呈竹溪玉堂','劉翼','宋','宋诗','song-poetry','','[]','不見仙翁四十春，幸然丘隴在比鄰。',32,'全唐诗/poet.song.210000.json','["不見仙翁四十春，幸然丘隴在比鄰。", "當年四海從游者，報佛深恩有幾人。"]'),
('9a5f2722-87a5-465e-a092-fe1df4dd9bc4','句','劉翼','宋','宋诗','song-poetry','','[]','富貴功名堪擘畫，最難擘畫子孫賢。',16,'全唐诗/poet.song.210000.json','["富貴功名堪擘畫，最難擘畫子孫賢。"]'),
('a2e375af-937b-42a1-8d16-a4cd82f76779','偈頌七十一首  其一','釋了惠','宋','宋诗','song-poetry','','[]','投胎不著，一錯百錯。',39,'全唐诗/poet.song.210000.json','["投胎不著，一錯百錯。", "周行七步惹塵埃，直至如今抖不落。", "抖不落，定慧只得將錯就錯。"]'),
('cbe88e4e-d3e2-48c2-b2a0-db6dba898332','偈頌七十一首  其二','釋了惠','宋','宋诗','song-poetry','','[]','物見主，眼卓豎。',32,'全唐诗/poet.song.210000.json','["物見主，眼卓豎。", "此是吾家修月斧，須憑衆力共提持，無圓缺處重修補。"]'),
('551ae0b0-7568-432c-a5b9-84cdd6f0b970','偈頌七十一首  其三','釋了惠','宋','宋诗','song-poetry','','[]','舉步生荆棘，翻身墮嶮崖。',24,'全唐诗/poet.song.210000.json','["舉步生荆棘，翻身墮嶮崖。", "一毫不動著，當處自沉埋。"]'),
('80c5646d-54c4-45e0-b075-2987b6fdf955','偈頌七十一首  其四','釋了惠','宋','宋诗','song-poetry','','[]','李下不整冠，瓜田不納履。',38,'全唐诗/poet.song.210000.json','["李下不整冠，瓜田不納履。", "尀耐老臊胡，西來十萬里。", "疑殺東震旦人，將謂單傳直指。"]'),
('0e062b0f-fe14-45cf-a2de-8aea554728b4','偈頌七十一首  其五','釋了惠','宋','宋诗','song-poetry','','[]','大地爲囹圄，鞫勘佛與祖。',56,'全唐诗/poet.song.210000.json','["大地爲囹圄，鞫勘佛與祖。", "款案猶未圓，棒喝如雷雨。", "平白累山僧，有屈無雪處。", "有雪處，楖𣗖橫擔不顧人，直入千峰萬峰去。"]'),
('ba9ce209-59c8-4919-ac1a-84af26766b38','偈頌七十一首  其六','釋了惠','宋','宋诗','song-poetry','','[]','玄中之玄，妙中之妙。',34,'全唐诗/poet.song.210000.json','["玄中之玄，妙中之妙。", "識其淵源，得其樞要。", "普化踢倒飯床，水潦呵呵大笑。"]'),
('c7f21c66-a0ef-4ee2-a05d-2c38d6ab0415','偈頌七十一首  其七','釋了惠','宋','宋诗','song-poetry','','[]','山空木落，秋清露寒。',38,'全唐诗/poet.song.210000.json','["山空木落，秋清露寒。", "釋迦鹵莽，達磨顢頇。", "唯有陶靖節，東籬採黄菊，爛醉夕陽殘。"]'),
('fce7ea92-b9fb-4bca-8bb6-21d485212d44','偈頌七十一首  其八','釋了惠','宋','宋诗','song-poetry','','[]','兩手指天地，周行步更多。',24,'全唐诗/poet.song.210000.json','["兩手指天地，周行步更多。", "可憐黄面老，螃蟹落湯鍋。"]'),
('012f84ed-c4f2-4f68-aa96-eb83405e99b6','偈頌七十一首  其九','釋了惠','宋','宋诗','song-poetry','','[]','撥亂乾坤老賊精，天教化火自焚身。',32,'全唐诗/poet.song.210000.json','["撥亂乾坤老賊精，天教化火自焚身。", "賊心賊行難磨滅，二月依前是仲春。"]'),
('fc2c87ee-7029-49fe-901a-f5bce9f75854','偈頌七十一首  其一○','釋了惠','宋','宋诗','song-poetry','','[]','一二三四五，不落宮商角徵羽。',46,'全唐诗/poet.song.210000.json','["一二三四五，不落宮商角徵羽。", "混然格調超千古，白雪陽春安足數。", "此曲而今誰樂聞，夜來月在長松樹。"]'),
('3ccbbc4c-e528-4ca6-aa9e-4050fba782f6','偈頌七十一首  其一一','釋了惠','宋','宋诗','song-poetry','','[]','天兮高，地兮厚。',40,'全唐诗/poet.song.210000.json','["天兮高，地兮厚。", "月爲夜，日爲晝。", "重陽定是九月九。", "淵明採菊向東籬，山僧面南看北斗。"]'),
('a252dce7-14d0-4d48-9502-d55bcf9d554a','偈頌七十一首  其一二','釋了惠','宋','宋诗','song-poetry','','[]','七手八脚，三頭兩面。',66,'全唐诗/poet.song.210000.json','["七手八脚，三頭兩面。", "歡喜冤家，頭頭撞見。", "山僧建立宗旨，直須爲我成褫。", "學人未達其源，也要請師方便。", "有方便，沒方便。", "石鞏張弓，三平中箭。"]'),
('1c0df393-0a37-487b-b927-f0cf96b7e530','偈頌七十一首  其一三','釋了惠','宋','宋诗','song-poetry','','[]','鷹窠裏懵鴟，鳩巢中俊鷂。',50,'全唐诗/poet.song.210000.json','["鷹窠裏懵鴟，鳩巢中俊鷂。", "稱尊未必尊，做小未必小。", "只麽泥裏洗泥，到了全沒分曉。", "有分曉，海水不禁杓子舀。"]'),
('61957659-6c87-45a6-ba2c-7e1353e51dc7','偈頌七十一首  其一四','釋了惠','宋','宋诗','song-poetry','','[]','五月端午令節，艾人苦痛不徹。',72,'全唐诗/poet.song.210000.json','["五月端午令節，艾人苦痛不徹。", "可憐病在膏肓，又被邪神所惑。", "撞著太上老君，也是赤口白舌。", "山僧反覆思量，別無仙方秘訣。", "如今抑不得已，只得就渠身上打劫。"]'),
('9ae94e96-919b-4a33-92e3-8b963281fd3a','偈頌七十一首  其一五','釋了惠','宋','宋诗','song-poetry','','[]','白雲深處憨眠好，野菜添油滋味長。',32,'全唐诗/poet.song.210000.json','["白雲深處憨眠好，野菜添油滋味長。", "千古康廬話頭活，山僧笑擘紫泥香。"]'),
('7af28a61-8db5-4b08-8ed1-b8b5fc043d83','偈頌七十一首  其一六','釋了惠','宋','宋诗','song-poetry','','[]','的的此事，真不可說。',36,'全唐诗/poet.song.210000.json','["的的此事，真不可說。", "不可說中真可說，真可說，無可說。", "齒臨部臨，急急敕攝。"]'),
('82ecc760-8a62-4237-a223-729fc0c501a3','偈頌七十一首  其一七','釋了惠','宋','宋诗','song-poetry','','[]','向上關，脚下路。',20,'全唐诗/poet.song.210000.json','["向上關，脚下路。", "才擬問如何，邯鄲學唐步。"]'),
('22d966b9-9e91-443f-8c62-ad3565950322','偈頌七十一首  其一八','釋了惠','宋','宋诗','song-poetry','','[]','楚江南畔，甬水東邊。',40,'全唐诗/poet.song.210000.json','["楚江南畔，甬水東邊。", "有一句子，不方不圓。", "四七二三，望風結舌。", "德山臨濟，退後垂涎。"]'),
('15a75c26-8250-4922-ab3d-33b7993ed2f5','偈頌七十一首  其一九','釋了惠','宋','宋诗','song-poetry','','[]','隔江回首，已涉波瀾。',20,'全唐诗/poet.song.210000.json','["隔江回首，已涉波瀾。", "官路交肩，猶添荆棘。"]'),
('c68df01c-cf5c-44e9-9937-812e448163fc','偈頌七十一首  其二○','釋了惠','宋','宋诗','song-poetry','','[]','秉太阿劍，立太平基。',38,'全唐诗/poet.song.210000.json','["秉太阿劍，立太平基。", "卷旗青海尾，奏凱亂峰西。", "弟應兄呼成活業，汝携鉏去我扶犁。"]'),
('9ae1b5ef-e1f0-473c-99da-b1b188be0879','偈頌七十一首  其二一','釋了惠','宋','宋诗','song-poetry','','[]','年去年來，年來年去。',34,'全唐诗/poet.song.210000.json','["年去年來，年來年去。", "雖有去來年，且無來去路。", "既無來去路，實無有去來。"]'),
('e3f165cf-08cf-4738-b907-6379e69b85c2','偈頌七十一首  其二二','釋了惠','宋','宋诗','song-poetry','','[]','起寨重招五百兵，等閑恢復百餘城。',32,'全唐诗/poet.song.210000.json','["起寨重招五百兵，等閑恢復百餘城。", "凌烟閣上清風起，留得將軍萬世名。"]'),
('d1054a0a-42c7-45a6-ac73-bd3f1f1334ab','偈頌七十一首  其二三','釋了惠','宋','宋诗','song-poetry','','[]','護生須是殺，殺盡始安居。',24,'全唐诗/poet.song.210000.json','["護生須是殺，殺盡始安居。", "會得箇中意，唵悉唎蘇嚧。"]'),
('8c4e8e2d-5832-4b87-8139-25ccb8ea8fbb','偈頌七十一首  其二四','釋了惠','宋','宋诗','song-poetry','','[]','諸佛諸祖，邪入肺腑。',20,'全唐诗/poet.song.210000.json','["諸佛諸祖，邪入肺腑。", "無藥可醫，無術可取。"]'),
('c8ce1013-80c2-4341-92c2-bcb114dd6ced','偈頌七十一首  其二五','釋了惠','宋','宋诗','song-poetry','','[]','面壁堆危引客過，問誰那更問如何。',32,'全唐诗/poet.song.210000.json','["面壁堆危引客過，問誰那更問如何。", "道尋常已成多事，檢點儂家事更多。"]'),
('14151a6f-951c-4874-8ade-c355acdbad2c','偈頌七十一首  其二六','釋了惠','宋','宋诗','song-poetry','','[]','洞山有物黑似漆，老倒玉泉裩赫赤。',70,'全唐诗/poet.song.210000.json','["洞山有物黑似漆，老倒玉泉裩赫赤。", "赤者吉中有凶，黑者凶中有吉，明眼衲僧難辨的。", "即今吉凶悔吝拈向一邊，玉泉洞山且靠一壁，却聽拄杖子出來露箇消息。"]'),
('14145858-a52a-4f17-a186-ff8b533e8c84','偈頌七十一首  其二七','釋了惠','宋','宋诗','song-poetry','','[]','迦葉擎拳，阿難合掌。',48,'全唐诗/poet.song.210000.json','["迦葉擎拳，阿難合掌。", "臨濟入門喝，德山入門棒。", "小人道消，君子道長。", "曉來策杖過溪西，十分春在梅梢上。"]'),
('e4651899-8d76-4b34-beab-0b16f8dd83ff','偈頌七十一首  其二八','釋了惠','宋','宋诗','song-poetry','','[]','洪機莫測，至德難量。',38,'全唐诗/poet.song.210000.json','["洪機莫測，至德難量。", "萬民幾鷗鷺，四海一池塘。", "日日春風相鼓舞，不知時世是羲皇。"]'),
('27819a1b-4f92-4acf-806c-271080f89267','偈頌七十一首  其二九','釋了惠','宋','宋诗','song-poetry','','[]','冰雪凍皮膚，麻麥餓腸肚。',52,'全唐诗/poet.song.210000.json','["冰雪凍皮膚，麻麥餓腸肚。", "見日未嘗迷，見星安有悟。", "黄面老瞿曇，甜瓜成苦瓠。", "那更錯行山下路，一步兩步三四步。"]'),
('77340ed0-218a-44aa-b5e2-fb5d98ca157c','偈頌七十一首  其三○','釋了惠','宋','宋诗','song-poetry','','[]','舊歲已去，去不可追。',20,'全唐诗/poet.song.210000.json','["舊歲已去，去不可追。", "新歲當來，來不可拒。"]'),
('658a9acf-6c65-4252-ad29-a1275dbe1635','偈頌七十一首  其三一','釋了惠','宋','宋诗','song-poetry','','[]','諸佛日日降生，聖人時時出現。',75,'全唐诗/poet.song.210000.json','["諸佛日日降生，聖人時時出現。", "與大地群生，同一耳聞，同一眼見，同此一心，同此一念。", "共樂太平時，大家呈笑面。", "有誰更問，日與長老，孰近孰遠，大千沙界含元殿。"]'),
('dbbad735-daeb-44a7-ba48-d3704bce3b16','偈頌七十一首  其三二','釋了惠','宋','宋诗','song-poetry','','[]','霜蹄一躍趁春風，看盡深紅及淺紅。',32,'全唐诗/poet.song.210000.json','["霜蹄一躍趁春風，看盡深紅及淺紅。", "鞭影未摇歸路活，杜鵑聲在夕陽中。"]'),
('cf63f1a1-8b2b-4d4a-a53f-46507fbb3178','偈頌七十一首  其三三','釋了惠','宋','宋诗','song-poetry','','[]','大千總是神仙藥，此藥無多靈驗多。',32,'全唐诗/poet.song.210000.json','["大千總是神仙藥，此藥無多靈驗多。", "七佛之師雖解用，難醫無病老維摩。"]'),
('af59cbb0-b17f-4ad1-9ee7-a0f1ced130e8','偈頌七十一首  其三四','釋了惠','宋','宋诗','song-poetry','','[]','這些業種自何來，雖不同門共一家。',32,'全唐诗/poet.song.210000.json','["這些業種自何來，雖不同門共一家。", "連累山僧至今日，一重枷上又添枷。"]'),
('8d17186b-e99c-4c54-97ab-e1a95e9bf15b','偈頌七十一首  其三五','釋了惠','宋','宋诗','song-poetry','','[]','東澗一滴水，東湖千丈波。',24,'全唐诗/poet.song.210000.json','["東澗一滴水，東湖千丈波。", "幾多湖上客，無可奈船何。"]'),
('3589d06f-44b6-4a35-b96c-cf757b81ae3e','偈頌七十一首  其三六','釋了惠','宋','宋诗','song-poetry','','[]','火種深埋冷寂中，幾回撥著煖烘烘。',32,'全唐诗/poet.song.210000.json','["火種深埋冷寂中，幾回撥著煖烘烘。", "不知將謂吹噓力，元是東君信息通。"]'),
('95bd6bae-e659-485d-8616-1425f522bc3e','偈頌七十一首  其三七','釋了惠','宋','宋诗','song-poetry','','[]','明星照得眼睛穿，眼睛覷得明星落。',32,'全唐诗/poet.song.210000.json','["明星照得眼睛穿，眼睛覷得明星落。", "夜半依前是子時，敢保不曾成正覺。"]'),
('e03eaadc-ab11-4a8b-ae6d-e86354792e26','偈頌七十一首  其三八','釋了惠','宋','宋诗','song-poetry','','[]','權實雙行，主賓互立。',20,'全唐诗/poet.song.210000.json','["權實雙行，主賓互立。", "拏空塞空，以的破的。"]'),
('4fa41356-e4a7-4034-9969-8e21352f4a8e','偈頌七十一首  其三九','釋了惠','宋','宋诗','song-poetry','','[]','風前無語立須臾，接得雙雙錦鯉魚。',32,'全唐诗/poet.song.210000.json','["風前無語立須臾，接得雙雙錦鯉魚。", "一等是傳真的信，有通書有不通書。"]'),
('d8fdd427-124e-4f52-a3b9-be5877fcf7d1','偈頌七十一首  其四○','釋了惠','宋','宋诗','song-poetry','','[]','飛雪巖前，炎天飛雪。',36,'全唐诗/poet.song.210000.json','["飛雪巖前，炎天飛雪。", "凍得虛空，七花八裂。", "至今捏聚不成團，子規夜哭松梢月。"]'),
('5085fe10-27d5-4d47-8ddc-3d04bf6a0113','偈頌七十一首  其四一','釋了惠','宋','宋诗','song-poetry','','[]','荆榛密密布前峰，塞斷行人路不通。',32,'全唐诗/poet.song.210000.json','["荆榛密密布前峰，塞斷行人路不通。", "昨夜連山遭野火，更無芽蘗惱春風。"]'),
('0d21b93d-e83b-4284-b60b-e81d419afe99','偈頌七十一首  其四二','釋了惠','宋','宋诗','song-poetry','','[]','拄杖自拄杖，山僧自山僧。',40,'全唐诗/poet.song.210000.json','["拄杖自拄杖，山僧自山僧。", "庭空積深雪，池冷起冰稜。", "樓上未吹新歲角，窗前且點舊年燈。"]'),
('9e3e96ef-93d2-4c6b-b603-aedff5ac7c3b','偈頌七十一首  其四三','釋了惠','宋','宋诗','song-poetry','','[]','護生須是殺，殺盡始安居。',24,'全唐诗/poet.song.210000.json','["護生須是殺，殺盡始安居。", "會得箇中意，鐵船水上浮。"]'),
('a90ad18f-b6f9-4a66-b2f8-c627f8f1f42d','偈頌七十一首  其四四','釋了惠','宋','宋诗','song-poetry','','[]','滿目荆榛，亙天烈焰。',44,'全唐诗/poet.song.210000.json','["滿目荆榛，亙天烈焰。", "百匝千重，四方八面。", "趙州拏得七斤衫，普化走入大悲院，蠟人眼光如掣電。"]'),
('cbd41e1c-cb61-40a1-9e7c-a29a7241638b','偈頌七十一首  其四五','釋了惠','宋','宋诗','song-poetry','','[]','石溪怒發，勢不可遏。',20,'全唐诗/poet.song.210000.json','["石溪怒發，勢不可遏。", "大地平沈，虛空慘怛。"]'),
('8be4a32d-a4fd-49ec-8777-8b0f79307dc8','偈頌七十一首  其四六','釋了惠','宋','宋诗','song-poetry','','[]','虎生三子尾吒沙，咂舌垂涎弄爪牙。',32,'全唐诗/poet.song.210000.json','["虎生三子尾吒沙，咂舌垂涎弄爪牙。", "但見威風起巖竇，不知月照幾千家。"]'),
('a67bde5d-f654-4301-a538-0f9fcd133c6d','偈頌七十一首  其四七','釋了惠','宋','宋诗','song-poetry','','[]','今朝九月九，淵明開醉口。',48,'全唐诗/poet.song.210000.json','["今朝九月九，淵明開醉口。", "指點東籬菊，大駡西門柳。", "諸人聽得，只麽飲氣吞聲。", "山僧聞之，不免袖中出手。"]'),
('25bd684a-5752-42dc-bd39-fdc5d39cba95','偈頌七十一首  其四八','釋了惠','宋','宋诗','song-poetry','','[]','扁舟劃斷曉江雲，一曲高歌遠送君。',32,'全唐诗/poet.song.210000.json','["扁舟劃斷曉江雲，一曲高歌遠送君。", "驚起灘頭野鴨子，海天飛去不成群。"]'),
('945b27f6-8914-4ee1-826b-fc5c4bf45262','偈頌七十一首  其四九','釋了惠','宋','宋诗','song-poetry','','[]','千峰沐雨，萬樹籠烟。',22,'全唐诗/poet.song.210000.json','["千峰沐雨，萬樹籠烟。", "磨盤呈舊面，水碓拜新年。"]'),
('ddb36898-fe4a-45a5-ac81-42530fc613c8','偈頌七十一首  其五○','釋了惠','宋','宋诗','song-poetry','','[]','六年心念已灰寒，幾欲求閑不得閑。',32,'全唐诗/poet.song.210000.json','["六年心念已灰寒，幾欲求閑不得閑。", "今日不求閑自至，一枝藤占幾江山。"]'),
('2b4d9d6b-bc70-470f-9fce-6970d714df1d','偈頌七十一首  其五一','釋了惠','宋','宋诗','song-poetry','','[]','一擊華鯨吼月明，主翁魂夢已惺惺。',32,'全唐诗/poet.song.210000.json','["一擊華鯨吼月明，主翁魂夢已惺惺。", "海天空闊無知己，贏得潮聲到客亭。"]'),
('9341258f-dc78-4e1c-b782-2aa6df095074','偈頌七十一首  其五二','釋了惠','宋','宋诗','song-poetry','','[]','南山鼈鼻蛇，攛入新羅國。',24,'全唐诗/poet.song.210000.json','["南山鼈鼻蛇，攛入新羅國。", "吞却鎮海珠，咬殺嘉州佛。"]'),
('7a898b7d-e7cb-42ee-9d75-0aefe6e7363d','偈頌七十一首  其五三','釋了惠','宋','宋诗','song-poetry','','[]','今之房杜昔伊周，功蓋東南三百州。',32,'全唐诗/poet.song.210000.json','["今之房杜昔伊周，功蓋東南三百州。", "十二峰前月如翦，不知分照幾家樓。"]'),
('0334d765-467c-4de9-9991-c1cec1516090','偈頌七十一首  其五四','釋了惠','宋','宋诗','song-poetry','','["\u8861\u5c71"]','屋前基業，屋後生涯。',50,'全唐诗/poet.song.210000.json','["屋前基業，屋後生涯。", "堂堂妙用，不假安排。", "暑退凉飈起，燕歸鴻鴈來。", "天台南嶽，峨嵋五臺。", "新羅擊皷大唐齋。"]'),
('e95159a9-4251-45cc-be53-e8b4d250dd6d','偈頌七十一首  其五五','釋了惠','宋','宋诗','song-poetry','','[]','孟嘉已前，淵明去後。',54,'全唐诗/poet.song.210000.json','["孟嘉已前，淵明去後。", "誰家籬畔欠黄花，那箇盃中無白酒，重陽只是九月九。", "阿呵呵，始信茱萸茶苦澀，展眉人少皺眉多。"]'),
('70434c72-3365-42f5-83d7-5d45f4957489','偈頌七十一首  其五六','釋了惠','宋','宋诗','song-poetry','','[]','陪盡老精神，杯盤越樣新。',24,'全唐诗/poet.song.210000.json','["陪盡老精神，杯盤越樣新。", "誰知村店酒，難勸御樓人。"]'),
('1f28962c-f97b-4722-a836-ef1ebc81bca3','偈頌七十一首  其五七','釋了惠','宋','宋诗','song-poetry','','[]','瞿塘三峽風波險，棧閣連雲行路難。',32,'全唐诗/poet.song.210000.json','["瞿塘三峽風波險，棧閣連雲行路難。", "烽火相連兵刃接，一封鄉信報平安。"]'),
('36959672-6081-489f-9a82-bb08c089e8ad','偈頌七十一首  其五八','釋了惠','宋','宋诗','song-poetry','','[]','仲冬嚴寒年年事，須知事上大有事。',32,'全唐诗/poet.song.210000.json','["仲冬嚴寒年年事，須知事上大有事。", "若人知得事上事，到了全然不干事。"]'),
('7e50c00e-c07f-4eb6-a07d-5248a26f863d','偈頌七十一首  其五九','釋了惠','宋','宋诗','song-poetry','','[]','東土與西土，鑊湯無冷處。',50,'全唐诗/poet.song.210000.json','["東土與西土，鑊湯無冷處。", "暗室裏突出鱉鼻蛇，平田中撞著白額虎。", "眼放閃電光，毒氣成煙霧。", "最難行是芝峰路。"]'),
('981186ba-b2f7-464a-a1d0-084b9d65d81c','偈頌七十一首  其六○','釋了惠','宋','宋诗','song-poetry','','[]','四序暗推遷，鉢盂口向天。',24,'全唐诗/poet.song.210000.json','["四序暗推遷，鉢盂口向天。", "止餘三十日，便是一周年。"]'),
('8ac827ca-078e-4dbb-93e1-912e4ea59750','偈頌七十一首  其六一','釋了惠','宋','宋诗','song-poetry','','[]','去年今日節，海角天涯傳報捷。',64,'全唐诗/poet.song.210000.json','["去年今日節，海角天涯傳報捷。", "今日去年朝，黄童白叟盡歌謠。", "雨不破塊，風不鳴條。", "漁者自漁，樵者自樵。", "草木昆蟲王化裏，萬拜誰道不逢堯。"]'),
('debff62a-a3f9-47b0-8187-bde95a4e8d8e','偈頌七十一首  其六二','釋了惠','宋','宋诗','song-poetry','','[]','星在天上，眼在眉下。',28,'全唐诗/poet.song.210000.json','["星在天上，眼在眉下。", "星無暗明，眼無晝夜。", "密密綿綿無縫罅。"]'),
('7b40c924-a259-4f24-9742-5ee37d85cbaf','偈頌七十一首  其六三','釋了惠','宋','宋诗','song-poetry','','[]','二月十有五，瞿曇開死鋪。',40,'全唐诗/poet.song.210000.json','["二月十有五，瞿曇開死鋪。", "摩胸告衆時，槨示雙趺處。", "縮不來，展不去，七手八脚一時露。"]'),
('780d3019-d5d4-4b3f-9b65-2766ac1302a3','偈頌七十一首  其六四','釋了惠','宋','宋诗','song-poetry','','[]','貴如圭璧，賤如泥土。',59,'全唐诗/poet.song.210000.json','["貴如圭璧，賤如泥土。", "鎮壓山川，輝騰今古。", "有商量，沒價數。", "富者得之貧，貧者得之富。", "豈不見茶陵山下郁闍梨，騎馿踏斷溪橋路。"]'),
('420ab5be-12a0-4e97-aefb-7138ee8490a9','偈頌七十一首  其六五','釋了惠','宋','宋诗','song-poetry','','[]','重陽佳節到來，瑞巖無可安排。',52,'全唐诗/poet.song.210000.json','["重陽佳節到來，瑞巖無可安排。", "一十二峰黄栗粽，東大洋海茱萸茶。", "萬象摩唇捋嘴，虛空綴齒粘牙，不知秋意落誰家。"]'),
('e47a3741-f3c3-47e6-bda4-e838e609b73b','偈頌七十一首  其六六','釋了惠','宋','宋诗','song-poetry','','[]','沒艱難處立難難，難透村婆者一關。',32,'全唐诗/poet.song.210000.json','["沒艱難處立難難，難透村婆者一關。", "忽地假鷄啼午夜，馬蹄踏月過長安。"]'),
('b7ee94bd-431d-4f92-ab4b-2b09dd90c1f2','偈頌七十一首  其六七','釋了惠','宋','宋诗','song-poetry','','[]','大機普應，妙用全彰。',40,'全唐诗/poet.song.210000.json','["大機普應，妙用全彰。", "井通滄海，日上扶桑。", "擊石火，閃電光。", "進前先蹉過，退後絕承當。"]'),
('e1a01001-816d-484b-993e-0c9621e86e9e','偈頌七十一首  其六八','釋了惠','宋','宋诗','song-poetry','','[]','冷坐雪堆中，羅睺入命宮。',44,'全唐诗/poet.song.210000.json','["冷坐雪堆中，羅睺入命宮。", "被人贓作佛，打失主人翁。", "眉間蛛網斷，頂𩕳鵲巢空。", "公案今朝又一重。"]'),
('f2d10099-e17f-4f27-9992-fba6ce514a18','偈頌七十一首  其六九','釋了惠','宋','宋诗','song-poetry','','[]','人間共賞元宵，瑞巖本光現瑞。',60,'全唐诗/poet.song.210000.json','["人間共賞元宵，瑞巖本光現瑞。", "屋上山，橋下水。", "三門八字打開，左右青葉婁至。", "頭頂天，脚踏地。", "陳如覷破香積厨，釋迦不受然燈記。"]'),
('3d9e900a-57cf-433d-85cc-7c2006de5e41','偈頌七十一首  其七○','釋了惠','宋','宋诗','song-poetry','','[]','生於穢土，不受點污。',36,'全唐诗/poet.song.210000.json','["生於穢土，不受點污。", "目顧四方，周行七步。", "看來步步討便宜，落水也要占乾處。"]'),
('c333128b-a325-4bd0-bd07-3cae2a8d9978','偈頌七十一首  其七一','釋了惠','宋','宋诗','song-poetry','','[]','無病之藥，不傳之方。',37,'全唐诗/poet.song.210000.json','["無病之藥，不傳之方。", "昨朝用不得，今日恰相當。", "如何是相當處，往往呼爲百草霜。"]'),
('e54ba6a9-fc78-4367-a964-6e78b6019f51','禪會圖黄檗掌沙彌','釋了惠','宋','宋诗','song-poetry','','[]','膝下黄金貴，掌中天地寬。',24,'全唐诗/poet.song.210000.json','["膝下黄金貴，掌中天地寬。", "風雲欣際會，四海夜濤寒。"]'),
('9dc99cf5-c31c-4a53-bb14-68d62dd33649','趙州接趙王','釋了惠','宋','宋诗','song-poetry','','[]','跏趺迎上客，曲录對旌幢。',24,'全唐诗/poet.song.210000.json','["跏趺迎上客，曲录對旌幢。", "不是家風別，他居禮樂邦。"]'),
('fe180145-0560-47dc-9bad-5b18a87c1d1b','國一見代宗來起立','釋了惠','宋','宋诗','song-poetry','','[]','立在威儀外，全身在裏頭。',24,'全唐诗/poet.song.210000.json','["立在威儀外，全身在裏頭。", "重重賜龍袖，難掩面門羞。"]'),
('f241d2db-3b47-4696-9701-3d3e139e265e','中原之寶','釋了惠','宋','宋诗','song-poetry','','[]','至寶應難別，波斯雙眼昏。',24,'全唐诗/poet.song.210000.json','["至寶應難別，波斯雙眼昏。", "何如放下手，留取鎮中原。"]'),
('4fa68ea9-9672-4b5b-bbb7-70d7d048a16f','文宗嗜蛤蜊','釋了惠','宋','宋诗','song-poetry','','[]','螺師蚌蛤類，大唐天子心。',24,'全唐诗/poet.song.210000.json','["螺師蚌蛤類，大唐天子心。", "嗜好即深信，南無觀世音。"]'),
('8a14413a-78f9-4a8a-947f-f2a5f6a278f5','李習之見藥山','釋了惠','宋','宋诗','song-poetry','','[]','即今非見面，昔日不聞名。',24,'全唐诗/poet.song.210000.json','["即今非見面，昔日不聞名。", "一句添三句，篇章湊不成。"]'),
('18d0453c-94f6-4533-bc37-0a8f77853694','韓文公見大顛','釋了惠','宋','宋诗','song-poetry','','[]','事繁求省要，省要事頻繁。',24,'全唐诗/poet.song.210000.json','["事繁求省要，省要事頻繁。", "縱得三平老，文公只姓韓。"]'),
('356ab406-284c-4714-bd47-3acfd97502c8','龐居士見馬祖','釋了惠','宋','宋诗','song-poetry','','[]','孰是心空者，誰爲選佛人。',24,'全唐诗/poet.song.210000.json','["孰是心空者，誰爲選佛人。", "笊籬二尺柄，簸箕三寸唇。"]'),
('4640d0d2-07e7-40ce-8270-ff3616d8a4cb','丹霞見靈照','釋了惠','宋','宋诗','song-poetry','','[]','當風鴉臭氣，一箇豆娘兒。',24,'全唐诗/poet.song.210000.json','["當風鴉臭氣，一箇豆娘兒。", "熏得行人走，衝爺皺斷眉。"]'),
('cefdeb10-e8f4-4ca1-b30b-c40fd358e0e3','捧佛安名','釋了惠','宋','宋诗','song-poetry','','[]','名正字亦正，形端影亦端。',24,'全唐诗/poet.song.210000.json','["名正字亦正，形端影亦端。", "呼來并諾去，馿屎雜栴檀。"]'),
('80f02685-fc37-4be5-83f1-ac410ce0d447','說無生話','釋了惠','宋','宋诗','song-poetry','','[]','家有全棚樂，新翻調不同。',24,'全唐诗/poet.song.210000.json','["家有全棚樂，新翻調不同。", "分明恨離別，却是喜相逢。"]'),
('32b84968-96d6-4c7d-93f1-755e56706c0b','女子看日','釋了惠','宋','宋诗','song-poetry','','[]','劣女還閨閤，癡爺看日頭。',24,'全唐诗/poet.song.210000.json','["劣女還閨閤，癡爺看日頭。", "幾生親骨肉，不共戴天讎。"]'),
('0e2fe599-5480-43cb-bf54-6624ebfa7f45','龐大倚鋤而化','釋了惠','宋','宋诗','song-poetry','','[]','辨地要從苗，枝殘葉後凋。',24,'全唐诗/poet.song.210000.json','["辨地要從苗，枝殘葉後凋。", "春風收契券，鋤柄亦抽條。"]'),
('11ab9f5d-2c4c-4bda-be2f-3e973666db19','重畫知識壁','釋了惠','宋','宋诗','song-poetry','','[]','幸自十方無壁落，誰將五彩畫虛空。',32,'全唐诗/poet.song.210000.json','["幸自十方無壁落，誰將五彩畫虛空。", "善財眼裏生花翳，去却一重添一重。"]'),
('1c2fe29d-f369-4c59-9fd7-ca09cfa2b754','鴈山出隊上陳侍郎','釋了惠','宋','宋诗','song-poetry','','[]','尊者從空擲鉢來，神通用盡却成獃。',32,'全唐诗/poet.song.210000.json','["尊者從空擲鉢來，神通用盡却成獃。", "看來不似維摩老，一默千門萬戶開。"]'),
('ff1aa32e-e238-4bfb-9228-e91be419bd9e','古帆','釋了惠','宋','宋诗','song-poetry','','[]','海變桑田數莫窮，幾回高挂逆流中。',32,'全唐诗/poet.song.210000.json','["海變桑田數莫窮，幾回高挂逆流中。", "自從一飽清風後，船上時時有散工。"]'),
('6437319e-73fe-46ef-adad-55aeb0467f03','雪庭','釋了惠','宋','宋诗','song-poetry','','[]','玉砌曉光寒，家風箇樣生。',24,'全唐诗/poet.song.210000.json','["玉砌曉光寒，家風箇樣生。", "須知平白處，著脚是深坑。"]'),
('89c7236d-e9a8-4ff1-8b8a-7f1fd63602f5','自省','釋了惠','宋','宋诗','song-poetry','','[]','𥉌𥉍眼孔忽然開，冷汗通身笑滿腮。',32,'全唐诗/poet.song.210000.json','["𥉌𥉍眼孔忽然開，冷汗通身笑滿腮。", "數十年間將謂道，誰知今日却元來。"]'),
('9964c3e7-aea3-48c2-b915-dc9bddc89805','閑田','釋了惠','宋','宋诗','song-poetry','','[]','秦不耕兮漢不耘，钁頭邊事杳無聞。',32,'全唐诗/poet.song.210000.json','["秦不耕兮漢不耘，钁頭邊事杳無聞。", "年來也有秋成望，三合清風半合雲。"]'),
('3ee10840-c06d-49ad-886a-dc93898cd457','聞叟','釋了惠','宋','宋诗','song-poetry','','[]','不是耳從聲畔去，亦非聲向耳邊來。',32,'全唐诗/poet.song.210000.json','["不是耳從聲畔去，亦非聲向耳邊來。", "新羅國裏打齋鼓，老漢鉢盂齊展開。"]'),
('31ee57f7-2c5c-49b0-91eb-0d465a13258d','一翁','釋了惠','宋','宋诗','song-poetry','','[]','朕兆未分初，都盧只老夫。',24,'全唐诗/poet.song.210000.json','["朕兆未分初，都盧只老夫。", "包羲太多事，胡處又添鬚。"]'),
('f0ef6f2b-2c82-4dd9-a63e-df7af27cf3cf','斷橋','釋了惠','宋','宋诗','song-poetry','','[]','頭枕溪西尾搭東，東西只尺不相通。',32,'全唐诗/poet.song.210000.json','["頭枕溪西尾搭東，東西只尺不相通。", "跳不過處水千里，進得步時山萬重。"]'),
('90e17fd4-9676-41fc-a9a0-074c9fca9d62','西窗','釋了惠','宋','宋诗','song-poetry','','[]','分得竺乾些子光，拓開戶牖闢封疆。',32,'全唐诗/poet.song.210000.json','["分得竺乾些子光，拓開戶牖闢封疆。", "誰知迥絕安排處，昨夜三更挂夕陽。"]'),
('e71e64be-dab1-4972-8b8b-d9bf91cc2208','松坡','釋了惠','宋','宋诗','song-poetry','','[]','白頭棄钁下烟扉，正是欣逢快便時。',32,'全唐诗/poet.song.210000.json','["白頭棄钁下烟扉，正是欣逢快便時。", "豈謂傍山根脚在，至今留得礙人枝。"]'),
('2486b4c1-41d0-4ed6-bf1e-15892cd1cbdc','病翁','釋了惠','宋','宋诗','song-poetry','','[]','八萬四千毛竅裏，如來禪與祖師禪。',32,'全唐诗/poet.song.210000.json','["八萬四千毛竅裏，如來禪與祖師禪。", "一回白汗俱通暢，忌口更須三十年。"]'),
('cc328623-8f77-475b-ad77-1925b97cbb49','石室','釋了惠','宋','宋诗','song-poetry','','[]','鎚鑿不到處，縱橫丈許寬。',24,'全唐诗/poet.song.210000.json','["鎚鑿不到處，縱橫丈許寬。", "寧教苔蘚去，要下一籌難。"]'),
('4485e00f-ec94-4671-97d9-2ae993ffe04f','別川道士','釋了惠','宋','宋诗','song-poetry','','[]','塵中相見頭顱別，座上交談語笑同。',32,'全唐诗/poet.song.210000.json','["塵中相見頭顱別，座上交談語笑同。", "拶到了無同別處，擎拳合掌各西東。"]'),
('09fd70c6-e4ab-4389-af50-7ddc70749c63','送徹上人歸蓬州','釋了惠','宋','宋诗','song-poetry','','[]','蓬萊一尺離青天，水不行舟古語傳。',32,'全唐诗/poet.song.210000.json','["蓬萊一尺離青天，水不行舟古語傳。", "但得胸中有江海，歸家陸地也撐船。"]'),
('f6b4400a-48df-4251-b93f-8a46126dcd07','閬州權兄歸住錦屏','釋了惠','宋','宋诗','song-poetry','','[]','歸家結束蓋頭茅，坐看青山久不磨。',32,'全唐诗/poet.song.210000.json','["歸家結束蓋頭茅，坐看青山久不磨。", "切莫風前開臭口，恐人傳作閬山歌。"]'),
('881197d1-7001-4bbd-ac19-49f83038b2e6','堅上人歸成都','釋了惠','宋','宋诗','song-poetry','','[]','蘇州得得上凌霄，恰值山寒雪未消。',32,'全唐诗/poet.song.210000.json','["蘇州得得上凌霄，恰值山寒雪未消。", "逗到雪消山骨露，春風已在錦江橋。"]'),
('309ac615-7b41-4c62-9080-e68389f4b990','送人歸昌州','釋了惠','宋','宋诗','song-poetry','','[]','見說家山富海棠，杜陵才短沒篇章。',32,'全唐诗/poet.song.210000.json','["見說家山富海棠，杜陵才短沒篇章。", "煩君開口道一句，攛掇教他分外香。"]'),
('cb7f0628-c8c5-4a70-84cd-6a38f01ef527','送人歸湖南','釋了惠','宋','宋诗','song-poetry','','[]','白紙無端墨筆書，分明一句却模糊。',32,'全唐诗/poet.song.210000.json','["白紙無端墨筆書，分明一句却模糊。", "青燈夜雨湘江上，添得平沙落雁圖。"]'),
('473c0416-e489-43e0-a466-89b30260e8b4','送僧之江西','釋了惠','宋','宋诗','song-poetry','','[]','一粒收成敵萬倉，可憐別甑不炊香。',32,'全唐诗/poet.song.210000.json','["一粒收成敵萬倉，可憐別甑不炊香。", "簸箕唇外打𨁝跳，八十四人皆粃糠。"]'),
('31ab29e9-812a-435c-8247-db7d07dd95d0','送人之岳山','釋了惠','宋','宋诗','song-poetry','','[]','莫珍龍袖貴金襴，試撥湖湘草裏看。',32,'全唐诗/poet.song.210000.json','["莫珍龍袖貴金襴，試撥湖湘草裏看。", "撥看路邊牛糞火，烏藤變作紫栴檀。"]'),
('83d7006b-c4b9-4247-abdf-f7ba8c181ee8','送奎上人往中川','釋了惠','宋','宋诗','song-poetry','','[]','湫間雲冷不成眠，聽得樵歌一曲全。',32,'全唐诗/poet.song.210000.json','["湫間雲冷不成眠，聽得樵歌一曲全。", "切莫喧傳江上路，此聲不入釣魚船。"]'),
('3c71f9fe-9408-4eaf-8b13-d01173e3c088','送李道士歸東湖','釋了惠','宋','宋诗','song-poetry','','[]','湫龍噀水濕髭鬚，四十九盤山畫符。',32,'全唐诗/poet.song.210000.json','["湫龍噀水濕髭鬚，四十九盤山畫符。", "此法未傳先有驗，夜來驅月下東湖。"]'),
('f3b5ebf1-9079-49f2-874f-e2c2385bbd51','送性侍者之冷泉','釋了惠','宋','宋诗','song-poetry','','[]','爺兒解釋死生冤，覓語欲登靈鷲山。',32,'全唐诗/poet.song.210000.json','["爺兒解釋死生冤，覓語欲登靈鷲山。", "借與門前溪上路，草鞋錢是你儂還。"]'),
('b030fa9a-c585-4270-afd0-2d229eafe8fc','送日本俊上人','釋了惠','宋','宋诗','song-poetry','','[]','鉢盂捧入大唐來，飯裏無端咬著砂。',32,'全唐诗/poet.song.210000.json','["鉢盂捧入大唐來，飯裏無端咬著砂。", "一粒砂藏諸國土，方知寸步不離家。"]'),
('d6468c09-86ec-4111-98dd-e7fee8485e1e','瑞上人血書蓮經報親','釋了惠','宋','宋诗','song-poetry','','[]','二千年前血滴滴，今日分明重指出。',32,'全唐诗/poet.song.210000.json','["二千年前血滴滴，今日分明重指出。", "所生父母知不知，一二三四五六七。"]'),
('9cc19782-0479-4e24-95b6-b5ac4632b2c2','趙山臺蓮花方丈','釋了惠','宋','宋诗','song-poetry','','[]','一芙蕖是一毗耶，一葉香風一室開。',32,'全唐诗/poet.song.210000.json','["一芙蕖是一毗耶，一葉香風一室開。", "三萬二千師子座，藕絲竅裏涌將來。"]'),
('fea9d205-55c5-4bbc-899c-fc5e581f9a73','黄梅一會','釋了惠','宋','宋诗','song-poetry','','[]','日暮下山投宿處，風前聞客誦經時。',32,'全唐诗/poet.song.210000.json','["日暮下山投宿處，風前聞客誦經時。", "分明此處此時節，總在目前人不知。"]'),
('977dd3d9-97e7-4fab-8bba-821a6d14e66d','靈江','釋了惠','宋','宋诗','song-poetry','','[]','水底烏龜無卦兆，岸頭神樹不相關。',32,'全唐诗/poet.song.210000.json','["水底烏龜無卦兆，岸頭神樹不相關。", "要知禍福流行處，只在波心月一彎。"]'),
('f5db527e-7d57-48d1-a974-06141d9cc958','木翁','釋了惠','宋','宋诗','song-poetry','','[]','不知天地是同根，到老全無刀斧痕。',32,'全唐诗/poet.song.210000.json','["不知天地是同根，到老全無刀斧痕。", "結得同行箇上座，夜來扶過落花村。"]'),
('d16ebe93-6da1-473d-8eec-c9ebcbb246e7','鳴鴈松林接待','釋了惠','宋','宋诗','song-poetry','','[]','望見松林笑滿腮，香厨豈爲者僧開。',32,'全唐诗/poet.song.210000.json','["望見松林笑滿腮，香厨豈爲者僧開。", "三千里外有知己，鳴鴈带書招不來。"]'),
('55c92079-4e28-4e8a-b730-ebd54d150350','寄樂山居士','釋了惠','宋','宋诗','song-poetry','','[]','雪鰲寒聳玉稜層，門釘桃符似不曾。',32,'全唐诗/poet.song.210000.json','["雪鰲寒聳玉稜層，門釘桃符似不曾。", "將謂已無閑鬼祟，客床猶有不眠僧。"]'),
('e4dc47e5-7172-48f8-b2fd-ba012b703e9b','奉化亭山廟接待','釋了惠','宋','宋诗','song-poetry','','[]','只箇亭山歇脚亭，豈圖一飽脚頭輕。',32,'全唐诗/poet.song.210000.json','["只箇亭山歇脚亭，豈圖一飽脚頭輕。", "須知鉢裏和籮飯，粒粒無非鬼眼睛。"]'),
('1a3339bf-13e8-418f-a70b-ec37d9f98968','聞父訃二首  其一','釋了惠','宋','宋诗','song-poetry','','[]','眉毛蓋眼赤鬚胡，女嫁男婚不識渠。',32,'全唐诗/poet.song.210000.json','["眉毛蓋眼赤鬚胡，女嫁男婚不識渠。", "唯是我儂偏孝順，十年不作問安書。"]'),
('38fba219-754d-4e5d-90c7-d8439fcbcef8','聞父訃二首  其二','釋了惠','宋','宋诗','song-poetry','','[]','見說如何與若何，恰如風向樹頭過。',32,'全唐诗/poet.song.210000.json','["見說如何與若何，恰如風向樹頭過。", "若論父子分明處，自古綿州所出多。"]'),
('44887477-ee4d-4f91-98bb-cb40485f1b82','悼虎丘枯樁和尚  其一','釋了惠','宋','宋诗','song-poetry','','[]','佛心之子毒蛇心，歡喜無端變作嗔。',32,'全唐诗/poet.song.210000.json','["佛心之子毒蛇心，歡喜無端變作嗔。", "五處住山開毒口，不知噴殺幾多人。"]'),
('914f881c-98a8-4d01-807a-14bd1ae3ae74','悼虎丘枯樁和尚  其二','釋了惠','宋','宋诗','song-poetry','','[]','華雨臺前倒法幢，海門浪裏釘枯樁。',32,'全唐诗/poet.song.210000.json','["華雨臺前倒法幢，海門浪裏釘枯樁。", "千古萬古撼不動，礙塞潑天揚子江。"]'),
('42bce15f-2095-431f-b0ae-cbd7c9c6cc38','悼滅翁  其一','釋了惠','宋','宋诗','song-poetry','','[]','咬牙囓齒駡松源，四海五湖洪浪奔。',32,'全唐诗/poet.song.210000.json','["咬牙囓齒駡松源，四海五湖洪浪奔。", "天目山雲梁渚月，就中嘲謗不成冤。"]'),
('056a019b-ce01-4da2-b900-fc3a9ac875f7','悼滅翁  其二','釋了惠','宋','宋诗','song-poetry','','[]','盡道滅翁今滅門，那知滅字塞乾坤。',32,'全唐诗/poet.song.210000.json','["盡道滅翁今滅門，那知滅字塞乾坤。", "道渠已滅不曾滅，總不是渠真子孫。"]'),
('ea26a998-7ce2-4f24-88c2-3abe27cce965','謝萬年淮海寄擬爲上堂','釋了惠','宋','宋诗','song-poetry','','[]','不愁台嶺路岧嶤，生怕平田惡水澆。',32,'全唐诗/poet.song.210000.json','["不愁台嶺路岧嶤，生怕平田惡水澆。", "一杓又傾三百里，令人含恨不能消。"]'),
('9c369509-b307-460c-87eb-b2e45608af4c','寓北山小閣因事偶作','釋了惠','宋','宋诗','song-poetry','','[]','老去將貧買得閑，十層梯下是人間。',32,'全唐诗/poet.song.210000.json','["老去將貧買得閑，十層梯下是人間。", "忽因送客聞新事，又囑山童緊著關。"]'),
('afbefdc7-3825-4e49-928b-32c74406851e','出山相贊','釋了惠','宋','宋诗','song-poetry','','[]','夜半見明星，山中添冷話。',46,'全唐诗/poet.song.210000.json','["夜半見明星，山中添冷話。", "脚未出山來，此話行天下。", "我觀一切衆生成佛多時，只有你者老子猶欠悟在。"]'),
('4a79e0af-e3c9-484f-b7a2-f33e1608f10a','達磨贊  其一','釋了惠','宋','宋诗','song-poetry','','[]','噫吁，西來何所圖。',29,'全唐诗/poet.song.210000.json','["噫吁，西來何所圖。", "未開花五葉，先壞一莖蘆，秋風吹恨滿江湖。"]'),
('a0b02dcf-24ab-4752-8ee2-5ce06d874f05','達磨贊  其二','釋了惠','宋','宋诗','song-poetry','','[]','西土不拘，東土不管。',36,'全唐诗/poet.song.210000.json','["西土不拘，東土不管。", "口邊落節，臂邊拔本。", "自携隻履賦歸歟，脚下至今猶未穩。"]'),
('99e52821-4a30-4e8e-8ad2-24de6fa99f34','觀音贊','釋了惠','宋','宋诗','song-poetry','','[]','字字不真，句句不實。',38,'全唐诗/poet.song.210000.json','["字字不真，句句不實。", "真實色身，何處尋覓。", "無尋覓處，正觀現前。", "菡蓞花香水接天。"]'),
('223f94d1-7694-4fe8-98e1-e03c16cde4d7','常思惟贊','釋了惠','宋','宋诗','song-poetry','','[]','不滯聞見而受用聞見，不涉思惟而深入思惟。',36,'全唐诗/poet.song.210000.json','["不滯聞見而受用聞見，不涉思惟而深入思惟。", "一坐至今扶不起，圓通門戶草離離。"]'),
('9fa14616-a893-4c86-af0e-b33f40bfb5ba','海眼光贊','釋了惠','宋','宋诗','song-poetry','','[]','海眼爲香餌，悲心作釣鉤。',24,'全唐诗/poet.song.210000.json','["海眼爲香餌，悲心作釣鉤。", "魚龍知幾許，貪者自擡頭。"]'),
('ae9eb7d0-6c2d-4700-9174-b1d196a27eb1','又','釋了惠','宋','宋诗','song-poetry','','[]','抱膝踞巖阿，自在特自在。',33,'全唐诗/poet.song.210000.json','["抱膝踞巖阿，自在特自在。", "一線柳梢風，掃浄衆生界。", "苦苦，忽然變成雨。"]'),
('36d95684-4f64-44e0-8841-0eeefc1fef95','又','釋了惠','宋','宋诗','song-poetry','','[]','玉腕指尖新，力能提萬鈞。',24,'全唐诗/poet.song.210000.json','["玉腕指尖新，力能提萬鈞。", "上他籃子裏，未必是金鱗。"]'),
('0a1eab35-dd6e-4ab8-847c-a2ae460c8897','文殊爲龍女說法贊','釋了惠','宋','宋诗','song-poetry','','[]','作獅子吼，震龍王宮。',36,'全唐诗/poet.song.210000.json','["作獅子吼，震龍王宮。", "說者如啞，聽者如聾。", "清凉山頂照明月，無垢世界生清風。"]'),
('8999754e-37f9-4121-9ba7-d405e3742685','普賢出山相贊','釋了惠','宋','宋诗','song-poetry','','[]','駕白象王，數黑豆子。',38,'全唐诗/poet.song.210000.json','["駕白象王，數黑豆子。", "行願不相應，身心不相似。", "雖然瓶瀉二千酎，敢保胸中無一字。"]'),
('2b9a44c3-5284-4c2f-b959-e0a6cc838553','布袋贊','釋了惠','宋','宋诗','song-poetry','','[]','烏藤橫占閻浮界，鼻孔直撐兜率天。',32,'全唐诗/poet.song.210000.json','["烏藤橫占閻浮界，鼻孔直撐兜率天。", "剛道化身千百億，一身猶自不完全。"]'),
('df5a7317-10ef-4395-b77d-ff0b27da5d6e','又','釋了惠','宋','宋诗','song-poetry','','[]','布袋沒半邊，烏藤欠一橛。',32,'全唐诗/poet.song.210000.json','["布袋沒半邊，烏藤欠一橛。", "手指空中底，要且不是佛。", "是什麽，咄咄咄。"]'),
('02cfda64-6761-47e4-8bf8-fc7f7b977187','又','釋了惠','宋','宋诗','song-poetry','','[]','挑起慳囊，慳而不悋。',45,'全唐诗/poet.song.210000.json','["挑起慳囊，慳而不悋。", "回頭等一箇人，知是張何李鄭。", "且等且等，等到彌勒下生時，或然等得也不定。"]'),
('eda8adb0-dbd3-4122-82c8-70fdb318d499','又','釋了惠','宋','宋诗','song-poetry','','[]','轉腦回頭，百般賣弄。',34,'全唐诗/poet.song.210000.json','["轉腦回頭，百般賣弄。", "滯貨只些兒，盡力拽不動。", "吽吽，我不信得恁麽鄭重。"]'),
('edbd151d-4896-4dec-9189-729ee10fc4c1','布袋贊','釋了惠','宋','宋诗','song-poetry','','[]','捫腹一笑，笑裏戈矛。',36,'全唐诗/poet.song.210000.json','["捫腹一笑，笑裏戈矛。", "背手牽囊，囊中錐刺。", "將謂渠儂有底聱，元來奉化只如此。"]'),
('2caef0b5-95a2-4ffe-9a65-28d70d560f7f','三教贊','釋了惠','宋','宋诗','song-poetry','','[]','姓孔名聃，字曰瞿曇。',32,'全唐诗/poet.song.210000.json','["姓孔名聃，字曰瞿曇。", "禪道第二，文章第三。", "同門同出入，不是我同參。"]'),
('4623ee83-a707-49e9-8ba8-72b24985fe61','維摩贊','釋了惠','宋','宋诗','song-poetry','','[]','示疾毗耶方丈，文殊亦難近傍。',28,'全唐诗/poet.song.210000.json','["示疾毗耶方丈，文殊亦難近傍。", "看來無藥可醫，只是忌口爲上。"]'),
('bebd4da3-ef97-4e08-ab2e-705a5de937f2','須菩提贊','釋了惠','宋','宋诗','song-poetry','','[]','道箇希有世尊，不知口是禍門。',28,'全唐诗/poet.song.210000.json','["道箇希有世尊，不知口是禍門。", "至今看經未了，立得拄杖生根。"]'),
('dc619a9c-be92-4334-8a13-c866224d8012','馬郎婦贊','釋了惠','宋','宋诗','song-poetry','','[]','七軸蓮經，自舒自卷。',36,'全唐诗/poet.song.210000.json','["七軸蓮經，自舒自卷。", "嫁人之媒，算人之本。", "金沙去後轉風流，幾度桃花春浪暖。"]'),
('00a72f38-8ff8-47a9-a007-ced97d630fde','觀音坐巖中并十六羅漢贊','釋了惠','宋','宋诗','song-poetry','','[]','應現聲聞身，本身曾不動。',40,'全唐诗/poet.song.210000.json','["應現聲聞身，本身曾不動。", "衆身齊說法，平地波濤涌。", "此法不知誰解聽，巖谷曉來雲氣重。"]'),
('00ac77a0-875e-4b2d-80b6-78e4743233cf','豐干閭丘虎贊','釋了惠','宋','宋诗','song-poetry','','[]','虎怕人心惡，人欺虎太慈。',24,'全唐诗/poet.song.210000.json','["虎怕人心惡，人欺虎太慈。", "雖逢賢太守，難打者官司。"]'),
('056605fe-3589-4300-b0a5-29a30fc53ef5','寒拾贊','釋了惠','宋','宋诗','song-poetry','','[]','五臺爲床，峨嵋作枕。',30,'全唐诗/poet.song.210000.json','["五臺爲床，峨嵋作枕。", "眠似不眠，惺如不惺。", "喚起來，三十苕帚柄。"]'),
('133369f3-a0bd-474d-8498-4c991d3a41f4','拾得磨墨寒山題巖贊  其一','釋了惠','宋','宋诗','song-poetry','','[]','亂石當陶泓，千巖作詩軸。',40,'全唐诗/poet.song.210000.json','["亂石當陶泓，千巖作詩軸。", "意到句不就，句到意不足。", "墨漸消，筆漸禿。", "蒼松偃蹇莓苔綠。"]'),
('654aa366-1258-4df7-ae8e-bde818c34dbb','拾得磨墨寒山題巖贊  其二','釋了惠','宋','宋诗','song-poetry','','[]','高興上層巔，斷崖收晚烟。',48,'全唐诗/poet.song.210000.json','["高興上層巔，斷崖收晚烟。", "筆底兩三字，人間千百篇。", "心手不相知，石上墨成池。", "劫石有消日，此墨無盡時。"]'),
('d369e4df-d951-4d19-90a2-ad651a6d67ea','磨鍼羅漢贊','釋了惠','宋','宋诗','song-poetry','','[]','磨礲分寸工夫，建立針鋒世界。',28,'全唐诗/poet.song.210000.json','["磨礲分寸工夫，建立針鋒世界。", "尚欠些子合尖，且待石頭爛壞。"]'),
('f10fa784-d400-4173-90fe-568b3250c802','洗鉢羅漢贊','釋了惠','宋','宋诗','song-poetry','','[]','水落方能石露，有心別無用處。',28,'全唐诗/poet.song.210000.json','["水落方能石露，有心別無用處。", "若問佛法如何，日洗鉢盂兩度。"]'),
('28cf9273-4f77-466a-9412-ae4ab46ae35e','善財贊','釋了惠','宋','宋诗','song-poetry','','[]','捏定五十三人性命若一藕絲，擎起百一十城世界如一荷葉。',62,'全唐诗/poet.song.210000.json','["捏定五十三人性命若一藕絲，擎起百一十城世界如一荷葉。", "此未入母胎已前神通，正參見文殊已後時節。", "樓閣門前事若何，夜來池沼皆明月。"]'),
('a1d63db0-ff13-42ea-bd90-0e2028c27032','四睡贊  其一','釋了惠','宋','宋诗','song-poetry','','[]','人兮不覊，虎兮不縛。',36,'全唐诗/poet.song.210000.json','["人兮不覊，虎兮不縛。", "是四憨癡，成一火落。", "雖然合眼只一般，也有睡著睡不著。"]'),
('84fa2316-d73d-42ae-b5bc-edfd030bfdd3','四睡贊  其二','釋了惠','宋','宋诗','song-poetry','','[]','無固無必，挨肩促膝。',32,'全唐诗/poet.song.210000.json','["無固無必，挨肩促膝。", "人夢不祥，虎夢大吉。", "世上有誰知，天台雲羃羃。"]'),
('7b49c842-04bc-4295-ac40-5114d206400f','朝陽穿破衲贊','釋了惠','宋','宋诗','song-poetry','','[]','一衲橫肩遮百醜，破處冷風吹不透。',32,'全唐诗/poet.song.210000.json','["一衲橫肩遮百醜，破處冷風吹不透。", "待伊穿線要重聯，金烏已在西山後。"]'),
('2d301b54-d7c7-4ca5-8f39-a2be2fbfdcfa','對月了殘經贊  其一','釋了惠','宋','宋诗','song-poetry','','[]','破微塵出大經卷，一彈指頃千百遍。',32,'全唐诗/poet.song.210000.json','["破微塵出大經卷，一彈指頃千百遍。", "只因錯認月爲燈，至今展卷遮羞面。"]'),
('fa9f0daf-abee-4070-9866-6736008fc591','對月了殘經贊  其二','釋了惠','宋','宋诗','song-poetry','','[]','麻線貫竹針，太陽相對面。',24,'全唐诗/poet.song.210000.json','["麻線貫竹針，太陽相對面。", "通身破綻多，如何補得遍。"]'),
('3e087b0d-aae1-47b9-8a77-87be230729e1','對月了殘經贊  其三','釋了惠','宋','宋诗','song-poetry','','[]','好念脫空經，不知山月轉。',24,'全唐诗/poet.song.210000.json','["好念脫空經，不知山月轉。", "將謂了多時，猶有者一卷。"]'),
('006e4f68-aa60-4a82-aedb-626708e8e246','豬頭和尚贊','釋了惠','宋','宋诗','song-poetry','','[]','提起臭豬頭，密持清浄戒。',32,'全唐诗/poet.song.210000.json','["提起臭豬頭，密持清浄戒。", "將謂足脂膏，元來少肉菜。", "如何出得金華界。"]'),
('9eadc0ed-b0f5-48f0-8c9f-28eec6985446','又','釋了惠','宋','宋诗','song-poetry','','[]','聖者聖何從，空中柳絮蹤。',24,'全唐诗/poet.song.210000.json','["聖者聖何從，空中柳絮蹤。", "豬頭不得喫，遍地扇腥風。"]'),
('a6684226-fca5-42c3-b19e-31dad107b06d','又','釋了惠','宋','宋诗','song-poetry','','[]','豬頭捧起，全苦全甘。',34,'全唐诗/poet.song.210000.json','["豬頭捧起，全苦全甘。", "饑兮不喫，飽而常貪。", "大地作柄扇子，難遮滿面羞慚。"]'),
('3d37fef6-2157-4ca8-a65a-1ddabc1d30de','言法華贊','釋了惠','宋','宋诗','song-poetry','','[]','口中念底，空中寫底。',34,'全唐诗/poet.song.210000.json','["口中念底，空中寫底。", "是何章句，是何宗旨。", "人道你轉法華，我道法華轉你。"]'),
('d76b3d0c-d704-4704-9954-e44b5780b3e7','鷄骨和尚贊','釋了惠','宋','宋诗','song-poetry','','[]','喫既不知數，吐亦難數渠。',24,'全唐诗/poet.song.210000.json','["喫既不知數，吐亦難數渠。", "非圖甜得口，意在五更初。"]'),
('75defc42-ee10-428a-912f-d356c8ced3c7','政黄牛贊','釋了惠','宋','宋诗','song-poetry','','[]','屈膝跨牛腰，山遥水更遥。',24,'全唐诗/poet.song.210000.json','["屈膝跨牛腰，山遥水更遥。", "有詩吟未就，白鷺下溪橋。"]');
